<?php



// Catch all output and errors

ob_start();



// Enable error reporting for debugging

error_reporting(E_ALL);

ini_set('display_errors', 0);

ini_set('log_errors', 1);

ini_set('error_log', __DIR__ . '/php_errors.log');



// Set headers

header('Content-Type: application/json; charset=utf-8');

header('Access-Control-Allow-Origin: *');

header('Access-Control-Allow-Methods: POST, GET, OPTIONS');

header('Access-Control-Allow-Headers: Content-Type');



// Handle preflight requests

if ($_SERVER['REQUEST_METHOD'] === 'OPTIONS') {

    http_response_code(200);

    exit;

}



/**

 * Automatically binds parameters to a prepared statement by detecting their types,

 * preventing manual type-string counting errors.

 */

function safeBindParam($stmt, ...$params) {

    $types = '';

    foreach ($params as $param) {

        if (is_int($param)) {

            $types .= 'i';

        } elseif (is_float($param)) {

            $types .= 'd';

        } else {

            $types .= 's';

        }

    }

    $stmt->bind_param($types, ...$params);

}



/**

 * Ensures churches.church_type exists before handlers query or write it.

 */

function ensureChurchTypeColumn(mysqli $conn): void

{

    $check = $conn->query("SHOW COLUMNS FROM churches LIKE 'church_type'");

    if ($check && $check->num_rows > 0) {

        return;

    }



    if (!$conn->query("ALTER TABLE churches ADD COLUMN church_type ENUM('kids','youth') NOT NULL DEFAULT 'kids'")) {

        throw new Exception('Failed to ensure church_type column: ' . $conn->error);

    }

}



function ensureStudentsAddedByColumn(mysqli $conn): void

{

    $check = $conn->query("SHOW COLUMNS FROM students LIKE 'added_by'");

    if ($check && $check->num_rows > 0) {

        return;

    }

    $conn->query("ALTER TABLE students ADD COLUMN added_by VARCHAR(100) DEFAULT NULL");

}



// ── Safe deletion of uploaded files ─────────────────────────

/**

 * Safely deletes an uploaded image file from the server.

 * Handles both full URLs (https://sunday-school.online/uploads/...)

 * and relative paths (/uploads/...).

 * 

 * Security: validates path is within uploads dir, no traversal,

 * and the file is a real image. Never throws — returns bool.

 */

function deleteUploadedFile(?string $imageUrl): bool {
    if (empty($imageUrl)) return false;

    // Extract relative path from full URL or relative path
    $path = $imageUrl;
    if (strpos($path, 'https://') === 0 || strpos($path, 'http://') === 0) {
        $parsed = parse_url($path);
        $path = $parsed['path'] ?? '';
    }

    // Must start with /uploads/
    if (strpos($path, '/uploads/') !== 0) {
        error_log("deleteUploadedFile: path does not start with /uploads/: " . $imageUrl);
        return false;
    }

    // Build absolute file path
    $filePath = __DIR__ . $path;
    $realPath = @realpath($filePath);
    $uploadsDir = @realpath(__DIR__ . '/uploads');

    // Safety checks
    if (!$realPath || !$uploadsDir) {
        error_log("deleteUploadedFile: file not found or uploads dir missing: " . $imageUrl);
        return false;
    }

    // Path traversal protection
    if (strpos($realPath, $uploadsDir . DIRECTORY_SEPARATOR) !== 0 && $realPath !== $uploadsDir) {
        error_log("SECURITY deleteUploadedFile: path traversal attempt blocked: " . $imageUrl);
        return false;
    }

    // Must be a regular file
    if (!is_file($realPath)) {
        error_log("deleteUploadedFile: not a regular file: " . $imageUrl);
        return false;
    }

    // Map /uploads/... to /uploads/trash_bin/...
    $trashPath = str_replace('/uploads/', '/uploads/trash_bin/', $path);
    $trashFilePath = __DIR__ . $trashPath;
    $trashDir = dirname($trashFilePath);

    if (!is_dir($trashDir)) {
        @mkdir($trashDir, 0755, true);
    }

    // Move file
    if (@rename($realPath, $trashFilePath)) {
        error_log("✅ Moved uploaded file to trash bin: " . $path . " -> " . $trashPath);
        return true;
    }

    // Fallback: copy and delete if rename fails
    if (@copy($realPath, $trashFilePath)) {
        @unlink($realPath);
        error_log("✅ Moved uploaded file to trash bin (copy+delete): " . $path . " -> " . $trashPath);
        return true;
    }

    error_log("❌ Failed to move uploaded file to trash bin: " . $path);
    return false;
}

/**
 * Deletes the new image file forever (since the update was reverted)
 * and recovers the old image file from the trash bin back to its original location.
 */
function restoreRevertedImageFile(?string $oldImageUrl, ?string $newImageUrl): void {
    // 1. Delete the new image file forever
    if (!empty($newImageUrl)) {
        $newPath = $newImageUrl;
        if (strpos($newPath, 'https://') === 0 || strpos($newPath, 'http://') === 0) {
            $parsed = parse_url($newPath);
            $newPath = $parsed['path'] ?? '';
        }
        if (strpos($newPath, '/uploads/') === 0 && strpos($newPath, '/uploads/trash_bin/') !== 0) {
            $newRealFile = __DIR__ . $newPath;
            if (is_file($newRealFile)) {
                @unlink($newRealFile);
                error_log("🗑️ Reverted photo deleted forever: " . $newRealFile);
            }
        }
    }

    // 2. Recover the old image file from trash bin back to its original location
    if (!empty($oldImageUrl)) {
        $oldPath = $oldImageUrl;
        if (strpos($oldPath, 'https://') === 0 || strpos($oldPath, 'http://') === 0) {
            $parsed = parse_url($oldPath);
            $oldPath = $parsed['path'] ?? '';
        }
        if (strpos($oldPath, '/uploads/') === 0) {
            $trashPath = str_replace('/uploads/', '/uploads/trash_bin/', $oldPath);
            $trashRealFile = __DIR__ . $trashPath;
            $originalRealFile = __DIR__ . $oldPath;

            if (is_file($trashRealFile)) {
                $origDir = dirname($originalRealFile);
                if (!is_dir($origDir)) {
                    @mkdir($origDir, 0755, true);
                }
                if (@rename($trashRealFile, $originalRealFile) || (@copy($trashRealFile, $originalRealFile) && @unlink($trashRealFile))) {
                    error_log("🔄 Reverted photo recovered from trash bin: " . $trashPath . " -> " . $oldPath);
                }
            }
        }
    }
}

/**
 * Recovers a deleted photo from the trash bin back to its main uploads directory.
 */
function recoverRevertedImageFile(?string $imageUrl): void {
    if (empty($imageUrl)) return;

    $path = $imageUrl;
    if (strpos($path, 'https://') === 0 || strpos($path, 'http://') === 0) {
        $parsed = parse_url($path);
        $path = $parsed['path'] ?? '';
    }

    if (strpos($path, '/uploads/') === 0) {
        $trashPath = str_replace('/uploads/', '/uploads/trash_bin/', $path);
        $trashRealFile = __DIR__ . $trashPath;
        $originalRealFile = __DIR__ . $path;

        if (is_file($trashRealFile)) {
            $origDir = dirname($originalRealFile);
            if (!is_dir($origDir)) {
                @mkdir($origDir, 0755, true);
            }
            if (@rename($trashRealFile, $originalRealFile) || (@copy($trashRealFile, $originalRealFile) && @unlink($trashRealFile))) {
                error_log("🔄 Recovered photo from trash bin: " . $trashPath . " -> " . $path);
            }
        }
    }
}



// ── Game / QR processing for trips ─────────────────────────

function processGameQRCode()

{

    try {

        // Allow uncle or church admin

        checkUncleAuth();

        $churchId = getChurchId();

        $uncleId = $_SESSION['uncle_id'] ?? null;



        $tripId = intval($_REQUEST['trip'] ?? $_REQUEST['trip_id'] ?? 0);

        $studentId = intval($_REQUEST['id'] ?? $_REQUEST['student_id'] ?? 0);

        $game_action = strtolower(trim($_REQUEST['game_action'] ?? 'increment'));

        $amount = intval($_REQUEST['amount'] ?? 1);

        $actionName = sanitize($_REQUEST['action_name'] ?? '');



        if ($tripId <= 0 || $studentId <= 0) {

            sendJSON(['success' => false, 'message' => 'trip and id are required']);

            return;

        }



        $conn = getDBConnection();



        // Load student (don't restrict by church yet — collaboration may allow cross-church updates)

        $stmt = $conn->prepare("
            SELECT s.id, s.name, s.church_id, s.trip_points, s.image_url, c.church_name 
            FROM students s
            JOIN churches c ON s.church_id = c.id
            WHERE s.id = ? 
            LIMIT 1
        ");

        $stmt->bind_param('i', $studentId);

        $stmt->execute();

        $res = $stmt->get_result();

        if ($res->num_rows === 0) {

            sendJSON(['success' => false, 'message' => 'Student not found in this church']);

            return;

        }

        $student = $res->fetch_assoc();



        // Load trip to check collaborating churches

        $tstmt = $conn->prepare("SELECT id, title, church_id, points_config, collaborating_churches FROM trips WHERE id = ? LIMIT 1");

        $tstmt->bind_param('i', $tripId);

        $tstmt->execute();

        $tres = $tstmt->get_result();

        if ($tres->num_rows === 0) {

            sendJSON(['success' => false, 'message' => 'Trip not found']);

            return;

        }

        $trip = $tres->fetch_assoc();

        $pointsConfig = [];
        if (!empty($trip['points_config'])) {
            $pointsConfig = json_decode($trip['points_config'], true) ?? [];
        }
        $pointsPermission = $pointsConfig['points_permission'] ?? 'all';
        if ($amount > 0 || $game_action === 'naughty') {
            if ($pointsPermission === 'disabled') {
                sendJSON(['success' => false, 'message' => 'تم إيقاف تسجيل النقاط لهذه الرحلة']);
                return;
            } else if ($pointsPermission === 'admin') {
                $role = strtolower($_SESSION['uncle_role'] ?? '');
                if (!in_array($role, ['admin', 'developer', 'dev'])) {
                    sendJSON(['success' => false, 'message' => 'تسجيل النقاط متاح للمسؤولين فقط']);
                    return;
                }
            }
        }

        $pointsJson = $student['trip_points'] ?? '';

        // Determine participating churches for this trip (owner + collaborators)

        $participants = [$trip['church_id']];

        $collabRaw = $trip['collaborating_churches'] ?? '';

        $collab = [];

        if (!empty($collabRaw)) {

            $decodedCollab = json_decode($collabRaw, true);

            if (is_array($decodedCollab))

                $collab = array_map('intval', $decodedCollab);

        }

        $participants = array_unique(array_merge($participants, $collab));



        if ($churchId <= 0 || !in_array($churchId, $participants, true)) {

            sendJSON(['success' => false, 'message' => 'غير مصرح بتحديث نقاط هذه الرحلة']);

            return;

        }

        $studentChurchId = intval($student['church_id'] ?? 0);

        if (!in_array($studentChurchId, $participants, true)) {

            sendJSON(['success' => false, 'message' => 'هذا الطفل غير مسجل في رحلة مشتركة مع كنيستك']);

            return;

        }

        // Check if student is registered for this trip
        $regStmt = $conn->prepare("SELECT id FROM trip_registrations WHERE trip_id = ? AND student_id = ? AND cancelled = 0 LIMIT 1");
        $regStmt->bind_param('ii', $tripId, $studentId);
        $regStmt->execute();
        if ($regStmt->get_result()->num_rows === 0) {
            sendJSON(['success' => false, 'message' => 'هذا الطفل غير مسجل في هذه الرحلة']);
            return;
        }

        $points = json_decode($pointsJson, true);

        if (!is_array($points))

            $points = [];

        $oldRank = _getStudentTripRank($conn, $tripId, $studentId);



        $current = intval($points[$tripId] ?? 0);

        $undoingLogId = intval($_REQUEST['undoing_log_id'] ?? 0);
        if ($undoingLogId > 0) {
            $logCheck = $conn->prepare("SELECT id, change_amount FROM coupon_logs WHERE id = ? LIMIT 1");
            $logCheck->bind_param("i", $undoingLogId);
            $logCheck->execute();
            $logRes = $logCheck->get_result();
            if ($logRes->num_rows === 0) {
                // If it is already deleted/undone, return success but do NOT alter the points!
                sendJSON([
                    'success' => true,
                    'message' => 'تم التراجع عن هذه العملية بالفعل',
                    'points' => $current,
                    'is_naughty' => !empty($points["n_{$tripId}"])
                ]);
                return;
            }
            $logRow = $logRes->fetch_assoc();
            $origChange = intval($logRow['change_amount']);
            
            $amount = abs($origChange);
            $game_action = ($origChange > 0) ? 'decrement' : 'increment';
        }



        if ($game_action === 'increment') {

            $new = $current + $amount;

            $verb = "+{$amount}";

        } elseif ($game_action === 'decrement') {

            $new = $current - $amount;

            $verb = "-{$amount}";

        } elseif ($game_action === 'set') {

            $new = $amount;

            $verb = "={$amount}";

        } elseif ($game_action === 'naughty') {

            $isNaughty = !($points["n_{$tripId}"] ?? false);

            $points["n_{$tripId}"] = $isNaughty;

            $new = $current;

            $verb = $isNaughty ? "naughty_on" : "naughty_off";

        } else {

            sendJSON(['success' => false, 'message' => 'Invalid action']);

            return;

        }



        $points[$tripId] = $new;

        $newJson = json_encode($points, JSON_UNESCAPED_UNICODE);



        // Update student trip_points by id (no church constraint because student may belong to another church)

        $up = $conn->prepare("UPDATE students SET trip_points = ? WHERE id = ?");

        $up->bind_param('si', $newJson, $studentId);

        if (!$up->execute()) {

            sendJSON(['success' => false, 'message' => 'Failed to update points: ' . $up->error]);

            return;

        }



        // Log the points change in coupon_logs using trip_points_normal reason
        $changeAmount = 0;
        if ($game_action === 'increment') {
            $changeAmount = $amount;
        } elseif ($game_action === 'decrement') {
            $changeAmount = -1 * $amount;
        } elseif ($game_action === 'set') {
            $changeAmount = $new - $current;
        }

        $logId = 0;
        if ($changeAmount !== 0) {
            $undoingLogId = intval($_REQUEST['undoing_log_id'] ?? 0);
            if ($undoingLogId > 0) {
                $delStmt = $conn->prepare("DELETE FROM coupon_logs WHERE id = ?");
                $delStmt->bind_param("i", $undoingLogId);
                $delStmt->execute();
            } else {
                $reason = "trip_points_normal:" . $tripId;
                if (!empty($actionName)) {
                    $reason .= ":" . $actionName;
                }
                $logStmt = $conn->prepare("
                    INSERT INTO coupon_logs (student_id, uncle_id, old_count, new_count, change_amount, change_type, reason)
                    VALUES (?, ?, ?, ?, ?, 'manual', ?)
                ");
                $logStmt->bind_param("iiiiis", $studentId, $uncleId, $current, $new, $changeAmount, $reason);
                $logStmt->execute();
                $logId = $conn->insert_id;
            }

            // Audit log
            $auditReason = "نقاط بالرحلة (مسح عادي): " . ($changeAmount > 0 ? "+" . $changeAmount : $changeAmount);
            if (!empty($actionName)) {
                $auditReason .= " - " . $actionName;
            }
            auditCouponChange($studentId, $student['name'], $current, $new, $auditReason);
        }



        // Log activity

        $details = "trip_id:$tripId;student_id:$studentId;change:$verb;new:$new";

        logActivity($churchId, $uncleId, 'game_points', $details);



        // Notify admin via existing Google Apps Script path (keeps previous behaviour)

        // If you prefer server-side email, replace sendAsyncRequest with mail logic.

        try {

            $churchEmail = getChurchAdminEmail($churchId);

            $uncleEmail = null;

            if ($uncleId) {

                $u = $conn->prepare("SELECT email FROM uncles WHERE id = ? LIMIT 1");

                $u->bind_param('i', $uncleId);

                $u->execute();

                $ur = $u->get_result()->fetch_assoc();

                $uncleEmail = $ur['email'] ?? null;

            }



            if ($churchEmail || $uncleEmail) {

                $scriptUrl = 'https://script.google.com/macros/s/AKfycbxsDA0veJTA3C_2Bw47coffOagRigWwaZnyxWuGb_gSVUCWM958V1bUcaZDwfIHVZ7b1g/exec';

                $payload = [

                    'action' => 'notifyGameActivity',

                    'church_email' => $churchEmail,

                    'uncle_email' => $uncleEmail,

                    'church_id' => $churchId,

                    'trip_id' => $tripId,

                    'student_id' => $studentId,

                    'student_name' => $student['name'] ?? '',

                    'change' => $verb,

                    'new_points' => $new,

                    'timestamp' => date('Y-m-d H:i:s')

                ];

                sendAsyncRequest($scriptUrl, $payload);

            }

        } catch (Exception $e) {

            error_log('notifyGameActivity error: ' . $e->getMessage());

        }



        $isNaughty = $points["n_{$tripId}"] ?? false;

        if ($undoingLogId <= 0) {
            _checkAndNotifyTripRankUpgrade($conn, $tripId, $studentId, $oldRank, $student['name'], $churchId);

            if ($game_action === 'naughty') {
                $pointsConfig = json_decode($trip['points_config'] ?? '', true);
                $naughtyEnabled = isset($pointsConfig['notifications']['naughty']) ? (bool)$pointsConfig['notifications']['naughty'] : true; // default on

                if ($naughtyEnabled) {
                    $tripTitle = $trip['title'] ?? 'الرحلة';
                    if (empty($tripTitle) || $tripTitle === 'الرحلة') {
                        $tstmt2 = $conn->prepare("SELECT title FROM trips WHERE id = ? LIMIT 1");
                        $tstmt2->bind_param('i', $tripId);
                        if ($tstmt2->execute()) {
                            $tres2 = $tstmt2->get_result()->fetch_assoc();
                            if ($tres2) $tripTitle = $tres2['title'];
                        }
                    }

                    $title = $isNaughty ? "⚠️ تنبيه سلوك (شغب)!" : "✅ إلغاء تنبيه السلوك";
                    $body = $isNaughty 
                        ? "تم تسجيل حالة شغب للطفل {$student['name']} في رحلة {$tripTitle}."
                        : "تم إلغاء حالة الشغب للطفل {$student['name']} في رحلة {$tripTitle}.";

                    $extra = [
                        'notifType' => 'naughty_status',
                        'trip_id' => $tripId,
                        'student_id' => $studentId,
                        'is_naughty' => $isNaughty
                    ];

                    _sendWebPushToChurch($conn, $churchId, $title, $body, $extra);
                    _sendWebPushToKids($conn, $churchId, $title, $body, $extra);

                    if (function_exists('pushNotification')) {
                        pushNotification($conn, $churchId, 'naughty_status', $title, $body, 'naughty_status', $tripId);
                    }
                }
            }
        }

        sendJSON([
            'success' => true,
            'log_id' => $logId,
            'student_id' => $studentId,
            'student_name' => $student['name'],
            'trip_id' => $tripId,
            'points' => $new,
            'is_naughty' => $isNaughty,
            'change' => $changeAmount,
            'profile_photo' => $student['image_url'],
            'church_name' => $student['church_name'] ?? ''
        ]);



    } catch (Exception $e) {

        error_log('processGameQRCode error: ' . $e->getMessage());

        sendJSON(['success' => false, 'message' => 'Error: ' . $e->getMessage()]);

    }

}



function processFastScanPoints()
{
    try {
        checkUncleAuth();
        $churchId = getChurchId();
        $uncleId = $_SESSION['uncle_id'] ?? null;

        $tripId = intval($_REQUEST['trip_id'] ?? 0);
        $studentId = intval($_REQUEST['student_id'] ?? 0);
        $amount = intval($_REQUEST['amount'] ?? 0);

        if ($tripId <= 0 || $studentId <= 0 || $amount === 0) {
            sendJSON(['success' => false, 'message' => 'trip_id, student_id, and non-zero amount are required']);
            return;
        }

        $conn = getDBConnection();

        // 1. Load student details
        $stmt = $conn->prepare("SELECT id, name, church_id, trip_points, image_url, class FROM students WHERE id = ? LIMIT 1");
        $stmt->bind_param('i', $studentId);
        $stmt->execute();
        $res = $stmt->get_result();
        if ($res->num_rows === 0) {
            sendJSON(['success' => false, 'message' => 'Student not found']);
            return;
        }
        $student = $res->fetch_assoc();

        // 2. Load trip to check collaborating churches
        $tstmt = $conn->prepare("SELECT id, church_id, collaborating_churches, points_config FROM trips WHERE id = ? LIMIT 1");
        $tstmt->bind_param('i', $tripId);
        $tstmt->execute();
        $tres = $tstmt->get_result();
        if ($tres->num_rows === 0) {
            sendJSON(['success' => false, 'message' => 'Trip not found']);
            return;
        }
        $trip = $tres->fetch_assoc();

        $pointsConfig = [];
        if (!empty($trip['points_config'])) {
            $pointsConfig = json_decode($trip['points_config'], true) ?? [];
        }
        $pointsPermission = $pointsConfig['points_permission'] ?? 'all';
        if ($pointsPermission === 'disabled') {
            sendJSON(['success' => false, 'message' => 'تم إيقاف تسجيل النقاط لهذه الرحلة']);
            return;
        } else if ($pointsPermission === 'admin') {
            $role = strtolower($_SESSION['uncle_role'] ?? '');
            if (!in_array($role, ['admin', 'developer', 'dev'])) {
                sendJSON(['success' => false, 'message' => 'تسجيل النقاط متاح للمسؤولين فقط']);
                return;
            }
        }

        // Check participating churches
        $participants = [$trip['church_id']];
        $collabRaw = $trip['collaborating_churches'] ?? '';
        $collab = [];
        if (!empty($collabRaw)) {
            $decodedCollab = json_decode($collabRaw, true);
            if (is_array($decodedCollab)) {
                $collab = array_map('intval', $decodedCollab);
            }
        }
        $participants = array_unique(array_merge($participants, $collab));

        if ($churchId <= 0 || !in_array($churchId, $participants, true)) {
            sendJSON(['success' => false, 'message' => 'غير مصرح بتحديث نقاط هذه الرحلة']);
            return;
        }

        $studentChurchId = intval($student['church_id'] ?? 0);
        if (!in_array($studentChurchId, $participants, true)) {
            sendJSON(['success' => false, 'message' => 'هذا الطفل غير مسجل في رحلة مشتركة مع كنيستك']);
            return;
        }

        // Check if student is registered for this trip
        $regStmt = $conn->prepare("SELECT id FROM trip_registrations WHERE trip_id = ? AND student_id = ? AND cancelled = 0 LIMIT 1");
        $regStmt->bind_param('ii', $tripId, $studentId);
        $regStmt->execute();
        if ($regStmt->get_result()->num_rows === 0) {
            sendJSON(['success' => false, 'message' => 'هذا الطفل غير مسجل في هذه الرحلة']);
            return;
        }

        $oldRank = _getStudentTripRank($conn, $tripId, $studentId);

        // 3. Update student trip points
        $pointsJson = $student['trip_points'] ?? '';
        $points = json_decode($pointsJson, true);
        if (!is_array($points)) {
            $points = [];
        }
        $oldCount = intval($points[$tripId] ?? 0);

        $undoingLogId = intval($_REQUEST['undoing_log_id'] ?? 0);
        if ($undoingLogId > 0) {
            $logCheck = $conn->prepare("SELECT id, change_amount FROM coupon_logs WHERE id = ? LIMIT 1");
            $logCheck->bind_param("i", $undoingLogId);
            $logCheck->execute();
            $logRes = $logCheck->get_result();
            if ($logRes->num_rows === 0) {
                // If it is already deleted/undone, return success but do NOT alter the points!
                sendJSON([
                    'success' => true,
                    'message' => 'تم التراجع عن هذه العملية بالفعل',
                    'student_name' => $student['name'],
                    'student_class' => $student['class'],
                    'student_points' => $oldCount
                ]);
                return;
            }
            $logRow = $logRes->fetch_assoc();
            $origChange = intval($logRow['change_amount']);
            
            $amount = -1 * $origChange;
        }

        $newCount = max(0, $oldCount + $amount);
        $points[$tripId] = $newCount;
        $newJson = json_encode($points, JSON_UNESCAPED_UNICODE);

        $up = $conn->prepare("UPDATE students SET trip_points = ?, updated_at = NOW() WHERE id = ?");
        $up->bind_param('si', $newJson, $studentId);
        if (!$up->execute()) {
            sendJSON(['success' => false, 'message' => 'Failed to update points: ' . $up->error]);
            return;
        }

        // 4. Log the points change in coupon_logs using trip_points_scan reason
        $actionName = sanitize($_REQUEST['action_name'] ?? '');
        $logId = 0;
        $undoingLogId = intval($_REQUEST['undoing_log_id'] ?? 0);
        if ($undoingLogId > 0) {
            $delStmt = $conn->prepare("DELETE FROM coupon_logs WHERE id = ?");
            $delStmt->bind_param("i", $undoingLogId);
            $delStmt->execute();
        } else {
            $reason = "trip_points_scan:" . $tripId;
            if (!empty($actionName)) {
                $reason .= ":" . $actionName;
            }
            $logStmt = $conn->prepare("
                INSERT INTO coupon_logs (student_id, uncle_id, old_count, new_count, change_amount, change_type, reason)
                VALUES (?, ?, ?, ?, ?, 'manual', ?)
            ");
            $logStmt->bind_param("iiiiis", $studentId, $uncleId, $oldCount, $newCount, $amount, $reason);
            $logStmt->execute();
            $logId = $conn->insert_id;
        }

        // 5. Audit log
        $auditReason = "مسح سريع نقاط بالرحلة: " . ($amount > 0 ? "+" . $amount : $amount);
        if (!empty($actionName)) {
            $auditReason .= " - " . $actionName;
        }
        if ($undoingLogId <= 0) {
            _checkAndNotifyTripRankUpgrade($conn, $tripId, $studentId, $oldRank, $student['name'], $churchId);
        }

        sendJSON([
            'success' => true,
            'log_id' => $logId,
            'student_name' => $student['name'],
            'student_class' => $student['class'],
            'new_points' => $newCount,
            'change' => $amount,
            'profile_photo' => $student['image_url']
        ]);

    } catch (Exception $e) {
        error_log('processFastScanPoints error: ' . $e->getMessage());
        sendJSON(['success' => false, 'message' => 'Error: ' . $e->getMessage()]);
    }
}



function getLatestTripPointsScan()
{
    try {
        checkUncleAuth();
        $tripId = intval($_REQUEST['trip_id'] ?? 0);
        if ($tripId <= 0) {
            sendJSON(['success' => false, 'message' => 'trip_id is required']);
            return;
        }

        $conn = getDBConnection();
        $reason = "trip_points_scan:" . $tripId;

        $stmt = $conn->prepare("
            SELECT cl.id, cl.student_id, cl.change_amount, cl.created_at, s.name as student_name, s.image_url as profile_photo
            FROM coupon_logs cl
            JOIN students s ON cl.student_id = s.id
            WHERE (cl.reason LIKE CONCAT('trip_points_scan:', ?, '%')
               OR cl.reason LIKE CONCAT('trip_points_normal:', ?, '%'))
            ORDER BY cl.id DESC
            LIMIT 1
        ");
        $stmt->bind_param('ii', $tripId, $tripId);
        $stmt->execute();
        $res = $stmt->get_result();

        if ($res->num_rows === 0) {
            sendJSON(['success' => true, 'latest' => null]);
            return;
        }

        $row = $res->fetch_assoc();
        sendJSON([
            'success' => true,
            'latest' => [
                'log_id' => intval($row['id']),
                'student_id' => intval($row['student_id']),
                'student_name' => $row['student_name'],
                'profile_photo' => $row['profile_photo'],
                'change_amount' => intval($row['change_amount']),
                'created_at' => $row['created_at']
            ]
        ]);

    } catch (Exception $e) {
        error_log('getLatestTripPointsScan error: ' . $e->getMessage());
        sendJSON(['success' => false, 'message' => 'Error: ' . $e->getMessage()]);
    }
}



function getRecentTripPointsScans()
{
    try {
        checkUncleAuth();
        $tripId = intval($_REQUEST['trip_id'] ?? 0);
        if ($tripId <= 0) {
            sendJSON(['success' => false, 'message' => 'trip_id is required']);
            return;
        }

        $conn = getDBConnection();
        $reason = "trip_points_scan:" . $tripId;
        $uncleId = $_SESSION['uncle_id'] ?? null;

        $stmt = $conn->prepare("
            SELECT cl.id, cl.student_id, cl.change_amount, cl.created_at, cl.reason, cl.uncle_id,
                   s.name as student_name, s.image_url as profile_photo,
                   u.name as uncle_name,
                   c.church_name
            FROM coupon_logs cl
            JOIN students s ON cl.student_id = s.id
            JOIN churches c ON s.church_id = c.id
            LEFT JOIN uncles u ON cl.uncle_id = u.id
            WHERE cl.reason LIKE CONCAT('trip_points_scan:', ?, '%')
               OR cl.reason LIKE CONCAT('trip_points_normal:', ?, '%')
               OR cl.reason LIKE CONCAT('trip_points_scan_undo:', ?, ':%')
               OR cl.reason LIKE CONCAT('trip_points_normal_undo:', ?, ':%')
            ORDER BY cl.id DESC
            LIMIT 100
        ");
        $stmt->bind_param('iiii', $tripId, $tripId, $tripId, $tripId);
        
        $stmt->execute();
        $res = $stmt->get_result();

        $logs = [];
        while ($row = $res->fetch_assoc()) {
            $logs[] = [
                'log_id' => intval($row['id']),
                'student_id' => intval($row['student_id']),
                'student_name' => $row['student_name'],
                'profile_photo' => $row['profile_photo'],
                'change_amount' => intval($row['change_amount']),
                'reason' => $row['reason'],
                'uncle_id' => $row['uncle_id'] !== null ? intval($row['uncle_id']) : null,
                'uncle_name' => $row['uncle_name'] ?? 'أدمن الكنيسة',
                'created_at' => $row['created_at'],
                'church_name' => $row['church_name'] ?? ''
            ];
        }

        sendJSON([
            'success' => true,
            'current_uncle_id' => $uncleId !== null ? intval($uncleId) : null,
            'scans' => $logs
        ]);

    } catch (Exception $e) {
        error_log('getRecentTripPointsScans error: ' . $e->getMessage());
        sendJSON(['success' => false, 'message' => 'Error: ' . $e->getMessage()]);
    }
}

function getTripLeaderboard()
{
    try {
        checkUncleAuth();
        $tripId = intval($_REQUEST['trip_id'] ?? 0);
        if ($tripId <= 0) {
            sendJSON(['success' => false, 'message' => 'trip_id is required']);
            return;
        }

        $limit = intval($_REQUEST['limit'] ?? 10);
        if ($limit <= 0 || $limit > 1000) {
            $limit = 10;
        }

        $timeFilter = $_REQUEST['time_filter'] ?? 'overall';
        
        $conn = getDBConnection();
        
        $dateFilterSql = "";
        if ($timeFilter === 'today') {
            $dateFilterSql = "AND DATE(cl.created_at) = CURDATE()";
        } elseif ($timeFilter === 'yesterday') {
            $dateFilterSql = "AND DATE(cl.created_at) = DATE_SUB(CURDATE(), INTERVAL 1 DAY)";
        }
        
        $stmt = $conn->prepare("
            SELECT s.id, s.name, s.image_url as profile_photo, s.class, c.church_name, SUM(cl.change_amount) as total_points
            FROM coupon_logs cl
            JOIN students s ON cl.student_id = s.id
            LEFT JOIN churches c ON s.church_id = c.id
            WHERE (cl.reason LIKE CONCAT('trip_points_scan:', ?, '%')
               OR cl.reason LIKE CONCAT('trip_points_normal:', ?, '%'))
               $dateFilterSql
            GROUP BY s.id, s.name, s.image_url, s.class, c.church_name
            HAVING total_points > 0
            ORDER BY total_points DESC
            LIMIT ?
        ");
        $stmt->bind_param('iii', $tripId, $tripId, $limit);
        $stmt->execute();
        $res = $stmt->get_result();
        
        $list = [];
        while ($row = $res->fetch_assoc()) {
            $list[] = [
                'student_id' => intval($row['id']),
                'name' => $row['name'],
                'profile_photo' => $row['profile_photo'],
                'class' => $row['class'],
                'church_name' => $row['church_name'],
                'total_points' => intval($row['total_points'])
            ];
        }
        
        sendJSON([
            'success' => true,
            'leaderboard' => $list
        ]);
    } catch (Exception $e) {
        sendJSON(['success' => false, 'message' => 'Internal server error: ' . $e->getMessage()]);
    }
}

function updateTripPointsConfig()

{

    try {

        checkAuth();

        $churchId = getChurchId();

        $tripId = intval($_POST['trip_id'] ?? 0);

        $configJson = $_POST['config_json'] ?? '';



        if ($tripId <= 0 || empty($configJson)) {

            sendJSON(['success' => false, 'message' => 'trip_id and config_json are required']);

            return;

        }



        // Validate JSON

        $decoded = json_decode($configJson, true);

        if (!is_array($decoded)) {

            sendJSON(['success' => false, 'message' => 'config_json must be valid JSON']);

            return;

        }



        $conn = getDBConnection();

        $stmt = $conn->prepare("UPDATE trips SET points_config = ? WHERE id = ? AND church_id = ?");

        $stmt->bind_param('sii', $configJson, $tripId, $churchId);

        if ($stmt->execute()) {

            logActivity($churchId, $_SESSION['uncle_id'] ?? null, 'update_trip_points_config', "trip:$tripId");

            sendJSON(['success' => true, 'message' => 'Trip points config saved']);

        } else {

            sendJSON(['success' => false, 'message' => 'Failed to save config: ' . $stmt->error]);

        }



    } catch (Exception $e) {

        error_log('updateTripPointsConfig error: ' . $e->getMessage());

        sendJSON(['success' => false, 'message' => 'Error: ' . $e->getMessage()]);

    }

}



