                $coupons,
                $totalCoupons,
                $photoUrl,
                $customInfoJson,
                $gender,
                $addedByType
            );
        }

        if ($stmt->execute()) {
            $studentId = $conn->insert_id;

            if (!empty($tempid)) {
                $insTemp = $conn->prepare("INSERT INTO student_temp_ids (student_id, temp_id) VALUES (?, ?) ON DUPLICATE KEY UPDATE temp_id = VALUES(temp_id)");
                $insTemp->bind_param("is", $studentId, $tempid);
                $insTemp->execute();
            }

            // ► AUDIT
            auditStudentAdd($studentId, $name, [
                'name' => $name,
                'class' => $className,
                'class_id' => $classId,
                'phone' => $cleanPhone,
                'address' => $address,
                'birthday' => $formattedBirthday,
                'coupons' => $coupons,
            ]);

            // Register in trip if trip_id is passed
            if ($tripId) {
                $checkReg = $conn->prepare("SELECT id FROM trip_registrations WHERE trip_id = ? AND student_id = ? AND cancelled = 0 LIMIT 1");
                $checkReg->bind_param("ii", $tripId, $studentId);
                $checkReg->execute();
                if ($checkReg->get_result()->num_rows === 0) {
                    $ins = $conn->prepare("INSERT INTO trip_registrations (trip_id, student_id, payment_status, notes) VALUES (?, ?, 'not_paid', 'Linked via QR card')");
                    $ins->bind_param("ii", $tripId, $studentId);
                    $ins->execute();
                }
            }

            sendJSON([
                'success' => true,
                'message' => 'تم إضافة الطفل بنجاح',
                'studentId' => $studentId,
                'photoUrl' => !empty($photoUrl) ? $photoUrl : null,
                'phone' => $cleanPhone
            ]);
        } else {
            error_log("❌ SQL Error: " . $stmt->error);
            sendJSON(['success' => false, 'message' => 'فشل في إضافة الطفل: ' . $stmt->error]);
        }



    } catch (Exception $e) {

        error_log("❌ addStudent error: " . $e->getMessage());

        sendJSON(['success' => false, 'message' => 'خطأ في إضافة الطفل: ' . $e->getMessage()]);

    }

}



function updateStudentImageAfterCreation()

{

    try {

        $conn = getDBConnection();

        $studentId = intval($_POST['studentId'] ?? 0);



        if ($studentId === 0) {

            sendJSON(['success' => false, 'message' => 'معرف الطفل مطلوب']);

            return;

        }



        $studentExistsStmt = $conn->prepare("SELECT id, name, image_url FROM students WHERE id = ? LIMIT 1");

        $studentExistsStmt->bind_param("i", $studentId);

        $studentExistsStmt->execute();

        $studentRow = $studentExistsStmt->get_result()->fetch_assoc();
        if (!$studentRow) {

            sendJSON(['success' => false, 'message' => 'Student not found']);

            return;

        }
        $oldImageUrl = $studentRow['image_url'] ?? '';
        $studentName = $studentRow['name'] ?? '';



        // Handle photo upload

        $photoUrl = null;

        if (isset($_FILES['photo']) && $_FILES['photo']['error'] === UPLOAD_ERR_OK) {

            error_log("Photo uploaded for update, starting upload process...");



            // Get student info for filename

            $infoStmt = $conn->prepare("SELECT name, phone FROM students WHERE id = ?");

            $infoStmt->bind_param("i", $studentId);

            $infoStmt->execute();

            $result = $infoStmt->get_result();



            if ($student = $result->fetch_assoc()) {

                $name = $student['name'];

                $phone = $student['phone'];



                // Clean phone for filename

                $cleanPhone = preg_replace('/[^\d]/', '', $phone);

                $photoFilename = !empty($cleanPhone) ?

                    "profile_{$cleanPhone}_" . time() . ".jpg" :

                    "profile_" . preg_replace('/[^a-zA-Z0-9]/', '_', $name) . "_" . time() . ".jpg";



                // Use the correct upload directory

                $uploadDir = __DIR__ . '/uploads/students/';



                // Create directory if it doesn't exist

                if (!is_dir($uploadDir)) {

                    mkdir($uploadDir, 0755, true);

                }



                $uploadPath = $uploadDir . $photoFilename;



                // Check file type

                $allowedTypes = ['image/jpeg', 'image/jpg', 'image/png', 'image/gif'];

                $fileType = mime_content_type($_FILES['photo']['tmp_name']);



                if (!in_array($fileType, $allowedTypes)) {

                    sendJSON(['success' => false, 'message' => 'نوع الملف غير مسموح به. المسموح: JPG, PNG, GIF']);

                    return;

                }



                // Move uploaded file

                if (move_uploaded_file($_FILES['photo']['tmp_name'], $uploadPath)) {

                    $photoUrl = "https://" . ($_SERVER['HTTP_HOST'] ?? 'sunday-school.online') . "/uploads/students/" . $photoFilename;

                    error_log("Photo uploaded successfully: $photoUrl");

                } else {

                    error_log("Failed to move uploaded file for update");

                }

            }

        } else {

            // If no file, use the provided URL

            $photoUrl = sanitize($_POST['imageUrl'] ?? '');

        }



        if ($photoUrl === null) {

            sendJSON(['success' => false, 'message' => 'لا توجد صورة مرفوعة']);

            return;

        }



        // Update the student record

        $updateStmt = $conn->prepare("UPDATE students SET image_url = ? WHERE id = ?");

        $updateStmt->bind_param("si", $photoUrl, $studentId);



        if ($updateStmt->execute()) {

            if (!empty($oldImageUrl)) {
                deleteUploadedFile($oldImageUrl);
            }

            writeAuditLog('student_edit', 'student', $studentId, $studentName, ['image_url' => $oldImageUrl], ['image_url' => $photoUrl], 'تعديل صورة الطفل');

            $verifyStmt = $conn->prepare("SELECT image_url FROM students WHERE id = ? LIMIT 1");

            $verifyStmt->bind_param("i", $studentId);

            $verifyStmt->execute();

            $saved = $verifyStmt->get_result()->fetch_assoc();

            $savedUrl = $saved['image_url'] ?? '';



            if ($savedUrl !== $photoUrl) {

                sendJSON(['success' => false, 'message' => 'Photo uploaded but was not saved to the student profile']);

                return;

            }



            sendJSON([

                'success' => true,

                'message' => 'Photo updated successfully',

                'student_id' => $studentId,

                'imageUrl' => $savedUrl

            ]);

            return;

            sendJSON(['success' => true, 'message' => 'تم تحديث الصورة بنجاح']);

        } else {

            sendJSON(['success' => false, 'message' => 'فشل في تحديث الصورة: ' . $updateStmt->error]);

        }



    } catch (Exception $e) {

        error_log("updateStudentImageAfterCreation error: " . $e->getMessage());

        sendJSON(['success' => false, 'message' => 'خطأ في تحديث الصورة']);

    }

}

function updateStudent()

{

    try {

        $churchId = getChurchId();

        $studentId = intval($_POST['studentId'] ?? 0);

        $name = sanitize($_POST['name'] ?? '');

        $classId = intval($_POST['classId'] ?? 0);

        $address = sanitize($_POST['address'] ?? '');

        $phone = $_POST['phone'] ?? '';

        $emergencyPhone = $_POST['emergency_phone'] ?? '';

        $medicalNotes = sanitize($_POST['medical_notes'] ?? '');

        $birthday = sanitize($_POST['birthday'] ?? '');

        $coupons = max(0, intval($_POST['coupons'] ?? 0));



        if ($studentId === 0 || empty($name) || $classId === 0) {

            sendJSON(['success' => false, 'message' => 'بيانات غير كاملة']);

            return;

        }



        // Phone cleaning

        $cleanPhone = preg_replace('/\s+/', '', $phone);

        $cleanPhone = preg_replace("/^'+/", '', $cleanPhone);

        $cleanPhone = preg_replace('/[^\d]/', '', $cleanPhone);



        if (!empty($cleanPhone) && substr($cleanPhone, 0, 1) !== '0') {

            $cleanPhone = '0' . $cleanPhone;

        }



        if (!empty($cleanPhone) && !preg_match('/^01[0-9]{9}$/', $cleanPhone)) {

            sendJSON(['success' => false, 'message' => 'رقم الهاتف يجب أن يبدأ بـ 01 ويتكون من 11 رقم']);

            return;

        }



        $cleanEmergencyPhone = preg_replace('/\s+/', '', $emergencyPhone);

        $cleanEmergencyPhone = preg_replace("/^'+/", '', $cleanEmergencyPhone);

        $cleanEmergencyPhone = preg_replace('/[^\d]/', '', $cleanEmergencyPhone);

        if (!empty($cleanEmergencyPhone) && substr($cleanEmergencyPhone, 0, 1) !== '0') {

            $cleanEmergencyPhone = '0' . $cleanEmergencyPhone;

        }

        if (!empty($cleanEmergencyPhone) && !preg_match('/^01[0-9]{9}$/', $cleanEmergencyPhone)) {

            sendJSON(['success' => false, 'message' => 'تليفون الطوارئ يجب أن يبدأ بـ 01 ويتكون من 11 رقم']);

            return;

        }



        $conn = getDBConnection();



        // Check student exists in this church

        ensureStudentSiblingGroupTables($conn);



        $checkStmt = $conn->prepare("

            SELECT id, attendance_coupons, custom_info 

            FROM students 

            WHERE id = ? AND church_id = ?

        ");

        $checkStmt->bind_param("ii", $studentId, $churchId);

        $checkStmt->execute();

        $result = $checkStmt->get_result();



        if ($result->num_rows === 0) {

            sendJSON(['success' => false, 'message' => 'لم يتم العثور على الطفل']);

            return;

        }



        $row = $result->fetch_assoc();

        $attendanceCoupons = intval($row['attendance_coupons']);

        $existingCustomInfoRaw = $row['custom_info'] ?? null;



        // Check duplicate name in same class (exclude current student)

        $duplicateStmt = $conn->prepare("

            SELECT id FROM students 

            WHERE church_id = ? 

            AND LOWER(TRIM(name)) = LOWER(TRIM(?)) 

            AND class_id = ? 

            AND id != ?

        ");

        $normalizedName = trim($name);

        $duplicateStmt->bind_param("isii", $churchId, $normalizedName, $classId, $studentId);

        $duplicateStmt->execute();



        if ($duplicateStmt->get_result()->num_rows > 0) {

            sendJSON(['success' => false, 'message' => 'اسم الطفل موجود بالفعل في هذا الفصل']);

            return;

        }



        // Format birthday

        $formattedBirthday = null;

        if (!empty($birthday)) {

            $formattedBirthday = formatDateToDB($birthday);

            if (!$formattedBirthday) {

                sendJSON(['success' => false, 'message' => 'تاريخ الميلاد غير صحيح']);

                return;

            }

        }



        // Get class name — church_classes first, then global

        $classStmt = $conn->prepare("

            SELECT arabic_name FROM church_classes 

            WHERE id = ? AND church_id = ? AND is_active = 1

            UNION

            SELECT arabic_name FROM classes 

            WHERE id = ?

            LIMIT 1

        ");

        $classStmt->bind_param("iii", $classId, $churchId, $classId);

        $classStmt->execute();

        $classResult = $classStmt->get_result();

        $classData = $classResult->fetch_assoc();

        $className = $classData['arabic_name'] ?? '';



        $currentCouponsStmt = $conn->prepare("

            SELECT attendance_coupons, commitment_coupons, task_coupons

            FROM students WHERE id = ?

        ");

        $currentCouponsStmt->bind_param("i", $studentId);

        $currentCouponsStmt->execute();

        $currentData = $currentCouponsStmt->get_result()->fetch_assoc();

        $attendanceCoupons = intval($currentData['attendance_coupons']);

        $taskCoupons = intval($currentData['task_coupons'] ?? 0);



        // Get snapshot BEFORE update

        $beforeSnapshot = getStudentSnapshot($studentId);



        // $coupons from POST = the new commitment_coupons value

        $totalCoupons = $attendanceCoupons + $coupons + $taskCoupons;



        error_log("Coupons calculation: attendance=$attendanceCoupons + commitment=$coupons + task=$taskCoupons = total=$totalCoupons");



        // Custom info — merge with existing; sibling links always come from DB table by student id

        $customInfoRaw = $_POST['custom_info'] ?? null;

        $customInfoJson = null;

        if ($customInfoRaw !== null) {

            if (trim($customInfoRaw) === '') {

                $customInfoJson = mergeStudentCustomInfoForUpdate($conn, $studentId, $existingCustomInfoRaw, []);

            } else {

                $decoded = json_decode($customInfoRaw, true);

                if (!is_array($decoded)) {

                    $decoded = ['field_0' => sanitize($customInfoRaw)];

                }

                $customInfoJson = mergeStudentCustomInfoForUpdate($conn, $studentId, $existingCustomInfoRaw, $decoded);

            }

        }



        $gender = sanitize($_POST['gender'] ?? '');

        if ($gender !== 'male' && $gender !== 'female') {

            $gender = detectGenderFromName($name);

        }



        if ($customInfoRaw !== null) {

            $updateStmt = $conn->prepare("

                UPDATE students 

                SET name = ?, class_id = ?, class = ?, address = ?, phone = ?, emergency_phone = ?, medical_notes = ?, birthday = ?, 

                    commitment_coupons = ?, coupons = ?, custom_info = ?, gender = ?, updated_at = NOW()

                WHERE id = ? AND church_id = ?

            ");

            safeBindParam(

                $updateStmt,

                $name,

                $classId,

                $className,

                $address,

                $cleanPhone,

                $cleanEmergencyPhone,

                $medicalNotes,

                $formattedBirthday,

                $coupons,

                $totalCoupons,

                $customInfoJson,

                $gender,

                $studentId,

                $churchId

            );

        } else {

            $updateStmt = $conn->prepare("

                UPDATE students 

                SET name = ?, class_id = ?, class = ?, address = ?, phone = ?, emergency_phone = ?, medical_notes = ?, birthday = ?, 

                    commitment_coupons = ?, coupons = ?, gender = ?, updated_at = NOW()

                WHERE id = ? AND church_id = ?

            ");

            safeBindParam(

                $updateStmt,

                $name,

                $classId,

                $className,

                $address,

                $cleanPhone,

                $cleanEmergencyPhone,

                $medicalNotes,

                $formattedBirthday,

                $coupons,

                $totalCoupons,

                $gender,

                $studentId,

                $churchId

            );

        }



        if ($updateStmt->execute()) {

            // Get snapshot AFTER update

            $afterSnapshot = getStudentSnapshot($studentId);



            // ► AUDIT

            auditStudentEdit($studentId, $beforeSnapshot ?? [], $afterSnapshot ?? []);



            sendJSON([

                'success' => true,

                'message' => 'تم تحديث معلومات الطفل بنجاح',

                'studentId' => $studentId,

                'phone' => $cleanPhone

            ]);

        } else {

            error_log("❌ Update failed: " . $conn->error);

            sendJSON(['success' => false, 'message' => 'فشل في تحديث الطفل: ' . $conn->error]);

        }

    } catch (Exception $e) {

        error_log("updateStudent error: " . $e->getMessage());

        sendJSON(['success' => false, 'message' => 'خطأ في تحديث الطفل: ' . $e->getMessage()]);

    }

}



function reviewStudentGender()

{

        try {

            $churchId = getChurchId();

            $studentId = intval($_POST['student_id'] ?? 0);

            $action = sanitize($_POST['action'] ?? '');

            $suggestedGender = sanitize($_POST['suggested_gender'] ?? '');



            if ($studentId === 0 || !in_array($action, ['approve', 'reject'], true)) {

                sendJSON(['success' => false, 'message' => 'بيانات المراجعة غير صحيحة']);

                return;

            }



            $conn = getDBConnection();

            $checkStmt = $conn->prepare("SELECT custom_info FROM students WHERE id = ? AND church_id = ?");

            $checkStmt->bind_param('ii', $studentId, $churchId);

            $checkStmt->execute();

            $result = $checkStmt->get_result();

            if ($result->num_rows === 0) {

                sendJSON(['success' => false, 'message' => 'لم يتم العثور على الطفل']);

                return;

            }



            $row = $result->fetch_assoc();

            $customInfo = json_decode($row['custom_info'] ?? 'null', true);

            if (!is_array($customInfo)) {

                $customInfo = [];

            }



            if ($action === 'approve') {

                if ($suggestedGender !== 'male' && $suggestedGender !== 'female') {

                    sendJSON(['success' => false, 'message' => 'النوع المقترح غير صالح']);

                    return;

                }

                $customInfo['gender_review_status'] = 'approved';

                $customInfo['gender_suggestion'] = $suggestedGender;

                $customInfoJson = json_encode($customInfo, JSON_UNESCAPED_UNICODE);

                $updateStmt = $conn->prepare("UPDATE students SET gender = ?, custom_info = ?, updated_at = NOW() WHERE id = ? AND church_id = ?");

                $updateStmt->bind_param('ssii', $suggestedGender, $customInfoJson, $studentId, $churchId);

            } else {

                $customInfo['gender_review_status'] = 'rejected';

                $customInfoJson = json_encode($customInfo, JSON_UNESCAPED_UNICODE);

                $updateStmt = $conn->prepare("UPDATE students SET custom_info = ?, updated_at = NOW() WHERE id = ? AND church_id = ?");

                $updateStmt->bind_param('sii', $customInfoJson, $studentId, $churchId);

            }



            if ($updateStmt->execute()) {

                sendJSON(['success' => true, 'message' => 'تم تحديث مراجعة النوع بنجاح']);

            } else {

                error_log("❌ reviewStudentGender failed: " . $conn->error);

                sendJSON(['success' => false, 'message' => 'فشل في حفظ مراجعة النوع']);

            }

        } catch (Exception $e) {

            sendJSON(['success' => false, 'message' => 'خطأ في الخادم']);

        }

    }

function updateStudentInfo()

{

    try {

        $studentId = intval($_POST['studentId'] ?? 0);

        $name = sanitize($_POST['name'] ?? '');

        $address = sanitize($_POST['address'] ?? '');

        $phone = sanitize($_POST['phone'] ?? '');

        $birthday = sanitize($_POST['birthday'] ?? '');



        if ($studentId === 0 || empty($name)) {

            sendJSON(['success' => false, 'message' => 'بيانات غير كاملة']);

            return;

        }



        // Format birthday using our function

        $formattedBirthday = null;

        if (!empty($birthday)) {

            $formattedBirthday = formatDateToDB($birthday);

            if (!$formattedBirthday) {

                sendJSON(['success' => false, 'message' => 'تاريخ الميلاد غير صحيح. استخدم DD/MM/YYYY']);

                return;

            }

        }



        $conn = getDBConnection();



        // Check if phone is already used by another student

        if (!empty($phone)) {

            $cleanPhone = preg_replace('/[^\d]/', '', $phone);



            $checkPhoneStmt = $conn->prepare("

                SELECT id FROM students 

                WHERE phone LIKE CONCAT('%', ?) AND id != ?

            ");

            $checkPhoneStmt->bind_param("si", $cleanPhone, $studentId);

            $checkPhoneStmt->execute();



            if ($checkPhoneStmt->get_result()->num_rows > 0) {

                sendJSON(['success' => false, 'message' => 'رقم الهاتف مستخدم بالفعل من قبل طفل آخر']);

                return;

            }

        }



        $gender = sanitize($_POST['gender'] ?? '');

        if ($gender !== 'male' && $gender !== 'female') {

            $gender = detectGenderFromName($name);

        }



        // Update student information

        $stmt = $conn->prepare("

            UPDATE students 

            SET name = ?, address = ?, phone = ?, birthday = ?, gender = ?, updated_at = NOW()

            WHERE id = ?

        ");

        $stmt->bind_param(

            "sssssi",

            $name,

            $address,

            $phone,

            $formattedBirthday,

            $gender,

            $studentId

        );



        if ($stmt->execute()) {

            // Update password if provided

            if (isset($_POST['password']) && !empty($_POST['password'])) {

                $password = $_POST['password'];

                $passwordHash = hash('sha256', $password);



                $updatePassStmt = $conn->prepare("

                    UPDATE students 

                    SET password_hash = ?

                    WHERE id = ?

                ");

                $updatePassStmt->bind_param("si", $passwordHash, $studentId);

                $updatePassStmt->execute();

            }



            sendJSON([

                'success' => true,

                'message' => 'تم تحديث المعلومات بنجاح'

            ]);

        } else {

            sendJSON(['success' => false, 'message' => 'فشل في تحديث المعلومات: ' . $conn->error]);

        }



    } catch (Exception $e) {

        error_log("updateStudentInfo error: " . $e->getMessage());

        sendJSON(['success' => false, 'message' => 'خطأ في تحديث المعلومات: ' . $e->getMessage()]);

    }

}



function updateCoupons()

{

    try {

        error_log("🔄 updateCoupons called");



        $churchId = getChurchId();

        $className = sanitize($_POST['className'] ?? '');

        $couponData = json_decode($_POST['couponData'] ?? '[]', true);



        error_log("Church ID: $churchId, Class: $className");

        error_log("Coupon Data: " . json_encode($couponData));



        if (empty($couponData)) {

            sendJSON(['success' => false, 'message' => 'لا توجد بيانات كوبونات']);

            return;

        }



        $conn = getDBConnection();

        $successCount = 0;

        $failCount = 0;



        foreach ($couponData as $record) {

            $studentName = sanitize($record['studentName'] ?? '');

            $coupons = max(0, intval($record['coupons'] ?? 0));



            error_log("Updating: $studentName -> $coupons coupons");



            // Search by student name and church_id only (no class JOIN that might fail)

            $stmt = $conn->prepare("

                SELECT id, coupons, attendance_coupons, task_coupons

                FROM students 

                WHERE church_id = ? AND name = ?

            ");

            $stmt->bind_param("is", $churchId, $studentName);

            $stmt->execute();

            $result = $stmt->get_result();



            if ($row = $result->fetch_assoc()) {

                $studentId = $row['id'];

                $oldTotal = intval($row['coupons']);

                $attendanceCoupons = intval($row['attendance_coupons']);

                $taskCoupons = intval($row['task_coupons'] ?? 0);

                $totalCoupons = $attendanceCoupons + $coupons + $taskCoupons;



                $updateStmt = $conn->prepare("

                    UPDATE students 

                    SET commitment_coupons = ?,

                        coupons = ?,

                        updated_at = NOW()

                    WHERE id = ? AND church_id = ?

                ");

                $updateStmt->bind_param("iiii", $coupons, $totalCoupons, $studentId, $churchId);



                if ($updateStmt->execute()) {

                    error_log("✅ Updated $studentName: commitment=$coupons, total=$totalCoupons");

                    // ► AUDIT

                    auditCouponChange($studentId, $studentName, $oldTotal, $totalCoupons, 'تعديل دفعة (التزام)');

                    _sendWebPushToKids($conn, $churchId, 'رصيد كوبونات جديد 🎟️', "تم تحديث رصيد الكوبونات الخاص بك. الرصيد الحالي: {$totalCoupons}", [
                        'notifType' => 'coupons',
                        'url' => '/user/',
                        'student_ids' => (string)$studentId
                    ]);

                    $successCount++;

                } else {

                    error_log("❌ Failed to update $studentName: " . $updateStmt->error);

                    $failCount++;

                }

            } else {

                error_log("⚠️ Student not found: $studentName in church $churchId");

                $failCount++;

            }

        }



        if ($successCount > 0) {

            sendJSON([

                'success' => true,

                'message' => "تم تحديث كوبونات $successCount طفل بنجاح" . ($failCount > 0 ? " (فشل $failCount)" : ''),

                'updated' => $successCount,

                'failed' => $failCount

            ]);

        } else {

            sendJSON([

                'success' => false,

                'message' => 'لم يتم تحديث أي كوبونات - تحقق من أسماء الأطفال',

                'updated' => 0,

                'failed' => $failCount

            ]);

        }



    } catch (Exception $e) {

        error_log("❌ updateCoupons error: " . $e->getMessage());

        sendJSON(['success' => false, 'message' => 'خطأ في تحديث الكوبونات: ' . $e->getMessage()]);

    }

}

// ===== GET CHURCH CLASSES WITH STUDENT COUNT =====

function getChurchClassesWithStats()

{

    try {

        $churchId = getChurchId();



        $conn = getDBConnection();



        // تحقق من وجود فصول مخصصة

        $checkCustom = $conn->prepare("SELECT COUNT(*) as cnt FROM church_classes WHERE church_id = ?");

        $checkCustom->bind_param("i", $churchId);

        $checkCustom->execute();

        $hasCustom = $checkCustom->get_result()->fetch_assoc()['cnt'] > 0;



        if ($hasCustom) {

            // فصول مخصصة مع عدد الأطفال

            $stmt = $conn->prepare("

                SELECT 

                    cc.id,

                    cc.code,

                    cc.arabic_name,

                    cc.display_order,

                    COUNT(s.id) as student_count

                FROM church_classes cc

                LEFT JOIN students s ON s.class_id = cc.id AND s.church_id = ?

                WHERE cc.church_id = ? AND cc.is_active = 1

                GROUP BY cc.id

                ORDER BY cc.display_order

            ");

            $stmt->bind_param("ii", $churchId, $churchId);

        } else {

            // فصول افتراضية مع عدد الأطفال

            $stmt = $conn->prepare("

                SELECT 

                    c.id,

                    c.code,

                    c.arabic_name,

                    c.display_order,

                    COUNT(s.id) as student_count

                FROM classes c

                LEFT JOIN students s ON s.class_id = c.id AND s.church_id = ?

                GROUP BY c.id

                ORDER BY c.display_order

            ");

            $stmt->bind_param("i", $churchId);

        }



        $stmt->execute();

        $result = $stmt->get_result();



        $classes = [];

        while ($row = $result->fetch_assoc()) {

            $classes[] = [

                'id' => (int) $row['id'],

                'code' => $row['code'],

                'arabic_name' => $row['arabic_name'],

                'display_order' => (int) $row['display_order'],

                'student_count' => (int) $row['student_count'],

                'is_custom' => $hasCustom

            ];

        }



        sendJSON([

            'success' => true,

            'classes' => $classes,

            'has_custom' => $hasCustom

        ]);



    } catch (Exception $e) {

        error_log("getChurchClassesWithStats error: " . $e->getMessage());

        sendJSON(['success' => false, 'message' => 'خطأ في تحميل الفصول']);

    }

}

// ===== GET PUBLIC CHURCH CLASSES (للتسجيل العام) =====

function getPublicChurchClasses()

{

    try {

        $churchId = intval($_POST['church_id'] ?? $_GET['church_id'] ?? 0);



        if ($churchId === 0) {

            sendJSON(['success' => false, 'message' => 'معرف الكنيسة مطلوب']);

            return;

        }



        $conn = getDBConnection();



        // أولاً: تحقق من وجود فصول مخصصة لهذه الكنيسة

        $customStmt = $conn->prepare("

            SELECT COUNT(*) as count 

            FROM church_classes 

            WHERE church_id = ? AND is_active = 1

        ");

        $customStmt->bind_param("i", $churchId);

        $customStmt->execute();

        $customResult = $customStmt->get_result();

        $hasCustom = $customResult->fetch_assoc()['count'] > 0;



        if ($hasCustom) {

            // إذا وجدت فصول مخصصة، أرجعها

            $classStmt = $conn->prepare("

                SELECT id, code, arabic_name, display_order

                FROM church_classes 

                WHERE church_id = ? AND is_active = 1

                ORDER BY display_order, arabic_name

            ");

            $classStmt->bind_param("i", $churchId);

        } else {

            // إذا لم توجد فصول مخصصة، أرجع الفصول الافتراضية من جدول classes

            $classStmt = $conn->prepare("

                SELECT id, code, arabic_name, display_order

                FROM classes 

                ORDER BY display_order

            ");

        }



        $classStmt->execute();

        $result = $classStmt->get_result();



        $classes = [];

        while ($row = $result->fetch_assoc()) {

            $classes[] = [

                'id' => $row['id'],

                'code' => $row['code'],

                'arabic_name' => $row['arabic_name'],

                'display_order' => $row['display_order'],

                'is_custom' => $hasCustom

            ];

        }



        // Load custom registration fields for this church

        $customFields = [];

        try {

            $cfStmt = $conn->prepare("SELECT custom_field FROM church_settings WHERE church_id = ? LIMIT 1");

            $cfStmt->bind_param("i", $churchId);

            $cfStmt->execute();

            $cfRow = $cfStmt->get_result()->fetch_assoc();

            if ($cfRow && !empty($cfRow['custom_field'])) {

                $decoded = json_decode($cfRow['custom_field'], true);

                if (is_array($decoded))

                    $customFields = $decoded;

            }

        } catch (Exception $cfErr) {

            error_log("getPublicChurchClasses custom_field error: " . $cfErr->getMessage());

        }



        sendJSON([

            'success' => true,

            'classes' => $classes,

            'has_custom' => $hasCustom,

            'custom_fields' => $customFields,

            'message' => $hasCustom ? 'تم تحميل الفصول المخصصة' : 'تم تحميل الفصول الافتراضية'

        ]);



    } catch (Exception $e) {

        error_log("getPublicChurchClasses error: " . $e->getMessage());

        sendJSON(['success' => false, 'message' => 'خطأ في تحميل الفصول']);

    }

}

// ===== FIXED: DELETE STUDENT =====

function deleteStudent()

{

    try {

        $churchId = getChurchId();

        $studentId = intval($_POST['studentId'] ?? 0);



        if ($studentId === 0) {

            sendJSON(['success' => false, 'message' => 'معرف الطفل مطلوب']);

            return;

        }



        $conn = getDBConnection();



        // First, get student info for logging

        $getStmt = $conn->prepare("

            SELECT s.name, s.image_url, c.arabic_name as class 

            FROM students s

            LEFT JOIN classes c ON s.class_id = c.id

            WHERE s.id = ? AND s.church_id = ?

        ");

        $getStmt->bind_param("ii", $studentId, $churchId);

        $getStmt->execute();

        $result = $getStmt->get_result();



        if ($result->num_rows === 0) {

            sendJSON(['success' => false, 'message' => 'لم يتم العثور على الطفل']);

            return;

        }



        $student = $result->fetch_assoc();

        $studentName = $student['name'];

        $className = $student['class'];

        $studentImageUrl = $student['image_url'] ?? null;



        // Start transaction

        $conn->begin_transaction();



        try {

            // Get snapshot BEFORE delete

            $studentSnapshot = getStudentSnapshot($studentId);



            $deleteAttendanceStmt = $conn->prepare("

                DELETE FROM attendance 

                WHERE student_id = ?

            ");

            $deleteAttendanceStmt->bind_param("i", $studentId);

            $deleteAttendanceStmt->execute();



            // 2. Delete coupon logs if table exists

            $tableCheck = $conn->query("SHOW TABLES LIKE 'coupon_logs'");

            if ($tableCheck && $tableCheck->num_rows > 0) {

                $deleteLogsStmt = $conn->prepare("

                    DELETE FROM coupon_logs 

                    WHERE student_id = ?

                ");

                $deleteLogsStmt->bind_param("i", $studentId);

                $deleteLogsStmt->execute();

            }



            // 3. Delete the student

            $deleteStmt = $conn->prepare("

                DELETE FROM students 

                WHERE id = ? AND church_id = ?

            ");

            $deleteStmt->bind_param("ii", $studentId, $churchId);



            if ($deleteStmt->execute()) {

                if ($deleteStmt->affected_rows > 0) {

                    $conn->commit();



                    // Clean up student image file from disk

                    deleteUploadedFile($studentImageUrl);



                    // Log the deletion

                    error_log("Student deleted - ID: $studentId, Name: $studentName, Class: $className, Church: $churchId");



                    // ► AUDIT

                    auditStudentDelete($studentId, $studentSnapshot ?? ['id' => $studentId, 'name' => $studentName]);



                    sendJSON([

                        'success' => true,

                        'message' => 'تم حذف الطفل "' . $studentName . '" من فصل "' . $className . '" بنجاح',

                        'studentId' => $studentId

                    ]);

                } else {

                    $conn->rollback();

                    sendJSON(['success' => false, 'message' => 'لم يتم العثور على الطفل أو لا يوجد صلاحية للحذف']);

                }

            } else {

                $conn->rollback();

                error_log("Delete failed: " . $conn->error);

                sendJSON(['success' => false, 'message' => 'فشل في حذف الطفل: ' . $conn->error]);

            }



        } catch (Exception $e) {

            $conn->rollback();

            throw $e;

        }



    } catch (Exception $e) {

        error_log("deleteStudent error: " . $e->getMessage());

        sendJSON(['success' => false, 'message' => 'خطأ في حذف الطفل: ' . $e->getMessage()]);

    }

}

function getMergeComparison()
{
    try {
        $churchId = getChurchId();
        $studentIdA = intval($_POST['studentIdA'] ?? $_GET['studentIdA'] ?? 0);
        $studentIdB = intval($_POST['studentIdB'] ?? $_GET['studentIdB'] ?? 0);

        if ($studentIdA === 0 || $studentIdB === 0) {
            sendJSON(['success' => false, 'message' => 'معرفات الأطفال غير صالحة']);
            return;
        }

        $conn = getDBConnection();

        // Fetch student A
        $stmtA = $conn->prepare("
            SELECT s.*, c.church_name, COALESCE(cc.arabic_name, cl.arabic_name, s.class) AS class_name 
            FROM students s 
            LEFT JOIN churches c ON s.church_id = c.id 
            LEFT JOIN church_classes cc ON cc.id = s.class_id AND cc.church_id = s.church_id 
            LEFT JOIN classes cl ON cl.id = s.class_id 
            WHERE s.id = ? AND s.church_id = ?
        ");
        $stmtA->bind_param("ii", $studentIdA, $churchId);
        $stmtA->execute();
        $resA = $stmtA->get_result()->fetch_assoc();

        // Fetch student B
        $stmtB = $conn->prepare("
            SELECT s.*, c.church_name, COALESCE(cc.arabic_name, cl.arabic_name, s.class) AS class_name 
            FROM students s 
            LEFT JOIN churches c ON s.church_id = c.id 
            LEFT JOIN church_classes cc ON cc.id = s.class_id AND cc.church_id = s.church_id 
            LEFT JOIN classes cl ON cl.id = s.class_id 
            WHERE s.id = ? AND s.church_id = ?
        ");
        $stmtB->bind_param("ii", $studentIdB, $churchId);
        $stmtB->execute();
        $resB = $stmtB->get_result()->fetch_assoc();

        if (!$resA || !$resB) {
            sendJSON(['success' => false, 'message' => 'لم يتم العثور على أحد الأطفال أو الحسابات تنتمي لكنيسة أخرى']);
            return;
        }

        $hasPasswordA = !empty($resA['password_hash']);
        $hasPasswordB = !empty($resB['password_hash']);

        // Remove sensitive hashes
        unset($resA['password_hash']);
        unset($resB['password_hash']);

        // Fetch task submission count
        $taskStmtA = $conn->prepare("SELECT COUNT(*) as cnt FROM task_submissions WHERE student_id = ?");
        $taskStmtA->bind_param("i", $studentIdA);
        $taskStmtA->execute();
        $taskCountA = $taskStmtA->get_result()->fetch_assoc()['cnt'] ?? 0;

        $taskStmtB = $conn->prepare("SELECT COUNT(*) as cnt FROM task_submissions WHERE student_id = ?");
        $taskStmtB->bind_param("i", $studentIdB);
        $taskStmtB->execute();
        $taskCountB = $taskStmtB->get_result()->fetch_assoc()['cnt'] ?? 0;

        // Fetch attendance history
        $attStmtA = $conn->prepare("
            SELECT a.attendance_date, a.status, a.class_id, a.uncle_id, 
                   COALESCE(cc.arabic_name, cl.arabic_name, a.status) as class_name,
                   u.name as uncle_name
            FROM attendance a
            LEFT JOIN church_classes cc ON cc.id = a.class_id AND cc.church_id = a.church_id
            LEFT JOIN classes cl ON cl.id = a.class_id
            LEFT JOIN uncles u ON u.id = a.uncle_id
            WHERE a.student_id = ?
        ");
        $attStmtA->bind_param("i", $studentIdA);
        $attStmtA->execute();
        $attResultA = $attStmtA->get_result();
        $attA = [];
        while ($row = $attResultA->fetch_assoc()) {
            $attA[$row['attendance_date']] = $row;
        }

        $attStmtB = $conn->prepare("
            SELECT a.attendance_date, a.status, a.class_id, a.uncle_id, 
                   COALESCE(cc.arabic_name, cl.arabic_name, a.status) as class_name,
                   u.name as uncle_name
            FROM attendance a
            LEFT JOIN church_classes cc ON cc.id = a.class_id AND cc.church_id = a.church_id
            LEFT JOIN classes cl ON cl.id = a.class_id
            LEFT JOIN uncles u ON u.id = a.uncle_id
            WHERE a.student_id = ?
        ");
        $attStmtB->bind_param("i", $studentIdB);
        $attStmtB->execute();
        $attResultB = $attStmtB->get_result();
        $attB = [];
        while ($row = $attResultB->fetch_assoc()) {
            $attB[$row['attendance_date']] = $row;
        }

        $conflicts = [];
        $union = [];
        $allDates = array_unique(array_merge(array_keys($attA), array_keys($attB)));
        sort($allDates);

        foreach ($allDates as $d) {
            $hasA = isset($attA[$d]);
            $hasB = isset($attB[$d]);
            if ($hasA && $hasB) {
                $recA = $attA[$d];
                $recB = $attB[$d];
                if ($recA['status'] !== $recB['status'] || $recA['class_id'] !== $recB['class_id'] || $recA['uncle_id'] !== $recB['uncle_id']) {
                    $conflicts[] = [
                        'date' => $d,
                        'recordA' => $recA,
                        'recordB' => $recB
                    ];
                } else {
                    $union[] = [
                        'date' => $d,
                        'source' => 'both',
                        'record' => $recA
                    ];
                }
            } elseif ($hasA) {
                $union[] = [
                    'date' => $d,
                    'source' => 'A',
                    'record' => $attA[$d]
                ];
            } else {
                $union[] = [
                    'date' => $d,
                    'source' => 'B',
                    'record' => $attB[$d]
                ];
            }
        }

        sendJSON([
            'success' => true,
            'studentA' => $resA,
            'studentB' => $resB,
            'hasPasswordA' => $hasPasswordA,
            'hasPasswordB' => $hasPasswordB,
            'taskCountA' => $taskCountA,
            'taskCountB' => $taskCountB,
            'attendanceCountA' => count($attA),
            'attendanceCountB' => count($attB),
            'attendanceConflicts' => $conflicts,
            'attendanceUnion' => $union
        ]);

    } catch (Exception $e) {
        error_log("getMergeComparison error: " . $e->getMessage());
        sendJSON(['success' => false, 'message' => 'خطأ في جلب بيانات المقارنة: ' . $e->getMessage()]);
    }
}

function getMergeStudentSnapshot($studentId, $conn) {
    if (function_exists('getStudentSnapshot')) {
        $snapshot = getStudentSnapshot($studentId);
    } else {
        $stmt = $conn->prepare("SELECT * FROM students WHERE id = ?");
        $stmt->bind_param("i", $studentId);
        $stmt->execute();
        $snapshot = $stmt->get_result()->fetch_assoc();
        if (!$snapshot) return null;
        $snapshot['_attendance_history'] = [];
        $snapshot['_sibling_groups'] = [];
    }
    
    if (!$snapshot) return null;
    
    // Task Submissions
    $taskStmt = $conn->prepare("SELECT * FROM task_submissions WHERE student_id = ?");
    $taskStmt->bind_param("i", $studentId);
    $taskStmt->execute();
    $res = $taskStmt->get_result();
    $tasks = [];
    while ($row = $res->fetch_assoc()) {
        $tasks[] = $row;
    }
    $snapshot['_task_submissions'] = $tasks;
    
    // Exam Starts
    $examStmt = $conn->prepare("SELECT * FROM exam_starts WHERE student_id = ?");
    $examStmt->bind_param("i", $studentId);
    $examStmt->execute();
    $res = $examStmt->get_result();
    $exams = [];
    while ($row = $res->fetch_assoc()) {
        $exams[] = $row;
    }
    $snapshot['_exam_starts'] = $exams;
    
    // Trip Registrations & Payments
    $tripStmt = $conn->prepare("SELECT * FROM trip_registrations WHERE student_id = ?");
    $tripStmt->bind_param("i", $studentId);
    $tripStmt->execute();
    $res = $tripStmt->get_result();
    $trips = [];
    while ($row = $res->fetch_assoc()) {
        $regId = $row['id'];
        $payStmt = $conn->prepare("SELECT * FROM trip_payments WHERE registration_id = ?");
        $payStmt->bind_param("i", $regId);
        $payStmt->execute();
        $payRes = $payStmt->get_result();
        $payments = [];
        while ($pRow = $payRes->fetch_assoc()) {
            $payments[] = $pRow;
        }
        $row['_payments'] = $payments;
        $trips[] = $row;
    }
    $snapshot['_trip_registrations'] = $trips;
    
    // Trip Waitlist
    $waitStmt = $conn->prepare("SELECT * FROM trip_waitlist WHERE student_id = ?");
    $waitStmt->bind_param("i", $studentId);
    $waitStmt->execute();
    $res = $waitStmt->get_result();
    $waitlist = [];
    while ($row = $res->fetch_assoc()) {
        $waitlist[] = $row;
    }
    $snapshot['_trip_waitlist'] = $waitlist;

    // Coupon Withdrawals
    $wStmt = $conn->prepare("SELECT * FROM coupon_withdrawals WHERE student_id = ?");
    $wStmt->bind_param("i", $studentId);
    $wStmt->execute();
    $res = $wStmt->get_result();
    $withdrawals = [];
    while ($row = $res->fetch_assoc()) {
        $withdrawals[] = $row;
    }
    $snapshot['_coupon_withdrawals'] = $withdrawals;

    // Coupon Logs
    $logStmt = $conn->prepare("SELECT * FROM coupon_logs WHERE student_id = ?");
    $logStmt->bind_param("i", $studentId);
    $logStmt->execute();
    $res = $logStmt->get_result();
    $logs = [];
    while ($row = $res->fetch_assoc()) {
        $logs[] = $row;
    }
    $snapshot['_coupon_logs'] = $logs;

    return $snapshot;
}

function mergeDuplicateStudents()
{
    try {
        $churchId = getChurchId();
        
        $targetId = intval($_POST['target_id'] ?? 0);
        $duplicateId = intval($_POST['duplicate_id'] ?? 0);
        
        if ($targetId === 0 || $duplicateId === 0 || $targetId === $duplicateId) {
            sendJSON(['success' => false, 'message' => 'معرفات الأطفال غير صالحة']);
            return;
        }

        $conn = getDBConnection();

        // Verify church_id
        $checkStmt = $conn->prepare("SELECT id, name, image_url, custom_info, coupons, attendance_coupons, commitment_coupons, task_coupons, password_hash FROM students WHERE id = ? AND church_id = ?");
        
        $checkStmt->bind_param("ii", $targetId, $churchId);
        $checkStmt->execute();
        $targetStudent = $checkStmt->get_result()->fetch_assoc();

        $checkStmt->bind_param("ii", $duplicateId, $churchId);
        $checkStmt->execute();
        $duplicateStudent = $checkStmt->get_result()->fetch_assoc();

        if (!$targetStudent || !$duplicateStudent) {
            sendJSON(['success' => false, 'message' => 'أحد الحسابات غير موجود أو لا ينتمي لهذه الكنيسة']);
            return;
        }

        $profileFields = json_decode($_POST['profile_fields'] ?? '{}', true);
        $credentialsFrom = $_POST['credentials_from'] ?? 'A'; // 'A' or 'B'
        $attendanceMode = $_POST['attendance_mode'] ?? 'combine'; // 'combine', 'keep_A', 'keep_B'
        $attendanceConflicts = json_decode($_POST['attendance_conflicts'] ?? '{}', true);
        $couponsMode = $_POST['coupons_mode'] ?? 'sum'; // 'sum', 'keep_A', 'keep_B'
        $isTargetA = ($_POST['is_target_a'] ?? 'true') === 'true';

        // Fetch pre-merge snapshots for audit/undo
        $targetSnapshot = getMergeStudentSnapshot($targetId, $conn);
        $duplicateSnapshot = getMergeStudentSnapshot($duplicateId, $conn);

        // Start Transaction
        $conn->begin_transaction();

        try {
            // Update profile fields
            $stmtFull = $conn->prepare("SELECT * FROM students WHERE id = ?");
            $stmtFull->bind_param("i", $targetId);
            $stmtFull->execute();
            $tFull = $stmtFull->get_result()->fetch_assoc();

            $stmtFull->bind_param("i", $duplicateId);
            $stmtFull->execute();
            $dFull = $stmtFull->get_result()->fetch_assoc();

            // Resolve actual student A vs B records based on isTargetA
            $aFull = $isTargetA ? $tFull : $dFull;
            $bFull = $isTargetA ? $dFull : $tFull;

            $updateData = [];
            $updateFields = ['name', 'phone', 'emergency_phone', 'email', 'birthday', 'gender', 'class_id', 'address', 'medical_notes', 'image_url'];
            
            // Collect updated field values
            foreach ($updateFields as $field) {
                $source = $profileFields[$field] ?? 'A';
                if ($source === 'B') {
                    $updateData[$field] = $bFull[$field];
                } else {
                    $updateData[$field] = $aFull[$field];
                }
            }

            // Custom fields & Sibling group inside custom_info JSON
            $tCustom = json_decode($tFull['custom_info'] ?? 'null', true) ?: [];
            $dCustom = json_decode($dFull['custom_info'] ?? 'null', true) ?: [];
            
            $aCustom = $isTargetA ? $tCustom : $dCustom;
            $bCustom = $isTargetA ? $dCustom : $tCustom;
            
            $mergedCustom = $tCustom; // Start with target student's custom info
            if (isset($profileFields['custom_fields']) && is_array($profileFields['custom_fields'])) {
                foreach ($profileFields['custom_fields'] as $cfKey => $source) {
                    if ($source === 'B') {
                        if (isset($bCustom[$cfKey])) {
                            $mergedCustom[$cfKey] = $bCustom[$cfKey];
                        } else {
                            unset($mergedCustom[$cfKey]);
                        }
                    } else {
                        if (isset($aCustom[$cfKey])) {
                            $mergedCustom[$cfKey] = $aCustom[$cfKey];
                        } else {
                            unset($mergedCustom[$cfKey]);
                        }
                    }
                }
            } else {
                // Auto-choose values missing in target
                foreach ($dCustom as $k => $v) {
                    if ($k !== 'username' && $k !== 'sibling_group' && $k !== '_notes' && (!isset($mergedCustom[$k]) || empty($mergedCustom[$k]))) {
                        $mergedCustom[$k] = $v;
                    }
                }
            }

            // Sibling Group link
            if (!isset($mergedCustom['sibling_group']) && isset($dCustom['sibling_group'])) {
                $mergedCustom['sibling_group'] = $dCustom['sibling_group'];
            }

            // Merge internal '_notes' if present in both
            $notesA = $aCustom['_notes'] ?? [];
            $notesB = $bCustom['_notes'] ?? [];
            if (!is_array($notesA)) $notesA = [];
            if (!is_array($notesB)) $notesB = [];
            
            // Combine notes
            $combinedNotes = array_merge($notesA, $notesB);
            
            // Deduplicate notes by their id if they have ids
            $uniqueNotes = [];
            $seenNoteIds = [];
            foreach ($combinedNotes as $note) {
                $nId = $note['id'] ?? null;
                if ($nId) {
                    if (!in_array($nId, $seenNoteIds)) {
                        $seenNoteIds[] = $nId;
                        $uniqueNotes[] = $note;
                    }
                } else {
                    $uniqueNotes[] = $note;
                }
            }
            if (!empty($uniqueNotes)) {
                $mergedCustom['_notes'] = $uniqueNotes;
            } else {
                unset($mergedCustom['_notes']);
            }

            // Credentials (username + password_hash)
            $selectedPasswordHash = $tFull['password_hash'];
            $selectedUsername = $tCustom['username'] ?? null;

            if ($credentialsFrom === 'B') {
                $selectedPasswordHash = $bFull['password_hash'];
                $selectedUsername = $bCustom['username'] ?? null;
            } elseif ($credentialsFrom === 'A') {
                $selectedPasswordHash = $aFull['password_hash'];
                $selectedUsername = $aCustom['username'] ?? null;
            } else {
                if (empty($selectedPasswordHash) && !empty($dFull['password_hash'])) {
                    $selectedPasswordHash = $dFull['password_hash'];
                    $selectedUsername = $dCustom['username'] ?? null;
                }
            }

            if (!empty($selectedUsername)) {
                $mergedCustom['username'] = $selectedUsername;
            } else {
                unset($mergedCustom['username']);
            }

            // Coupons calculation
            $coupons = intval($tFull['coupons']);
            $attCoupons = intval($tFull['attendance_coupons']);
            $comCoupons = intval($tFull['commitment_coupons']);
            $tskCoupons = intval($tFull['task_coupons']);

            // Decide which coupons to keep based on couponsMode ('sum', 'keep_A', 'keep_B')
            $keepDuplicateCoupons = false;
            if ($isTargetA) {
                if ($couponsMode === 'keep_B') {
                    $keepDuplicateCoupons = true;
                }
            } else {
                if ($couponsMode === 'keep_A') {
                    $keepDuplicateCoupons = true;
                }
            }

            if ($couponsMode === 'sum') {
                $coupons += intval($dFull['coupons']);
                $attCoupons += intval($dFull['attendance_coupons']);
                $comCoupons += intval($dFull['commitment_coupons']);
                $tskCoupons += intval($dFull['task_coupons']);
            } elseif ($keepDuplicateCoupons) {
                $coupons = intval($dFull['coupons']);
                $attCoupons = intval($dFull['attendance_coupons']);
                $comCoupons = intval($dFull['commitment_coupons']);
                $tskCoupons = intval($dFull['task_coupons']);
            }

            // Let's resolve the class name for the chosen class_id!
            $chosenClassId = intval($updateData['class_id']);
            $classStmt = $conn->prepare("
                SELECT arabic_name FROM church_classes 
                WHERE id = ? AND church_id = ? AND is_active = 1
                UNION
                SELECT arabic_name FROM classes 
                WHERE id = ?
                LIMIT 1
            ");
            $classStmt->bind_param("iii", $chosenClassId, $churchId, $chosenClassId);
            $classStmt->execute();
            $classResult = $classStmt->get_result();
            $classData = $classResult->fetch_assoc();
            $chosenClassName = $classData['arabic_name'] ?? '';

            // Update Target Student
            $customInfoJSON = json_encode($mergedCustom, JSON_UNESCAPED_UNICODE);
            $updateStmt = $conn->prepare("
                UPDATE students 
                SET name = ?, phone = ?, emergency_phone = ?, email = ?, birthday = ?, 
                    gender = ?, class_id = ?, class = ?, address = ?, medical_notes = ?, image_url = ?, 
                    password_hash = ?, custom_info = ?, coupons = ?, attendance_coupons = ?, 
                    commitment_coupons = ?, task_coupons = ?, updated_at = NOW() 
                WHERE id = ?
            ");
            
            $updateStmt->bind_param("ssssssissssssiiiii", 
                $updateData['name'], $updateData['phone'], $updateData['emergency_phone'], 
                $updateData['email'], $updateData['birthday'], $updateData['gender'], 
                $updateData['class_id'], $chosenClassName, $updateData['address'], $updateData['medical_notes'], 
                $updateData['image_url'], $selectedPasswordHash, $customInfoJSON, 
                $coupons, $attCoupons, $comCoupons, $tskCoupons, $targetId
            );
            $updateStmt->execute();

            // Sibling group database links
            $sibStmt = $conn->prepare("SELECT group_id FROM student_sibling_group_members WHERE student_id = ?");
            $sibStmt->bind_param("i", $targetId);
            $sibStmt->execute();
            $tGroup = $sibStmt->get_result()->fetch_assoc();

            $sibStmt->bind_param("i", $duplicateId);
            $sibStmt->execute();
            $dGroup = $sibStmt->get_result()->fetch_assoc();

            if ($dGroup) {
                if (!$tGroup) {
                    $mvSib = $conn->prepare("UPDATE student_sibling_group_members SET student_id = ? WHERE student_id = ?");
                    $mvSib->bind_param("ii", $targetId, $duplicateId);
                    $mvSib->execute();
                } else {
                    $delSib = $conn->prepare("DELETE FROM student_sibling_group_members WHERE student_id = ?");
                    $delSib->bind_param("i", $duplicateId);
                    $delSib->execute();
                }
            }

            // Merge Attendance
            $keepTargetAttendance = true;
            $keepDuplicateAttendance = false;
            
            if ($attendanceMode === 'keep_A') {
                if ($isTargetA) {
                    $keepTargetAttendance = true;
                    $keepDuplicateAttendance = false;
                } else {
                    $keepTargetAttendance = false;
                    $keepDuplicateAttendance = true;
                }
            } elseif ($attendanceMode === 'keep_B') {
                if ($isTargetA) {
                    $keepTargetAttendance = false;
                    $keepDuplicateAttendance = true;
                } else {
                    $keepTargetAttendance = true;
                    $keepDuplicateAttendance = false;
                }
            } else {
                $keepTargetAttendance = false;
                $keepDuplicateAttendance = false;
            }

            if ($keepTargetAttendance) {
                $delAtt = $conn->prepare("DELETE FROM attendance WHERE student_id = ?");
                $delAtt->bind_param("i", $duplicateId);
                $delAtt->execute();
            } elseif ($keepDuplicateAttendance) {
                $delAtt = $conn->prepare("DELETE FROM attendance WHERE student_id = ?");
                $delAtt->bind_param("i", $targetId);
                $delAtt->execute();

                $mvAtt = $conn->prepare("UPDATE attendance SET student_id = ? WHERE student_id = ?");
                $mvAtt->bind_param("ii", $targetId, $duplicateId);
                $mvAtt->execute();
            } else {
                $getAttDates = $conn->prepare("SELECT id, attendance_date, status, class_id, uncle_id FROM attendance WHERE student_id = ?");
                
                $getAttDates->bind_param("i", $targetId);
                $getAttDates->execute();
                $attResA = $getAttDates->get_result();
                $datesA = [];
                while ($r = $attResA->fetch_assoc()) {
                    $datesA[$r['attendance_date']] = $r;
                }

                $getAttDates->bind_param("i", $duplicateId);
                $getAttDates->execute();
                $attResB = $getAttDates->get_result();
                $datesB = [];
                while ($r = $attResB->fetch_assoc()) {
                    $datesB[$r['attendance_date']] = $r;
                }

                foreach ($datesB as $date => $recB) {
                    if (isset($datesA[$date])) {
                        $recA = $datesA[$date];
                        $isConflict = $recA['status'] !== $recB['status'] || $recA['class_id'] !== $recB['class_id'] || $recA['uncle_id'] !== $recB['uncle_id'];
                        
                        if ($isConflict) {
                            $selectedSource = $attendanceConflicts[$date] ?? 'A';
                            
                            $keepDuplicateRecord = false;
                            if ($isTargetA) {
                                if ($selectedSource === 'B') {
                                    $keepDuplicateRecord = true;
                                }
                            } else {
                                if ($selectedSource === 'A') {
                                    $keepDuplicateRecord = true;
                                }
                            }

                            if ($keepDuplicateRecord) {
                                $delRec = $conn->prepare("DELETE FROM attendance WHERE id = ?");
                                $delRec->bind_param("i", $recA['id']);
                                $delRec->execute();

                                $mvRec = $conn->prepare("UPDATE attendance SET student_id = ? WHERE id = ?");
                                $mvRec->bind_param("ii", $targetId, $recB['id']);
                                $mvRec->execute();
                            } else {
                                $delRec = $conn->prepare("DELETE FROM attendance WHERE id = ?");
                                $delRec->bind_param("i", $recB['id']);
                                $delRec->execute();
                            }
                        } else {
                            $delRec = $conn->prepare("DELETE FROM attendance WHERE id = ?");
                            $delRec->bind_param("i", $recB['id']);
                            $delRec->execute();
                        }
                    } else {
                        $mvRec = $conn->prepare("UPDATE attendance SET student_id = ? WHERE id = ?");
                        $mvRec->bind_param("ii", $targetId, $recB['id']);
                        $mvRec->execute();
                    }
                }
            }

            // Merge Tasks submissions
            $taskStmt = $conn->prepare("SELECT id, task_id, score FROM task_submissions WHERE student_id = ?");
            
            $taskStmt->bind_param("i", $targetId);
            $taskStmt->execute();
            $tasksA = [];
            $resTasksA = $taskStmt->get_result();
            while ($row = $resTasksA->fetch_assoc()) {
                $tasksA[$row['task_id']] = $row;
            }

            $taskStmt->bind_param("i", $duplicateId);
            $taskStmt->execute();
            $resTasksB = $taskStmt->get_result();
            
            while ($rowB = $resTasksB->fetch_assoc()) {
                $taskId = $rowB['task_id'];
                if (isset($tasksA[$taskId])) {
                    $rowA = $tasksA[$taskId];
                    if (intval($rowB['score']) > intval($rowA['score'])) {
                        $delTask = $conn->prepare("DELETE FROM task_submissions WHERE id = ?");
                        $delTask->bind_param("i", $rowA['id']);
                        $delTask->execute();

                        $mvTask = $conn->prepare("UPDATE task_submissions SET student_id = ? WHERE id = ?");
                        $mvTask->bind_param("ii", $targetId, $rowB['id']);
                        $mvTask->execute();
                    } else {
                        $delTask = $conn->prepare("DELETE FROM task_submissions WHERE id = ?");
                        $delTask->bind_param("i", $rowB['id']);
                        $delTask->execute();
                    }
                } else {
                    $mvTask = $conn->prepare("UPDATE task_submissions SET student_id = ? WHERE id = ?");
                    $mvTask->bind_param("ii", $targetId, $rowB['id']);
                    $mvTask->execute();
                }
            }

            // Merge exam_starts
            $examStmt = $conn->prepare("SELECT id, task_id FROM exam_starts WHERE student_id = ?");
            $examStmt->bind_param("i", $targetId);
            $examStmt->execute();
            $examsA = [];
            $resExamsA = $examStmt->get_result();
            while ($row = $resExamsA->fetch_assoc()) {
                $examsA[$row['task_id']] = $row['id'];
            }

            $examStmt->bind_param("i", $duplicateId);
            $examStmt->execute();
            $resExamsB = $examStmt->get_result();
            while ($rowB = $resExamsB->fetch_assoc()) {
                $taskId = $rowB['task_id'];
                if (isset($examsA[$taskId])) {
                    $delExam = $conn->prepare("DELETE FROM exam_starts WHERE id = ?");
                    $delExam->bind_param("i", $rowB['id']);
                    $delExam->execute();
                } else {
                    $mvExam = $conn->prepare("UPDATE exam_starts SET student_id = ? WHERE id = ?");
                    $mvExam->bind_param("ii", $targetId, $rowB['id']);
                    $mvExam->execute();
                }
            }

            // Merge coupon logs & withdrawals
            $mvLogs = $conn->prepare("UPDATE coupon_logs SET student_id = ? WHERE student_id = ?");
            $mvLogs->bind_param("ii", $targetId, $duplicateId);
            $mvLogs->execute();

            $mvWithdrawals = $conn->prepare("UPDATE coupon_withdrawals SET student_id = ? WHERE student_id = ?");
            $mvWithdrawals->bind_param("ii", $targetId, $duplicateId);
            $mvWithdrawals->execute();

            // Merge trip registrations & payments
            $tripStmt = $conn->prepare("SELECT id, trip_id FROM trip_registrations WHERE student_id = ?");
            
            $tripStmt->bind_param("i", $targetId);
            $tripStmt->execute();
            $tripsA = [];
            $resTripsA = $tripStmt->get_result();
            while ($row = $resTripsA->fetch_assoc()) {
                $tripsA[$row['trip_id']] = $row['id'];
            }

            $tripStmt->bind_param("i", $duplicateId);
            $tripStmt->execute();
            $resTripsB = $tripStmt->get_result();
            while ($rowB = $resTripsB->fetch_assoc()) {
                $tripId = $rowB['trip_id'];
                $regIdB = $rowB['id'];
                if (isset($tripsA[$tripId])) {
                    $regIdA = $tripsA[$tripId];
                    $mvPayments = $conn->prepare("UPDATE trip_payments SET registration_id = ? WHERE registration_id = ?");
                    $mvPayments->bind_param("ii", $regIdA, $regIdB);
                    $mvPayments->execute();

                    $delReg = $conn->prepare("DELETE FROM trip_registrations WHERE id = ?");
                    $delReg->bind_param("i", $regIdB);
                    $delReg->execute();
                } else {
                    $mvReg = $conn->prepare("UPDATE trip_registrations SET student_id = ? WHERE id = ?");
                    $mvReg->bind_param("ii", $targetId, $regIdB);
                    $mvReg->execute();
                }
            }

            // Move remaining trip_waitlist rows
            $mvWait = $conn->prepare("UPDATE trip_waitlist SET student_id = ? WHERE student_id = ?");
            $mvWait->bind_param("ii", $targetId, $duplicateId);
            @$mvWait->execute();

            // Sibling group cleanup
            $delSib = $conn->prepare("DELETE FROM student_sibling_group_members WHERE student_id = ?");
            $delSib->bind_param("i", $duplicateId);
            $delSib->execute();

            // Delete Duplicate Student Record
            $delStudent = $conn->prepare("DELETE FROM students WHERE id = ? AND church_id = ?");
            $delStudent->bind_param("ii", $duplicateId, $churchId);
            $delStudent->execute();

            // Commit Transaction
            $conn->commit();

            // Cleanup deleted student's image file if we kept the other
            if (!empty($duplicateStudent['image_url']) && $updateData['image_url'] !== $duplicateStudent['image_url']) {
                deleteUploadedFile($duplicateStudent['image_url']);
            }
            if (!empty($targetStudent['image_url']) && $updateData['image_url'] !== $targetStudent['image_url']) {
                deleteUploadedFile($targetStudent['image_url']);
            }

            // Audit Log for Undo Merge
            $oldData = [
                'target_id' => $targetId,
                'duplicate_id' => $duplicateId,
                'target_snapshot' => $targetSnapshot,
                'duplicate_snapshot' => $duplicateSnapshot
            ];
            
            writeAuditLog(
                'student_merge',
                'student',
                $targetId,
                $targetStudent['name'],
                $oldData,
                null,
                "دمج حساب الطفل " . $duplicateStudent['name'] . " مع الحساب الرئيسي " . $targetStudent['name']
            );

            sendJSON([
                'success' => true,
                'message' => 'تم دمج الحسابات بنجاح وحذف الحساب المكرر للطفل "' . $duplicateStudent['name'] . '"'
            ]);

        } catch (Exception $txEx) {
            $conn->rollback();
            throw $txEx;
        }

    } catch (Exception $e) {
        error_log("mergeDuplicateStudents error: " . $e->getMessage());
        sendJSON(['success' => false, 'message' => 'خطأ في عملية الدمج: ' . $e->getMessage()]);
    }
}

function auditStudentMerge($targetId, $duplicateId, $targetName, $duplicateName) {
    try {
        $conn = getDBConnection();
        $churchId = getChurchId();
        $uncleId = $_SESSION['uncle_id'] ?? null;
        $action = 'merge_students';
        $details = json_encode([
            'target_id' => $targetId,
            'target_name' => $targetName,
            'duplicate_id' => $duplicateId,
            'duplicate_name' => $duplicateName
        ], JSON_UNESCAPED_UNICODE);

        $stmt = $conn->prepare("INSERT INTO audit_logs (church_id, uncle_id, action, entity, entity_id, details, created_at) VALUES (?, ?, ?, 'student', ?, ?, NOW())");
        $stmt->bind_param("iisis", $churchId, $uncleId, $action, $targetId, $details);
        $stmt->execute();
    } catch (Exception $e) {
        error_log("auditStudentMerge failed: " . $e->getMessage());
    }
}



// ===== UPDATE STUDENT IMAGE =====

function updateStudentImage()

{

    checkUncleAuth();



    try {

        $studentId = intval($_POST['student_id'] ?? $_POST['studentId'] ?? 0);

        $imageUrl = sanitize($_POST['imageUrl'] ?? '');



        if ($studentId === 0 || !isset($_POST['imageUrl'])) {

            sendJSON(['success' => false, 'message' => 'بيانات غير كاملة']);

            return;

        }



        $conn = getDBConnection();

        $oldQuery = $conn->prepare("SELECT name, image_url FROM students WHERE id = ? LIMIT 1");
        $oldQuery->bind_param("i", $studentId);
        $oldQuery->execute();
        $oldRow = $oldQuery->get_result()->fetch_assoc();
        $oldImageUrl = $oldRow['image_url'] ?? '';
        $studentName = $oldRow['name'] ?? '';

        $stmt = $conn->prepare("UPDATE students SET image_url = ? WHERE id = ?");

        $stmt->bind_param("si", $imageUrl, $studentId);



        if ($stmt->execute()) {

            if (!empty($oldImageUrl)) {
                deleteUploadedFile($oldImageUrl);
            }

            writeAuditLog('student_edit', 'student', $studentId, $studentName, ['image_url' => $oldImageUrl], ['image_url' => $imageUrl], 'تعديل صورة الطفل');

            sendJSON(['success' => true, 'message' => 'تم تحديث صورة الطفل بنجاح', 'student_id' => $studentId, 'imageUrl' => $imageUrl]);

        } else {

            sendJSON(['success' => false, 'message' => 'فشل في تحديث صورة الطفل: ' . $conn->error]);

        }



    } catch (Exception $e) {

        error_log("updateStudentImage error: " . $e->getMessage());

        sendJSON(['success' => false, 'message' => 'خطأ في تحديث صورة الطفل']);

    }

}



// ===== GET ALL ANNOUNCEMENTS =====

function getAllAnnouncements()

{

    try {

        $churchId = getChurchId();

        $cairoTimeZone = '+02:00';



        $conn = getDBConnection();

        ensureAnnouncementsTable($conn);

        $stmt = $conn->prepare("
            SELECT id, type, text as 'النص', link as 'الرابط', class as 'الفصل', student_names as 'أسماء الأطفال', is_active as 'منشط',
            button_text as 'نص الزر', image_url as 'رابط الصورة', description as 'الوصف التفصيلي', target_type as 'الجمهور المستهدف',
            DATE_FORMAT(CONVERT_TZ(created_at, '+00:00', ?), '%d/%m/%Y %h:%i %p') as 'تاريخ الإضافة'
            FROM announcements 
            WHERE church_id = ?
            ORDER BY created_at DESC
        ");

        $stmt->bind_param("si", $cairoTimeZone, $churchId);

        $stmt->execute();

        $result = $stmt->get_result();



        $announcements = [];

        while ($row = $result->fetch_assoc()) {

            if (!empty($row['تاريخ الإضافة'])) {

                $row['تاريخ الإضافة'] = str_replace(['AM', 'PM'], ['صباحاً', 'مساءً'], $row['تاريخ الإضافة']);

            }

            $announcements[] = $row;

        }



        sendJSON(['success' => true, 'announcements' => $announcements]);



    } catch (Exception $e) {

        error_log("getAllAnnouncements error: " . $e->getMessage());

        sendJSON(['success' => false, 'message' => 'خطأ في جلب الإعلانات']);

    }

}



function addAnnouncement()
{
    try {
        $churchId = getChurchId();
        $type = sanitize($_POST['type'] ?? 'message');
        $text = sanitize($_POST['text'] ?? '');
        $link = sanitize($_POST['link'] ?? '');
        $students = sanitize($_POST['students'] ?? '');
        $buttonText = sanitize($_POST['button_text'] ?? '');
        $imageUrl = sanitize($_POST['image_url'] ?? '');
        $description = sanitize($_POST['description'] ?? '');
        $targetType = sanitize($_POST['target_type'] ?? 'kids');

        // Accept either `classes` (array/JSON/comma-list) or legacy `class` single value.
        $classesRaw = $_POST['classes'] ?? $_POST['class'] ?? 'الجميع';
        $classes = [];
        if (is_array($classesRaw)) {
            $classes = $classesRaw;
        } else {
            $str = trim((string) $classesRaw);
            // Try JSON first
            if ($str !== '' && ($str[0] === '[' || $str[0] === '{')) {
                $decoded = json_decode($str, true);
                if (is_array($decoded)) $classes = $decoded;
            }
            if (empty($classes)) {
                // Fallback: split comma or pipe separated lists
                $parts = preg_split('/[,|]+/', $str);
                $parts = array_map('trim', $parts ?: []);
                $classes = array_values(array_filter($parts, fn($v) => $v !== ''));
            }
        }
        if (empty($classes)) $classes = ['الجميع'];

        // Validate classes list
        $allowedClasses = ['الجميع', 'حضانة', 'أولى', 'تانية', 'تالتة', 'رابعة', 'خامسة', 'سادسة'];
        foreach ($classes as $c) {
            if (!in_array($c, $allowedClasses)) {
                sendJSON(['success' => false, 'message' => 'الفصل غير صالح: ' . $c]);
                return;
            }
        }
        // Normalize stored class value: single 'الجميع' or comma-separated list
        $class = in_array('الجميع', $classes, true) ? 'الجميع' : implode(',', array_unique($classes));

        $conn = getDBConnection();
        ensureAnnouncementsTable($conn);

        // Insert with current timestamp (UTC)
        $stmt = $conn->prepare("
            INSERT INTO announcements (church_id, type, text, link, class, student_names, button_text, image_url, description, target_type, created_at)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, NOW())
        ");
        $stmt->bind_param("isssssssss", $churchId, $type, $text, $link, $class, $students, $buttonText, $imageUrl, $description, $targetType);

        if ($stmt->execute()) {
            $insertedId = $conn->insert_id;

            // Fetch the created timestamp converted to Cairo time
            $cairoTimeZone = '+02:00';
            $timeStmt = $conn->prepare("
                SELECT DATE_FORMAT(CONVERT_TZ(created_at, '+00:00', ?), '%d/%m/%Y %h:%i %p') as added_time 
                FROM announcements 
                WHERE id = ?
            ");
            $timeStmt->bind_param("si", $cairoTimeZone, $insertedId);
            $timeStmt->execute();
            $timeResult = $timeStmt->get_result();
            $timeData = $timeResult->fetch_assoc();

            // Get current Cairo time as fallback
            $cairoTime = new DateTime('now', new DateTimeZone('Africa/Cairo'));
            $defaultTime = $cairoTime->format('d/m/Y h:i A');

            $addedTime = $timeData['added_time'] ?? $defaultTime;
            // Replace AM/PM with Arabic
            $addedTime = str_replace(['AM', 'PM'], ['صباحاً', 'مساءً'], $addedTime);

            // ► AUDIT
            auditAnnouncementAdd($insertedId, $text);

            $extra = [
                'notifType' => 'announcement',
                'url' => '/user/',
                'redirect_url' => $link,
                'button_text' => $buttonText,
                'image_url' => $imageUrl,
                'description' => $description,
                'target_type' => $targetType
            ];
            if ($class !== 'الجميع') {
                $classNamesList = array_map('trim', explode(',', $class));
                $extra['class_names'] = $classNamesList;
            }

            if ($targetType === 'kids' || $targetType === 'both') {
                _sendWebPushToKids($conn, $churchId, 'إعلان جديد 📢', $text, $extra);
            }
            if ($targetType === 'uncles' || $targetType === 'both') {
                _sendWebPushToChurch($conn, $churchId, 'إعلان جديد 📢', $text, $extra);
            }

            sendJSON([
                'success' => true,
                'message' => 'تم إضافة الإعلان بنجاح',
                'added_at' => $addedTime,
                'announcement_id' => $insertedId
            ]);
        } else {
            sendJSON(['success' => false, 'message' => 'فشل في إضافة الإعلان: ' . $stmt->error]);
        }

    } catch (Exception $e) {
        error_log("addAnnouncement error: " . $e->getMessage());
        sendJSON(['success' => false, 'message' => 'خطأ في إضافة الإعلان: ' . $e->getMessage()]);
    }
}

