    }

}



function deleteAnnouncement()

{

    try {

        $churchId = getChurchId();

        $rowIndex = intval($_POST['rowIndex'] ?? 0);



        $conn = getDBConnection();



        // BEFORE delete, get old announcement data

        $oldAnnouncement = getAnnouncementSnapshot($rowIndex);



