        $googleScriptUrl = 'https://script.google.com/macros/s/AKfycbxsDA0veJTA3C_2Bw47coffOagRigWwaZnyxWuGb_gSVUCWM958V1bUcaZDwfIHVZ7b1g/exec';



        if ($status === 'approved') {

            // إرسال رسالة القبول

            $emailData = [

