// ===== BULK SAVE IMPORTED UNCLES =====

function bulkSaveImportedUncles()

{

    try {

        checkAuth();

        $churchId = getChurchId();

        $conn = getDBConnection();

        $conn->begin_transaction();



        $unclesJson = $_POST['uncles'] ?? '';

        $uncles = json_decode($unclesJson, true);



        if (!is_array($uncles)) {

            sendJSON(['success' => false, 'message' => 'بيانات الخُدام غير صالحة']);

            return;

        }



        $addedCount = 0;

        $errors = [];



        foreach ($uncles as $u) {

            $name = sanitize($u['name'] ?? '');

            $username = sanitize($u['username'] ?? '');

            $password = $u['password'] ?? '';

            $gender = sanitize($u['gender'] ?? 'male');

            $phone = sanitize($u['phone'] ?? '');

            $role = sanitize($u['role'] ?? 'uncle');

            $classesRaw = $u['classes'] ?? '';



            if (empty($name) || empty($username) || empty($password)) {

                $errors[] = "الاسم واسم المستخدم وكلمة المرور مطلوبة للخادم: " . ($name ?: $username ?: 'مجهول');

                continue;

            }



            // Check if username already exists in database

            $userCheck = $conn->prepare("SELECT id FROM uncles WHERE username = ?");

            $userCheck->bind_param("s", $username);

            $userCheck->execute();

            if ($userCheck->get_result()->num_rows > 0) {

                $errors[] = "اسم المستخدم '$username' مستخدم بالفعل";

                continue;

            }



            $passwordHash = hash('sha256', $password);



            // Normalize role

            if ($role !== 'admin' && $role !== 'uncle' && $role !== 'developer') {

                $role = 'uncle';

            }



            // Normalize gender

            if ($gender !== 'male' && $gender !== 'female') {

                $gender = 'male';

            }



            // Insert uncle

            $stmt = $conn->prepare("

                INSERT INTO uncles (church_id, name, username, password_hash, role, gender, phone)

                VALUES (?, ?, ?, ?, ?, ?, ?)

            ");

            $stmt->bind_param("issssss", $churchId, $name, $username, $passwordHash, $role, $gender, $phone);



            if ($stmt->execute()) {

                $newUncleId = $conn->insert_id;

                $addedCount++;



                // Process classes

                $assignedClasses = [];

                if (is_array($classesRaw)) {

                    $assignedClasses = $classesRaw;

                } elseif (!empty($classesRaw)) {

                    // Split comma-separated classes

                    $assignedClasses = array_map('trim', explode(',', $classesRaw));

                }



                $assignedClasses = array_filter(array_map('sanitize', $assignedClasses));



                if (!empty($assignedClasses)) {

                    saveUncleClasses($newUncleId, $churchId, $assignedClasses);

                }



                // Audit log for each uncle added

                writeAuditLog('uncle_add', 'uncle', $newUncleId, $name, null, [

                    'name' => $name,

                    'username' => $username,

                    'role' => $role,

                    'church_id' => $churchId,

                    'classes' => $assignedClasses,

                    'gender' => $gender,

                    'phone' => $phone,

                    'imported' => true

                ], 'إضافة خادم جديد عبر الاستيراد الجماعي');

            } else {

                $errors[] = "فشل إضافة الخادم '$name': " . $conn->error;

            }

        }



        if (!empty($errors) && $addedCount === 0) {

            $conn->rollback();

            sendJSON(['success' => false, 'message' => 'فشل الاستيراد بالكامل', 'errors' => $errors]);

        } else {

            $conn->commit();

            $msg = "تم استيراد $addedCount من الخدام بنجاح.";

            if (!empty($errors)) {

                $msg .= " ولكن حدثت بعض الأخطاء: " . count($errors);

            }

            sendJSON(['success' => true, 'message' => $msg, 'errors' => $errors]);

        }



    } catch (Exception $e) {

        if (isset($conn)) {

            $conn->rollback();

        }

        error_log("bulkSaveImportedUncles error: " . $e->getMessage());

        sendJSON(['success' => false, 'message' => 'خطأ في السيرفر أثناء حفظ الخُدام: ' . $e->getMessage()]);

    }

}





// ===== GENERATE EXCEL TEMPLATE =====

function generateExcelTemplate()

{

    try {

        require_once 'vendor/autoload.php'; // If using PhpSpreadsheet



        $spreadsheet = new \PhpOffice\PhpSpreadsheet\Spreadsheet();



        // Define all classes

        $classes = ['حضانة', 'أولى', 'تانية', 'تالتة', 'رابعة', 'خامسة', 'سادسة'];



        foreach ($classes as $index => $class) {

            if ($index > 0) {

                $spreadsheet->createSheet();

            }



            $sheet = $spreadsheet->setActiveSheetIndex($index);

            $sheet->setTitle($class);



            // Set headers

            $sheet->setCellValue('A1', 'الاسم');

            $sheet->setCellValue('B1', 'العنوان');

            $sheet->setCellValue('C1', 'الهاتف');

            $sheet->setCellValue('D1', 'تاريخ الميلاد (DD/MM/YYYY)');



            // Style headers

            $sheet->getStyle('A1:D1')->getFont()->setBold(true);

            $sheet->getStyle('A1:D1')->getFill()

                ->setFillType(\PhpOffice\PhpSpreadsheet\Style\Fill::FILL_SOLID)

                ->getStartColor()->setARGB('FF4F46E5');

            $sheet->getStyle('A1:D1')->getFont()->getColor()->setARGB('FFFFFFFF');



            // Set column widths

            $sheet->getColumnDimension('A')->setWidth(30);

            $sheet->getColumnDimension('B')->setWidth(40);

            $sheet->getColumnDimension('C')->setWidth(20);

            $sheet->getColumnDimension('D')->setWidth(25);



            // Add instructions

            $sheet->setCellValue('F1', 'تعليمات:');

            $sheet->setCellValue('F2', '1. املأ البيانات في الأعمدة A-D فقط');

            $sheet->setCellValue('F3', '2. تاريخ الميلاد: استخدم صيغة DD/MM/YYYY');

            $sheet->setCellValue('F4', '3. رقم الهاتف: ابدأ بـ 01XXXXXXXXX');

            $sheet->setCellValue('F5', '4. لا تغير تنسيق الأعمدة');

        }



        // Set first sheet as active

        $spreadsheet->setActiveSheetIndex(0);



        // Create Excel file

        $writer = new \PhpOffice\PhpSpreadsheet\Writer\Xlsx($spreadsheet);



        header('Content-Type: application/vnd.openxmlformats-officedocument.spreadsheetml.sheet');

        header('Content-Disposition: attachment;filename="kids_template_' . date('Y-m-d') . '.xlsx"');

        header('Cache-Control: max-age=0');



        $writer->save('php://output');

        exit;



    } catch (Exception $e) {

        // Fallback to CSV if Excel not available

        generateKidsTemplate();

    }

}



// ===== EXPORT ALL EXISTING KIDS AS CSV (pre-filled for editing) =====

function exportKidsData()

{

    try {

        $churchId = getChurchId();

        if (!$churchId) {

            sendJSON(['success' => false, 'message' => 'معرف الكنيسة مطلوب']);

            return;

        }



        $conn = getDBConnection();



        // ── Load custom field definitions ─────────────────────────

        ensureChurchSettingsTable($conn);

        $cfStmt = $conn->prepare("SELECT custom_field FROM church_settings WHERE church_id = ? LIMIT 1");

        $cfStmt->bind_param("i", $churchId);

        $cfStmt->execute();

        $cfRow = $cfStmt->get_result()->fetch_assoc();

        $customFieldDefs = [];

        if ($cfRow && !empty($cfRow['custom_field'])) {

            $cfData = json_decode($cfRow['custom_field'], true);

            if (is_array($cfData)) {

                if (isset($cfData[0]) && is_array($cfData[0]))

                    $customFieldDefs = $cfData;

                elseif (!empty($cfData['name']))

                    $customFieldDefs = [$cfData];

            }

        }



        // ── Load all students for this church ─────────────────────

        $stmt = $conn->prepare("

            SELECT s.id, s.name, s.address, s.phone, s.emergency_phone, s.medical_notes, s.birthday, s.gender, s.custom_info,

                   COALESCE(cc.arabic_name, gc.arabic_name, s.class) AS class_name

            FROM students s

            LEFT JOIN church_classes cc ON cc.id = s.class_id AND cc.church_id = s.church_id AND cc.is_active = 1

            LEFT JOIN classes gc        ON gc.id = s.class_id

            WHERE s.church_id = ?

              AND COALESCE(s.enrollment_status, 'active') = 'active'

            ORDER BY class_name, s.name

        ");

        $stmt->bind_param("i", $churchId);

        $stmt->execute();

        $rows = $stmt->get_result()->fetch_all(MYSQLI_ASSOC);



        // ── Fetch Sibling Names ───────────────────────────────────

        $siblingsMap = [];

        $sibStmt = $conn->prepare("

            SELECT ssgm.student_id, s_sib.name AS sibling_name

            FROM student_sibling_group_members ssgm

            INNER JOIN student_sibling_group_members ssgm2 

                ON ssgm.group_id = ssgm2.group_id AND ssgm.student_id != ssgm2.student_id

            INNER JOIN students s_sib 

                ON ssgm2.student_id = s_sib.id

            WHERE ssgm.church_id = ?

        ");

        if ($sibStmt) {

            $sibStmt->bind_param("i", $churchId);

            $sibStmt->execute();

            $sibRes = $sibStmt->get_result();

            while ($sibRow = $sibRes->fetch_assoc()) {

                $sid = (int) $sibRow['student_id'];

                $siblingsMap[$sid][] = $sibRow['sibling_name'];

            }

        }



        // ── Build CSV ─────────────────────────────────────────────

        // Columns: student_id, class, name, address, phone, emergency_phone, medical_notes, birthday, gender, siblings [, custom_fields...]

        // Quote custom field names to handle commas/special characters safely

        $customHeadersQuoted = array_map(function ($f) {

            $n = $f['name'] ?? '';

            return '"' . str_replace('"', '""', $n) . '"';

        }, $customFieldDefs);

        $headerLine = 'student_id,class,name,address,phone,emergency_phone,medical_notes,birthday,gender,siblings';

        if ($customHeadersQuoted)

            $headerLine .= ',' . implode(',', $customHeadersQuoted);

        $headerLine .= "\n";



        $csvContent = $headerLine;

        foreach ($rows as $r) {

            $id = (int) $r['id'];

            $class = $r['class_name'] ?? '';

            $name = $r['name'] ?? '';

            $address = $r['address'] ?? '';

            $phone = $r['phone'] ?? '';

            $emergencyPhone = $r['emergency_phone'] ?? '';

            $medicalNotes = $r['medical_notes'] ?? '';

            $birthday = $r['birthday'] ? date('d/m/Y', strtotime($r['birthday'])) : '';

            $gender = $r['gender'] ?? '';

            $genderLabel = '';

            if ($gender === 'female') {

                $genderLabel = 'أنثى';

            } elseif ($gender === 'male') {

                $genderLabel = 'ذكر';

            }

            $studentSiblings = isset($siblingsMap[$id]) ? implode(', ', $siblingsMap[$id]) : '';



            // Escape cell: wrap in quotes, escape internal quotes

            $esc = function ($v) {

                return '"' . str_replace('"', '""', $v) . '"';

            };



            $line = $id . ',' . $esc($class) . ',' . $esc($name) . ',' .

                $esc($address) . ',' . $esc($phone) . ',' . $esc($emergencyPhone) . ',' .

                $esc($medicalNotes) . ',' . $esc($birthday) . ',' . $esc($genderLabel) . ',' . $esc($studentSiblings);



            // Custom fields

            if ($customFieldDefs) {

                $info = !empty($r['custom_info']) ? json_decode($r['custom_info'], true) : [];

                if (!is_array($info))

                    $info = [];

                foreach ($customFieldDefs as $cfIdx => $cfDef) {

                    $key = $cfDef['key'] ?? ('field_' . $cfIdx);

                    // Support both new key format and legacy {'value':...}

                    $val = $info[$key] ?? ($info['field_' . $cfIdx] ?? ($cfIdx === 0 ? ($info['value'] ?? '') : ''));

                    $line .= ',' . $esc((string) $val);

                }

            }



            $csvContent .= $line . "\n";

        }



        header('Content-Type: text/csv; charset=utf-8');

        header('Content-Disposition: attachment; filename="kids_data_' . date('Y-m-d') . '.csv"');

        header('Cache-Control: no-cache, no-store, must-revalidate');

        echo chr(0xEF) . chr(0xBB) . chr(0xBF); // UTF-8 BOM for Excel

        echo $csvContent;

        exit;



    } catch (Exception $e) {

        error_log("exportKidsData error: " . $e->getMessage());

        sendJSON(['success' => false, 'message' => 'خطأ في تصدير البيانات: ' . $e->getMessage()]);

    }

}



function bulkAddKids()

{

    try {

        $churchId = getChurchId();

        $csvData = $_FILES['csvFile']['tmp_name'] ?? '';



        if (empty($csvData) || !file_exists($csvData)) {

            sendJSON(['success' => false, 'message' => 'الرجاء تحميل ملف CSV']);

            return;

        }



        $conn = getDBConnection();

        $conn->begin_transaction();



        // ── Read custom field definitions for this church ─────────

        $customFieldDefs = [];

        ensureChurchSettingsTable($conn);

        $cfStmt2 = $conn->prepare("SELECT custom_field FROM church_settings WHERE church_id = ? LIMIT 1");

        $cfStmt2->bind_param("i", $churchId);

        $cfStmt2->execute();

        $cfRow2 = $cfStmt2->get_result()->fetch_assoc();

        if ($cfRow2 && !empty($cfRow2['custom_field'])) {

            $cfData2 = json_decode($cfRow2['custom_field'], true);

            if (is_array($cfData2)) {

                if (isset($cfData2[0]) && is_array($cfData2[0]))

                    $customFieldDefs = $cfData2;

                elseif (!empty($cfData2['name']))

                    $customFieldDefs = [$cfData2];

            }

        }



        // ── Build class lookup map ────────────────────────────────

        $churchClasses = getClassesForChurch($churchId);

        $classMap = [];

        foreach ($churchClasses as $cls) {

            $key1 = mb_strtolower(trim($cls['arabic_name']));

            $key2 = mb_strtolower(trim($cls['code'] ?? ''));

            $classMap[$key1] = ['id' => $cls['id'], 'arabic_name' => $cls['arabic_name']];

            if (!empty($key2))

                $classMap[$key2] = ['id' => $cls['id'], 'arabic_name' => $cls['arabic_name']];

        }



        $addedCount = 0;

        $updatedCount = 0;

        $errorCount = 0;

        $skippedEmpty = 0;

        $errors = [];



        // ── Read CSV ──────────────────────────────────────────────

        $file = fopen($csvData, 'r');

        $bom = fread($file, 3);

        if ($bom !== chr(0xEF) . chr(0xBB) . chr(0xBF))

            rewind($file);



        // Read and detect header

        $headerRow = fgetcsv($file);

        $headerRow = array_map(function ($h) {

            return mb_strtolower(trim(str_replace('"', '', $h)));

        }, $headerRow);



        // Detect mode: does the CSV have a student_id column?

        $colStudentId = array_search('student_id', $headerRow);

        $isUpdateMode = $colStudentId !== false;



        // Detect column positions (flexible — works for both template and export formats)

        $colClass = array_search('class', $headerRow) !== false ? array_search('class', $headerRow) : ($isUpdateMode ? 1 : 0);

        $colName = array_search('name', $headerRow) !== false ? array_search('name', $headerRow) : ($isUpdateMode ? 2 : 1);

        $colAddress = array_search('address', $headerRow) !== false ? array_search('address', $headerRow) : ($isUpdateMode ? 3 : 2);

        $colPhone = array_search('phone', $headerRow) !== false ? array_search('phone', $headerRow) : ($isUpdateMode ? 4 : 3);

        $colBirthday = array_search('birthday', $headerRow) !== false ? array_search('birthday', $headerRow) : ($isUpdateMode ? 5 : 4);



        // Custom field columns: match by field key (e.g. "field_0") or by display name as fallback

        // The CSV header uses the field's display name (quoted), so we search for it.

        // We also check the key directly in case the header was generated with keys.

        $customColMap = []; // cfIdx => headerColIdx

        foreach ($customFieldDefs as $cfIdx => $cfDef) {

            $cfKey = $cfDef['key'] ?? ('field_' . $cfIdx);

            $cfNameLower = mb_strtolower(trim($cfDef['name'] ?? ''));



            // Try matching by display name first (normal flow)

            $found = false;

            foreach ($headerRow as $hIdx => $hVal) {

                $hLower = mb_strtolower(trim($hVal));

                if ($hLower === $cfNameLower || $hLower === $cfKey) {

                    $customColMap[$cfIdx] = $hIdx;

                    $found = true;

                    break;

                }

            }

            if (!$found) {

                // Positional fallback: custom fields start at col 5 (add mode) or 6 (update mode)

                $basePos = $isUpdateMode ? 6 : 5;

                $customColMap[$cfIdx] = $basePos + $cfIdx;

            }

        }



        error_log("bulkAddKids: isUpdateMode=" . ($isUpdateMode ? 'true' : 'false') . " | headerRow=" . implode('|', $headerRow));

        error_log("bulkAddKids: customFieldDefs count=" . count($customFieldDefs) . " | customColMap=" . json_encode($customColMap));



        $lineNumber = 1;



        while (($row = fgetcsv($file)) !== false) {

            $lineNumber++;

            // Pad to max needed index

            $maxIdx = max(array_merge(

                [$colClass, $colName, $colAddress, $colPhone, $colBirthday],

                $isUpdateMode ? [$colStudentId] : [],

                array_values($customColMap)

            ));

            while (count($row) <= $maxIdx)

                $row[] = '';



            $studentId = $isUpdateMode ? intval($row[$colStudentId] ?? 0) : 0;

            $classRaw = trim($row[$colClass] ?? '');

            $name = trim($row[$colName] ?? '');

            $address = trim($row[$colAddress] ?? '');

            $phone = trim($row[$colPhone] ?? '');

            $birthday = trim($row[$colBirthday] ?? '');



            // Custom field values

            $customRaws = [];

            foreach ($customFieldDefs as $cfIdx => $cfDef) {

                $customRaws[$cfIdx] = trim($row[$customColMap[$cfIdx]] ?? '');

            }



            if (empty($name)) {

                $skippedEmpty++;

                continue;

            }



            // ── Resolve class ─────────────────────────────────────

            $classId = 0;

            $className = $classRaw;

            if (!empty($classRaw)) {

                $lookupKey = mb_strtolower(trim($classRaw));

                if (isset($classMap[$lookupKey])) {

                    $classId = $classMap[$lookupKey]['id'];

                    $className = $classMap[$lookupKey]['arabic_name'];

                } else {

                    $errors[] = "السطر $lineNumber ($name): الفصل '$classRaw' غير معروف — تم التجاهل";

                    $errorCount++;

                    continue;

                }

            } elseif ($studentId > 0) {

                // In update mode, class is optional — keep existing if blank

                $existingStmt = $conn->prepare("SELECT class_id, class FROM students WHERE id = ? AND church_id = ?");

                $existingStmt->bind_param("ii", $studentId, $churchId);

                $existingStmt->execute();

                $existing = $existingStmt->get_result()->fetch_assoc();

                if ($existing) {

                    $classId = (int) $existing['class_id'];

                    $className = $existing['class'];

                }

            }



            if (!$classId && !$studentId) {

                $errors[] = "السطر $lineNumber ($name): الفصل مطلوب — تم التجاهل";

                $errorCount++;

                continue;

            }



            // ── Birthday ──────────────────────────────────────────

            $formattedBirthday = null;

            if (!empty($birthday)) {

                $formattedBirthday = formatDateToDB($birthday);

                if (!$formattedBirthday) {

                    $errors[] = "السطر $lineNumber ($name): تاريخ الميلاد '$birthday' غير صالح — تم الإضافة بدون تاريخ";

                }

            }



            // ── Phone cleaning ────────────────────────────────────

            $cleanPhone = trim($phone);

            if (preg_match('/^[\d.]+[eE][+\-]?\d+$/', $cleanPhone))

                $cleanPhone = number_format((float) $cleanPhone, 0, '.', '');

            $cleanPhone = preg_replace('/[^\d]/', '', $cleanPhone);

            if (!empty($cleanPhone)) {

                $len = strlen($cleanPhone);

                if ($len === 10 && $cleanPhone[0] === '1')

                    $cleanPhone = '0' . $cleanPhone;

                elseif ($len === 11 && substr($cleanPhone, 0, 2) !== '01')

                    $cleanPhone = '0' . substr($cleanPhone, 0, 10);

                elseif ($len < 10)

                    $cleanPhone = '';

                elseif ($len > 11)

                    $cleanPhone = substr($cleanPhone, -11);

            }

            if (!empty($cleanPhone) && !preg_match('/^01[0-9]{9}$/', $cleanPhone))

                $cleanPhone = '';



            // ── Build custom_info JSON ────────────────────────────

            $customInfoJson = null;

            if (!empty($customFieldDefs)) {

                $infoObj = [];

                foreach ($customFieldDefs as $cfIdx => $cfDef) {

                    $val = $customRaws[$cfIdx] ?? '';

                    if ($val !== '') {

                        $key = $cfDef['key'] ?? ('field_' . $cfIdx);

                        $infoObj[$key] = $val;

                    }

                }

                if (!empty($infoObj))

                    $customInfoJson = json_encode($infoObj, JSON_UNESCAPED_UNICODE);

            }



            // ══════════════════════════════════════════════════════

            // UPDATE MODE — student_id present in CSV

            // ══════════════════════════════════════════════════════

            if ($isUpdateMode && $studentId > 0) {

                // Verify the student belongs to this church

                $verifyStmt = $conn->prepare("SELECT id FROM students WHERE id = ? AND church_id = ?");

                $verifyStmt->bind_param("ii", $studentId, $churchId);

                $verifyStmt->execute();

                if (!$verifyStmt->get_result()->fetch_assoc()) {

                    $errors[] = "السطر $lineNumber ($name): ID $studentId غير موجود أو لا يخص هذه الكنيسة — تم التجاهل";

                    $errorCount++;

                    continue;

                }



                // Build UPDATE — only update fields that are non-empty in CSV

                // (so leaving a cell blank doesn't erase existing data)

                $setParts = ["name = ?", "updated_at = NOW()"];

                $setTypes = "s";

                $setValues = [$name];



                if ($classId > 0) {

                    $setParts[] = "class_id = ?";

                    $setParts[] = "class = ?";

                    $setTypes .= "is";

                    $setValues[] = $classId;

                    $setValues[] = $className;

                }

                if ($address !== '') {

                    $setParts[] = "address = ?";

                    $setTypes .= "s";

                    $setValues[] = $address;

                }

                if ($cleanPhone !== '') {

                    $setParts[] = "phone = ?";

                    $setTypes .= "s";

                    $setValues[] = $cleanPhone;

                }

                if ($formattedBirthday !== null) {

                    $setParts[] = "birthday = ?";

                    $setTypes .= "s";

                    $setValues[] = $formattedBirthday;

                }

                if ($customInfoJson !== null) {

                    $setParts[] = "custom_info = ?";

                    $setTypes .= "s";

                    $setValues[] = $customInfoJson;

                }



                $setTypes .= "ii"; // WHERE id = ? AND church_id = ?

                $setValues[] = $studentId;

                $setValues[] = $churchId;



                $updateSql = "UPDATE students SET " . implode(', ', $setParts) . " WHERE id = ? AND church_id = ?";

                $updateStmt = $conn->prepare($updateSql);

                $updateStmt->bind_param($setTypes, ...$setValues);



                if ($updateStmt->execute()) {

                    $updatedCount++;

                } else {

                    $errors[] = "السطر $lineNumber ($name): فشل في التحديث — " . $updateStmt->error;

                    $errorCount++;

                }

                continue;

            }



            // ══════════════════════════════════════════════════════

            // ADD MODE — no student_id, check for duplicates first

            // ══════════════════════════════════════════════════════

            $checkStmt = $conn->prepare("

                SELECT id FROM students

                WHERE church_id = ?

                  AND LOWER(REPLACE(name,' ','')) = LOWER(REPLACE(?,' ',''))

                  AND class_id = ?

            ");

            $checkStmt->bind_param("isi", $churchId, $name, $classId);

            $checkStmt->execute();

            if ($checkStmt->get_result()->num_rows > 0) {

                $errors[] = "السطر $lineNumber: '$name' موجود بالفعل في فصل '$className' — تم التجاهل";

                $skippedEmpty++;

                continue;

            }



            $addedByType = 'bulk_add';
            if ($formattedBirthday !== null) {

                $stmt = $conn->prepare("

                    INSERT INTO students

                    (church_id, name, class_id, class, address, phone, birthday,

                     commitment_coupons, coupons, attendance_coupons, custom_info, added_by)

                    VALUES (?, ?, ?, ?, ?, ?, ?, 0, 0, 0, ?, ?)

                ");

                // i=church_id, s=name, i=class_id, s=class, s=address, s=phone, s=birthday, s=custom_info, s=added_by

                $stmt->bind_param("isissssss", $churchId, $name, $classId, $className, $address, $cleanPhone, $formattedBirthday, $customInfoJson, $addedByType);

            } else {

                $stmt = $conn->prepare("

                    INSERT INTO students

                    (church_id, name, class_id, class, address, phone,

                     commitment_coupons, coupons, attendance_coupons, custom_info, added_by)

                    VALUES (?, ?, ?, ?, ?, ?, 0, 0, 0, ?, ?)

                ");

                // i=church_id, s=name, i=class_id, s=class, s=address, s=phone, s=custom_info, s=added_by

                $stmt->bind_param("isisssss", $churchId, $name, $classId, $className, $address, $cleanPhone, $customInfoJson, $addedByType);

            }



            if ($stmt->execute()) {

                $addedCount++;

            } else {

                $errors[] = "السطر $lineNumber ($name): فشل في الإضافة — " . $stmt->error;

                $errorCount++;

            }

        }



        fclose($file);



        if ($addedCount === 0 && $updatedCount === 0 && $errorCount > 0) {

            $conn->rollback();

            sendJSON([

                'success' => false,

                'message' => 'لم يتم إضافة أو تحديث أي طفل. يرجى مراجعة الأخطاء.',

                'errors' => array_slice($errors, 0, 25),

                'added' => 0,

                'updated' => 0,

                'failed' => $errorCount,

                'skipped' => $skippedEmpty,

                'availableClasses' => array_column($churchClasses, 'arabic_name'),

            ]);

        } else {

            $conn->commit();

            $msg = '';

            if ($addedCount > 0)

                $msg .= "تم إضافة $addedCount طفل";

            if ($updatedCount > 0)

                $msg .= ($msg ? ' — ' : '') . "تم تحديث $updatedCount طفل";

            if ($errorCount > 0)

                $msg .= " (فشل/تجاهل $errorCount)";

            if ($skippedEmpty > 0)

                $msg .= " (صفوف فارغة: $skippedEmpty)";

            sendJSON([

                'success' => true,

                'message' => $msg,

                'addedCount' => $addedCount,

                'updatedCount' => $updatedCount,

                'failed' => $errorCount,

                'skipped' => $skippedEmpty,

                'errors' => array_slice($errors, 0, 25),

                'availableClasses' => array_column($churchClasses, 'arabic_name'),

            ]);

        }



    } catch (Exception $e) {

        if (isset($conn))

            $conn->rollback();

        error_log("bulkAddKids error: " . $e->getMessage());

        sendJSON(['success' => false, 'message' => 'خطأ في الاستيراد: ' . $e->getMessage()]);

    }

}

function bulkSaveImportedKids()
{
    try {
        checkAuth();
        $churchId = getChurchId();
        $uncleId = $_SESSION['uncle_id'] ?? null;
        $conn = getDBConnection();
        $conn->begin_transaction();

        $tripId = isset($_POST['trip_id']) ? intval($_POST['trip_id']) : 0;
        $kidsJson = $_POST['kids'] ?? '';
        $kids = json_decode($kidsJson, true);

        if (!is_array($kids)) {
            sendJSON(['success' => false, 'message' => 'بيانات الأطفال غير صالحة']);
            return;
        }

        $allowedChurches = [$churchId];
        $maxParticipants = 0;
        if ($tripId > 0) {
            $tripStmt = $conn->prepare("SELECT church_id, max_participants, title, collaborating_churches, collaboration_limits FROM trips WHERE id = ?");
            $tripStmt->bind_param("i", $tripId);
            $tripStmt->execute();
            $trip = $tripStmt->get_result()->fetch_assoc();
            if (!$trip) {
                sendJSON(['success' => false, 'message' => 'الرحلة غير موجودة']);
                return;
            }
            ensureWaitlistTable($conn);
            $maxParticipants = intval($trip['max_participants'] ?? 0);
            
            $participants = [intval($trip['church_id'])];
            $collabRaw = $trip['collaborating_churches'] ?? '';
            if (!empty($collabRaw)) {
                $collab = json_decode($collabRaw, true);
                if (is_array($collab)) {
                    $participants = array_unique(array_merge($participants, array_map('intval', $collab)));
                }
            }
            if (in_array($churchId, $participants)) {
                $ownerChurchId = intval($trip['church_id']);
                if ($churchId === $ownerChurchId) {
                    $allowedChurches = $participants;
                } else {
                    $allowedChurches = [$churchId];
                }
            }

            $ownerChurchId = intval($trip['church_id']);
            $churchLimit = null;
            if ($ownerChurchId !== $churchId) {
                $limits = [];
                if (!empty($trip['collaboration_limits'])) {
                    $limits = json_decode($trip['collaboration_limits'], true);
                }
                if (is_array($limits) && isset($limits[strval($churchId)])) {
                    $churchLimit = intval($limits[strval($churchId)]);
                }
            }
        }

        $classMap = [];
        foreach ($allowedChurches as $cId) {
            $churchClasses = getClassesForChurch($cId);
            foreach ($churchClasses as $cls) {
                $key = normalizeArabicClassName($cls['arabic_name']);
                $classMap[$key] = ['id' => $cls['id'], 'arabic_name' => $cls['arabic_name']];
            }
        }

        $addedCount = 0;
        $updatedCount = 0;
        $registeredCount = 0;
        $errors = [];

        foreach ($kids as $kid) {
            $studentId = isset($kid['student_id']) ? intval($kid['student_id']) : 0;
            $name = sanitize($kid['name'] ?? '');
            $classRaw = sanitize($kid['class'] ?? '');
            $phone = sanitize($kid['phone'] ?? '');
            $emergencyPhone = sanitize($kid['emergency_phone'] ?? '');
            $medicalNotes = sanitize($kid['medical_notes'] ?? '');
            $gender = sanitize($kid['gender'] ?? '');
            $address = sanitize($kid['address'] ?? '');
            $birthday = sanitize($kid['birthday'] ?? '');
            $siblings = sanitize($kid['siblings'] ?? '');
            $customInfoInput = $kid['custom_info'] ?? [];

            if (empty($name)) {
                continue;
            }

            $classId = 0;
            $className = $classRaw;
            if (!empty($classRaw)) {
                $lookupKey = normalizeArabicClassName($classRaw);
                if (isset($classMap[$lookupKey])) {
                    $classId = $classMap[$lookupKey]['id'];
                    $className = $classMap[$lookupKey]['arabic_name'];
                }
            }

            $formattedBirthday = null;
            if (!empty($birthday)) {
                $formattedBirthday = formatDateToDB($birthday);
            }

            $cleanPhone = preg_replace('/[^\d]/', '', $phone);
            if (!empty($cleanPhone)) {
                if (strpos($cleanPhone, '002') === 0) {
                    $cleanPhone = substr($cleanPhone, 2);
                }
                if (strpos($cleanPhone, '20') === 0) {
                    $cleanPhone = substr($cleanPhone, 2);
                }
                if (strlen($cleanPhone) === 10 && $cleanPhone[0] === '1') {
                    $cleanPhone = '0' . $cleanPhone;
                }
            }
            if (!empty($cleanPhone) && !preg_match('/^01[0-9]{9}$/', $cleanPhone)) {
                $cleanPhone = '';
            }

            $cleanEmergencyPhone = preg_replace('/[^\d]/', '', $emergencyPhone);
            if (!empty($cleanEmergencyPhone)) {
                if (strpos($cleanEmergencyPhone, '002') === 0) {
                    $cleanEmergencyPhone = substr($cleanEmergencyPhone, 2);
                }
                if (strpos($cleanEmergencyPhone, '20') === 0) {
                    $cleanEmergencyPhone = substr($cleanEmergencyPhone, 2);
                }
                if (strlen($cleanEmergencyPhone) === 10 && $cleanEmergencyPhone[0] === '1') {
                    $cleanEmergencyPhone = '0' . $cleanEmergencyPhone;
                }
            }
            if (!empty($cleanEmergencyPhone) && !preg_match('/^01[0-9]{9}$/', $cleanEmergencyPhone)) {
                $cleanEmergencyPhone = '';
            }

            if ($gender !== 'male' && $gender !== 'female') {
                $gender = detectGenderFromName($name);
            }

            $targetChurchId = $churchId;
            $existingCustomInfo = [];
            if ($studentId > 0) {
                $getStmt = $conn->prepare("SELECT church_id, custom_info FROM students WHERE id = ?");
                $getStmt->bind_param("i", $studentId);
                $getStmt->execute();
                $existingRow = $getStmt->get_result()->fetch_assoc();
                if ($existingRow) {
                    $actualChurchId = intval($existingRow['church_id']);
                    if (in_array($actualChurchId, $allowedChurches)) {
                        $targetChurchId = $actualChurchId;
                        if (!empty($existingRow['custom_info'])) {
                            $existingCustomInfo = json_decode($existingRow['custom_info'], true) ?: [];
                        }
                    } else {
                        $studentId = 0;
                    }
                } else {
                    $studentId = 0;
                }
            }

            $infoObj = $existingCustomInfo;
            if (is_array($customInfoInput)) {
                foreach ($customInfoInput as $k => $v) {
                    $cleanK = strip_tags(trim((string)$k));
                    $cleanV = strip_tags(trim((string)$v));
                    if ($cleanK !== '') {
                        $infoObj[$cleanK] = $cleanV;
                    }
                }
            }
            $customInfoJson = !empty($infoObj) ? json_encode($infoObj, JSON_UNESCAPED_UNICODE) : null;

            if ($studentId > 0) {
                $setParts = ["name = ?", "gender = ?", "updated_at = NOW()"];
                $setTypes = "ss";
                $setValues = [$name, $gender];

                if ($classId > 0) {
                    $setParts[] = "class_id = ?";
                    $setParts[] = "class = ?";
                    $setTypes .= "is";
                    $setValues[] = $classId;
                    $setValues[] = $className;
                }
                if ($address !== '') {
                    $setParts[] = "address = ?";
                    $setTypes .= "s";
                    $setValues[] = $address;
                }
                if ($cleanPhone !== '') {
                    $setParts[] = "phone = ?";
                    $setTypes .= "s";
                    $setValues[] = $cleanPhone;
                }
                if ($cleanEmergencyPhone !== '') {
                    $setParts[] = "emergency_phone = ?";
                    $setTypes .= "s";
                    $setValues[] = $cleanEmergencyPhone;
                }
                if ($medicalNotes !== '') {
                    $setParts[] = "medical_notes = ?";
                    $setTypes .= "s";
                    $setValues[] = $medicalNotes;
                }
                if ($formattedBirthday !== null) {
                    $setParts[] = "birthday = ?";
                    $setTypes .= "s";
                    $setValues[] = $formattedBirthday;
                }
                if ($customInfoJson !== null) {
                    $setParts[] = "custom_info = ?";
                    $setTypes .= "s";
                    $setValues[] = $customInfoJson;
                }

                $setTypes .= "ii";
                $setValues[] = $studentId;
                $setValues[] = $targetChurchId;

                $updateSql = "UPDATE students SET " . implode(', ', $setParts) . " WHERE id = ? AND church_id = ?";
                $updateStmt = $conn->prepare($updateSql);
                $updateStmt->bind_param($setTypes, ...$setValues);
                if ($updateStmt->execute()) {
                    $updatedCount++;
                } else {
                    $errors[] = "فشل تحديث الطفل " . $name . ": " . $updateStmt->error;
                    continue;
                }
            } else {
                $addedByType = 'bulk_add';
                $insStmt = $conn->prepare("
                    INSERT INTO students 
                    (church_id, name, class_id, class, address, phone, emergency_phone, medical_notes, birthday, gender, custom_info, commitment_coupons, coupons, attendance_coupons, added_by)
                    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 0, 0, 0, ?)
                ");
                $insStmt->bind_param("isisssssssss", $targetChurchId, $name, $classId, $className, $address, $cleanPhone, $cleanEmergencyPhone, $medicalNotes, $formattedBirthday, $gender, $customInfoJson, $addedByType);
                if ($insStmt->execute()) {
                    $studentId = $conn->insert_id;
                    $addedCount++;
                } else {
                    $errors[] = "فشل إضافة الطفل " . $name . ": " . $insStmt->error;
                    continue;
                }
            }

            if ($studentId > 0 && !empty($siblings)) {
                linkSiblingsByName($conn, $targetChurchId, $studentId, $siblings);
            }

            if ($tripId > 0 && $studentId > 0) {
                $chkReg = $conn->prepare("SELECT id, cancelled FROM trip_registrations WHERE trip_id = ? AND student_id = ?");
                $chkReg->bind_param("ii", $tripId, $studentId);
                $chkReg->execute();
                $chkRegRes = $chkReg->get_result();

                $isAlreadyRegistered = false;
                $existingReg = null;
                if ($chkRegRes->num_rows > 0) {
                    $existingReg = $chkRegRes->fetch_assoc();
                    if ($existingReg['cancelled'] == 0) {
                        $isAlreadyRegistered = true;
                    }
                }

                if (!$isAlreadyRegistered) {
                }

                if ($chkRegRes->num_rows > 0) {
                    // Re-fetch existingReg if it was cancelled
                    if ($existingReg['cancelled'] == 1) {
                        $reactivate = $conn->prepare("UPDATE trip_registrations SET cancelled = 0, registered_by = ? WHERE id = ?");
                        $reactivate->bind_param("ii", $uncleId, $existingReg['id']);
                        $reactivate->execute();
                        $registeredCount++;
                    }
                } else {
                    $isWaitlist = false;
                    if ($churchId === $ownerChurchId) {
                        $ownerCountStmt = $conn->prepare("
                            SELECT COUNT(*) as cnt
                            FROM trip_registrations tr
                            LEFT JOIN students s ON tr.student_id = s.id AND tr.registration_type != 'guest'
                            LEFT JOIN guests g ON tr.guest_id = g.id AND tr.registration_type = 'guest'
                            WHERE tr.trip_id = ? 
                              AND tr.cancelled = 0
                              AND COALESCE(s.church_id, g.church_id) = ?
                        ");
                        $ownerCountStmt->bind_param("ii", $tripId, $ownerChurchId);
                        $ownerCountStmt->execute();
                        $ownerCount = (int) $ownerCountStmt->get_result()->fetch_assoc()['cnt'];
                        if ($maxParticipants > 0 && $ownerCount >= $maxParticipants) {
                            $isWaitlist = true;
                        }
                    } else {
                        // Check individual collaborator limit
                        if ($churchLimit !== null) {
                            $cntStmt = $conn->prepare("
                                SELECT COUNT(*) as cnt
                                FROM trip_registrations tr
                                LEFT JOIN students s ON tr.student_id = s.id AND tr.registration_type != 'guest'
                                LEFT JOIN guests g ON tr.guest_id = g.id AND tr.registration_type = 'guest'
                                WHERE tr.trip_id = ? 
                                  AND tr.cancelled = 0
                                  AND COALESCE(s.church_id, g.church_id) = ?
                            ");
                            $cntStmt->bind_param("ii", $tripId, $churchId);
                            $cntStmt->execute();
                            $churchActiveCount = (int) $cntStmt->get_result()->fetch_assoc()['cnt'];
                            if ($churchActiveCount >= $churchLimit) {
                                $isWaitlist = true;
                            }
                        }

                        if (!$isWaitlist) {
                            $collabLimitMode = $trip['collab_limit_mode'] ?? 'open';
                            if ($collabLimitMode === 'limited') {
                                $collabMax = intval($trip['collab_max_participants'] ?? 0);
                                $collabCountStmt = $conn->prepare("
                                    SELECT COUNT(*) as cnt
                                    FROM trip_registrations tr
                                    LEFT JOIN students s ON tr.student_id = s.id AND tr.registration_type != 'guest'
                                    LEFT JOIN guests g ON tr.guest_id = g.id AND tr.registration_type = 'guest'
                                    WHERE tr.trip_id = ? 
                                      AND tr.cancelled = 0
                                      AND COALESCE(s.church_id, g.church_id) != ?
                                ");
                                $collabCountStmt->bind_param("ii", $tripId, $ownerChurchId);
                                $collabCountStmt->execute();
                                $collabCount = (int) $collabCountStmt->get_result()->fetch_assoc()['cnt'];
                                if ($collabMax > 0 && $collabCount >= $collabMax) {
                                    $isWaitlist = true;
                                }
                            }
                        }
                    }

                    if ($isWaitlist) {
                        $checkWait = $conn->prepare("SELECT id FROM trip_waitlist WHERE trip_id = ? AND student_id = ?");
                        $checkWait->bind_param("ii", $tripId, $studentId);
                        $checkWait->execute();
                        if ($checkWait->get_result()->num_rows === 0) {
                            $position = getWaitlistNextPosition($conn, $tripId);
                            $insW = $conn->prepare("INSERT INTO trip_waitlist (trip_id, student_id, church_id, added_by, position) VALUES (?, ?, ?, ?, ?)");
                            $insW->bind_param("iiiii", $tripId, $studentId, $targetChurchId, $uncleId, $position);
                            $insW->execute();
                        }
                    } else {
                        $regStmt = $conn->prepare("
                            INSERT INTO trip_registrations (trip_id, student_id, registered_by, registration_type)
                            VALUES (?, ?, ?, 'student')
                        ");
                        $regStmt->bind_param("iii", $tripId, $studentId, $uncleId);
                        if ($regStmt->execute()) {
                            $registeredCount++;
                        } else {
                            $errors[] = "فشل تسجيل الطفل " . $name . " في الرحلة: " . $regStmt->error;
                        }
                    }
                }
            }
        }

        $conn->commit();
        sendJSON([
            'success' => true,
            'message' => "تم الاستيراد بنجاح! الإضافات: {$addedCount}، التحديثات: {$updatedCount}، التسجيلات في الرحلة: {$registeredCount}",
            'errors' => $errors,
            'added' => $addedCount,
            'updated' => $updatedCount,
            'registered' => $registeredCount
        ]);

    } catch (Exception $e) {
        if (isset($conn)) {
            $conn->rollback();
        }
        sendJSON(['success' => false, 'message' => 'خطأ في الاستيراد: ' . $e->getMessage()]);
    }
}

function normalizeArabicClassName($name) {
    if (empty($name)) return '';
    $name = mb_strtolower(trim($name), 'UTF-8');
    
    // Normalize Alef, Hamza
    $name = preg_replace('/[أإآا]/u', 'ا', $name);
    // Normalize Teh Marbuta
    $name = preg_replace('/ة/u', 'ه', $name);
    // Normalize Yeh
    $name = preg_replace('/[ىي]/u', 'ي', $name);
    
    // Replace standard grade spelling to colloquial base to ensure intersection matches
    $name = str_replace('ثانيه', 'تانيه', $name);
    $name = str_replace('ثالثه', 'تالته', $name);
    
    // Remove punctuation, slashes, dashes, spaces and the conjunction 'و' (and)
    $name = preg_replace('/[[:punct:]]/u', '', $name);
    $name = str_replace(' ', '', $name);
    $name = str_replace('و', '', $name);
    
    return $name;
}

function normalizeArabicNamePHP($str) {
    if (empty($str)) return '';
    $s = trim($str);
    $s = mb_strtolower($s, 'UTF-8');
    
    // Remove Arabic diacritics (harakat)
    $diacritics = [
        "\xd9\x8b", "\xd9\x8c", "\xd9\x8d", "\xd9\x8e", 
        "\xd9\x8f", "\xd9\x90", "\xd9\x91", "\xd9\x92"
    ];
    $s = str_replace($diacritics, '', $s);
    
    // Normalize Hamzas to bare Alif
    $s = preg_replace('/[أإآا]/u', 'ا', $s);
    // Normalize Ya/Alif Maqsura
    $s = preg_replace('/[ىي]/u', 'ي', $s);
    // Normalize Ta Marbuta to Ha
    $s = preg_replace('/ة/u', 'ه', $s);
    
    return $s;
}

function calculateFuzzyScorePHP($name1, $name2) {
    $n1 = normalizeArabicNamePHP($name1);
    $n2 = normalizeArabicNamePHP($name2);
    if ($n1 === $n2) return 1.0;
    
    $w1 = array_filter(explode(' ', $n1));
    $w2 = array_filter(explode(' ', $n2));
    if (empty($w1) || empty($w2)) return 0.0;
    
    $matches = 0;
    foreach ($w1 as $word1) {
        if (in_array($word1, $w2)) {
            $matches++;
        } else {
            $bestWordScore = 0;
            foreach ($w2 as $word2) {
                $d = levenshtein($word1, $word2);
                $maxL = max(mb_strlen($word1, 'UTF-8'), mb_strlen($word2, 'UTF-8'));
                if ($maxL > 0) {
                    $score = 1.0 - ($d / $maxL);
                    if ($score > $bestWordScore) {
                        $bestWordScore = $score;
                    }
                }
            }
            if ($bestWordScore > 0.8) {
                $matches += $bestWordScore;
            }
        }
    }
    
    $wordScore = $matches / max(count($w1), count($w2));
    $dist = levenshtein($n1, $n2);
    $maxLen = max(mb_strlen($n1, 'UTF-8'), mb_strlen($n2, 'UTF-8'));
    $strScore = $maxLen > 0 ? (1.0 - ($dist / $maxLen)) : 0;
    
    return max($wordScore, $strScore);
}

function linkSiblingsByName($conn, $churchId, $studentId, $siblingName) {
    if (empty($siblingName)) return;
    
    $cleanSiblingName = trim($siblingName);
    if (empty($cleanSiblingName)) return;
    
    // 1. Try exact query match first
    $stmt = $conn->prepare("SELECT id FROM students WHERE name = ? AND church_id = ? AND COALESCE(enrollment_status, 'active') = 'active' LIMIT 1");
    $stmt->bind_param("si", $cleanSiblingName, $churchId);
    $stmt->execute();
    $res = $stmt->get_result()->fetch_assoc();
    
    $siblingId = 0;
    if ($res) {
        $siblingId = intval($res['id']);
    } else {
        // 2. Fetch all active kids in this church to do normalized & fuzzy match
        $allStmt = $conn->prepare("SELECT id, name FROM students WHERE church_id = ? AND COALESCE(enrollment_status, 'active') = 'active'");
        $allStmt->bind_param("i", $churchId);
        $allStmt->execute();
        $studentsResult = $allStmt->get_result();
        
        $normSibling = normalizeArabicNamePHP($cleanSiblingName);
        $bestMatchId = 0;
        $bestMatchScore = 0;
        
        while ($row = $studentsResult->fetch_assoc()) {
            $dbName = $row['name'];
            $dbId = intval($row['id']);
            if ($dbId === $studentId) continue;
            
            // Normalized exact match
            $normDbName = normalizeArabicNamePHP($dbName);
            if ($normSibling === $normDbName) {
                $siblingId = $dbId;
                break;
            }
            
            // Fuzzy match score
            $score = calculateFuzzyScorePHP($cleanSiblingName, $dbName);
            if ($score > $bestMatchScore) {
                $bestMatchScore = $score;
                $bestMatchId = $dbId;
            }
        }
        
        if ($siblingId === 0 && $bestMatchScore >= 0.85) {
            $siblingId = $bestMatchId;
        }
    }
    
    if ($siblingId === 0 || $siblingId === $studentId) {
        return; // No match found or same student
    }
    
    // Check sibling groups
    $group1 = getStudentSiblingGroupMeta($conn, $studentId);
    $group2 = getStudentSiblingGroupMeta($conn, $siblingId);
    
    $groupId = '';
    if ($group1) {
        $groupId = $group1['id'];
    } elseif ($group2) {
        $groupId = $group2['id'];
    } else {
        $groupId = 'family_' . time() . '_' . substr(md5(uniqid('', true)), 0, 8);
        
        // Insert new sibling group
        $stmtName = $conn->prepare("SELECT name FROM students WHERE id = ?");
        $stmtName->bind_param("i", $siblingId);
        $stmtName->execute();
        $sRow = $stmtName->get_result()->fetch_assoc();
        $groupLabelName = $sRow ? $sRow['name'] : $cleanSiblingName;
        
        $label = 'عائلة ' . $groupLabelName;
        $status = 'approved';
        $linkedBy = $_SESSION['username'] ?? 'bulk_import';
        $linkedById = intval($_SESSION['uncle_id'] ?? 0);
        
        $grpStmt = $conn->prepare("INSERT INTO student_sibling_groups (id, church_id, label, status, linked_by_id, linked_by_name) VALUES (?, ?, ?, ?, ?, ?)");
        $grpStmt->bind_param("sissis", $groupId, $churchId, $label, $status, $linkedById, $linkedBy);
        $grpStmt->execute();
    }
    
    // Insert members if not already there
    $insMember = $conn->prepare("INSERT IGNORE INTO student_sibling_group_members (student_id, group_id, church_id) VALUES (?, ?, ?)");
    
    $insMember->bind_param("isi", $studentId, $groupId, $churchId);
    $insMember->execute();
    
    $insMember->bind_param("isi", $siblingId, $groupId, $churchId);
    $insMember->execute();
    
    // Sync custom info json
    syncSiblingGroupToStudentCustomInfo($conn, $studentId);
    syncSiblingGroupToStudentCustomInfo($conn, $siblingId);
}

function getKidsData()

{

    try {

        $churchId = getChurchId();

        $classFilter = sanitize($_GET['class'] ?? '');



        $conn = getDBConnection();



        $sql = "SELECT 

                    s.id, s.name, s.address, s.phone, s.birthday,

                    s.coupons, s.attendance_coupons, s.commitment_coupons,

                    s.image_url, s.church_id, s.class_id,

                    c.church_name,

                    cl.arabic_name as class

                FROM students s

                LEFT JOIN churches c ON s.church_id = c.id

                LEFT JOIN classes cl ON s.class_id = cl.id

                WHERE s.church_id = ?";



        $params = [$churchId];

        $types = "i";



        if (!empty($classFilter)) {

            $sql .= " AND cl.arabic_name = ?";

            $params[] = $classFilter;

            $types .= "s";

        }



        $sql .= " ORDER BY 

                CASE cl.arabic_name 

                    WHEN 'حضانة' THEN 1

                    WHEN 'أولى' THEN 2

                    WHEN 'تانية' THEN 3

                    WHEN 'تالتة' THEN 4

                    WHEN 'رابعة' THEN 5

                    WHEN 'خامسة' THEN 6

                    WHEN 'سادسة' THEN 7

                    ELSE 8

                END, s.name";



        $stmt = $conn->prepare($sql);

        $stmt->bind_param($types, ...$params);

        $stmt->execute();

        $result = $stmt->get_result();



        $kids = [];

        while ($row = $result->fetch_assoc()) {

            $kids[] = [

                'id' => $row['id'],

                'name' => $row['name'],

                'class' => $row['class'] ?? '---',

                'address' => $row['address'] ?? '',

                'phone' => $row['phone'] ?? '',

                'birthday' => formatDateFromDB($row['birthday']),

                'image_url' => $row['image_url'] ?? '',

                'coupons' => $row['coupons'] ?? 0,

                'attendance_coupons' => $row['attendance_coupons'] ?? 0,

                'commitment_coupons' => $row['commitment_coupons'] ?? 0

            ];

        }



        sendJSON(['success' => true, 'kids' => $kids, 'users' => $kids]);



    } catch (Exception $e) {

        error_log("getKidsData error: " . $e->getMessage());

        sendJSON(['success' => false, 'message' => 'خطأ في جلب بيانات الأطفال']);

    }

}



function handleKidLogin()

{

    try {

        $usernameInput = sanitize($_POST['username'] ?? '');

        $password = $_POST['password'] ?? '';



        if (empty($usernameInput) || empty($password)) {

            sendJSON(['success' => false, 'message' => 'رقم الهاتف وكلمة المرور مطلوبان']);

        }



        $passwordHash = hash('sha256', $password);

        $cleanInput = preg_replace('/[^\d]/', '', $usernameInput);



        error_log("🔐 Login attempt with input: $cleanInput");



        $conn = getDBConnection();



        $stmt = $conn->prepare("

            SELECT

                s.id, s.name, s.address, s.phone, s.birthday, s.email,

                s.coupons, s.attendance_coupons, s.commitment_coupons,

                s.task_coupons, s.image_url, s.church_id, s.class_id,

                s.custom_info, s.trip_points,

                c.church_name,
                COALESCE(c.church_type, 'kids') AS church_type,

                COALESCE(cc.arabic_name, cl.arabic_name, s.class) AS class

            FROM students s

            LEFT JOIN churches c  ON s.church_id = c.id

            LEFT JOIN church_classes cc ON cc.id = s.class_id AND cc.church_id = s.church_id AND cc.is_active = 1

            LEFT JOIN classes cl  ON cl.id = s.class_id

            WHERE (s.phone LIKE CONCAT('%', ?) OR s.phone = ?)

            AND s.password_hash = ?

        ");

        $stmt->bind_param("sss", $cleanInput, $cleanInput, $passwordHash);

        $stmt->execute();

        $result = $stmt->get_result();



        $students = [];

        $authenticatedIds = [];

        while ($row = $result->fetch_assoc()) {

            $row['class'] = $row['class'] ?? '---';

            $students[] = $row;

            $authenticatedIds[] = $row['id'];

        }



        // Also load siblings on same phone

        if (!empty($authenticatedIds)) {

            $idList = implode(',', array_map('intval', $authenticatedIds));

            $sibStmt = $conn->prepare("

                SELECT

                    s.id, s.name, s.address, s.phone, s.birthday, s.email,

                    s.coupons, s.attendance_coupons, s.commitment_coupons,

                    s.task_coupons, s.image_url, s.church_id, s.class_id,

                    s.custom_info,

                    c.church_name,

                    COALESCE(cc.arabic_name, cl.arabic_name, s.class) AS class

                FROM students s

                LEFT JOIN churches c  ON s.church_id = c.id

                LEFT JOIN church_classes cc ON cc.id = s.class_id AND cc.church_id = s.church_id AND cc.is_active = 1

                LEFT JOIN classes cl  ON cl.id = s.class_id

                WHERE (s.phone LIKE CONCAT('%', ?) OR s.phone = ?)

                AND s.id NOT IN ($idList)

            ");

            $sibStmt->bind_param("ss", $cleanInput, $cleanInput);

            $sibStmt->execute();

            $sibResult = $sibStmt->get_result();

            while ($row = $sibResult->fetch_assoc()) {

                $row['class'] = $row['class'] ?? '---';

                $students[] = $row;

            }

        }



        if (count($students) > 0) {

            error_log("🔐 Login successful for: $cleanInput");

            sendJSON(['success' => true, 'data' => $students, 'message' => 'تم تسجيل الدخول بنجاح']);

        } else {

            error_log("🔐 Login failed for: $cleanInput");

            sendJSON(['success' => false, 'message' => 'رقم الهاتف أو كلمة المرور غير صحيحة', 'data' => []]);

        }



    } catch (Exception $e) {

        error_log("❌ handleKidLogin error: " . $e->getMessage());

        sendJSON(['success' => false, 'message' => 'خطأ في تسجيل الدخول']);

    }

}

function checkKidPasswordByPhone()

{

    try {

        $phone = sanitize($_POST['phone'] ?? '');



        if (empty($phone)) {

            sendJSON(['success' => false, 'message' => 'رقم الهاتف مطلوب']);

        }



        // Clean the phone number

        $cleanPhone = preg_replace('/[^\d]/', '', $phone);



        error_log("🔐 Checking password for phone: $cleanPhone");



        $conn = getDBConnection();



        // First check if student exists

        $checkStmt = $conn->prepare("

            SELECT id, name, phone 

            FROM students 

            WHERE phone = ? 

               OR phone LIKE CONCAT('%', ?)

               OR REPLACE(phone, '''', '') = ?

               OR REPLACE(phone, '''', '') LIKE CONCAT('%', ?)

            LIMIT 1

        ");

        $checkStmt->bind_param("ssss", $cleanPhone, $cleanPhone, $cleanPhone, $cleanPhone);

        $checkStmt->execute();

        $result = $checkStmt->get_result();



        if ($student = $result->fetch_assoc()) {

            $studentId = $student['id'];



            // Now check if password exists

            // First, check if password_hash column exists

            $columnCheck = $conn->query("SHOW COLUMNS FROM students LIKE 'password_hash'");



            if ($columnCheck && $columnCheck->num_rows > 0) {

                // Column exists, check if there's a password

                $passwordStmt = $conn->prepare("

                    SELECT password_hash FROM students WHERE id = ?

                ");

                $passwordStmt->bind_param("i", $studentId);

                $passwordStmt->execute();

                $passwordResult = $passwordStmt->get_result();

                $passwordData = $passwordResult->fetch_assoc();



                $hasPassword = !empty($passwordData['password_hash']);

            } else {

                // Column doesn't exist or no password

                $hasPassword = false;

            }



            error_log("🔐 Student found: ID=" . $studentId . ", Name=" . $student['name'] .

                ", Has Password=" . ($hasPassword ? 'YES' : 'NO'));



            sendJSON([

                'success' => true,

                'has_password' => $hasPassword,

                'student_id' => $studentId,

                'message' => $hasPassword ? 'يوجد كلمة مرور مسجلة لهذا الرقم' : 'لا توجد كلمة مرور مسجلة'

            ]);



        } else {

            error_log("🔐 No student found for phone: $cleanPhone");

            sendJSON([

                'success' => false,

                'message' => 'لم يتم العثور على طفل بهذا الرقم'

            ]);

        }



    } catch (Exception $e) {

        error_log("❌ checkKidPasswordByPhone error: " . $e->getMessage());

        sendJSON(['success' => false, 'message' => 'خطأ في التحقق: ' . $e->getMessage()]);

    }

}



function setupStudentPassword()

{

    try {

        $studentId = intval($_POST['studentId'] ?? 0);

        $phone = sanitize($_POST['phone'] ?? '');

        $password = $_POST['password'] ?? '';

        $applyToAllSiblings = isset($_POST['applyToAllSiblings']) && $_POST['applyToAllSiblings'] === 'true';



        if ($studentId === 0 || empty($phone) || empty($password)) {

            sendJSON(['success' => false, 'message' => 'بيانات غير كاملة']);

        }



        $passwordHash = hash('sha256', $password);

        $cleanPhone = preg_replace('/[^\d]/', '', $phone);



        $conn = getDBConnection();



        if ($applyToAllSiblings) {

            // Apply password to ALL students with this phone number

            $updateStmt = $conn->prepare("

                UPDATE students 

                SET password_hash = ?, updated_at = NOW()

                WHERE (phone LIKE CONCAT('%', ?) OR phone = ?)

            ");

            $updateStmt->bind_param("sss", $passwordHash, $cleanPhone, $cleanPhone);



            if ($updateStmt->execute()) {

                $affectedRows = $updateStmt->affected_rows;

                sendJSON([

                    'success' => true,

                    'message' => "تم حفظ كلمة المرور لـ $affectedRows حساب",

                    'updated_count' => $affectedRows

                ]);

            } else {

                sendJSON(['success' => false, 'message' => 'فشل في حفظ كلمة المرور: ' . $conn->error]);

            }

        } else {

            // Apply password only to selected student

            $updateStmt = $conn->prepare("

                UPDATE students 

                SET password_hash = ?, updated_at = NOW()

                WHERE id = ?

            ");

            $updateStmt->bind_param("si", $passwordHash, $studentId);



            if ($updateStmt->execute()) {

                sendJSON([

                    'success' => true,

                    'message' => 'تم حفظ كلمة المرور بنجاح'

                ]);

            } else {

                sendJSON(['success' => false, 'message' => 'فشل في حفظ كلمة المرور: ' . $conn->error]);

            }

        }



    } catch (Exception $e) {

        error_log("setupStudentPassword error: " . $e->getMessage());

        sendJSON(['success' => false, 'message' => 'خطأ في إعداد كلمة المرور: ' . $e->getMessage()]);

    }

}



// ── Change/Set student password with old-password verification ───────────────

function changeStudentPassword()

{

    try {

        $studentId = intval($_POST['studentId'] ?? 0);

        $phone     = sanitize($_POST['phone'] ?? '');

        $oldPass   = $_POST['oldPassword'] ?? '';

        $newPass   = $_POST['newPassword'] ?? '';

        $isAdd     = ($_POST['isAdd'] ?? 'false') === 'true'; // true = no old pass needed



        if ($studentId === 0 || empty($phone) || empty($newPass)) {

            sendJSON(['success' => false, 'message' => 'بيانات غير كاملة']);

            return;

        }

        if (strlen($newPass) < 6) {

            sendJSON(['success' => false, 'message' => 'كلمة المرور يجب أن تكون 6 أحرف على الأقل']);

            return;

        }



        $conn = getDBConnection();



        // Fetch current hash

        $stmt = $conn->prepare("SELECT password_hash FROM students WHERE id = ? LIMIT 1");

        $stmt->bind_param("i", $studentId);

        $stmt->execute();

        $row = $stmt->get_result()->fetch_assoc();

        $currentHash = $row['password_hash'] ?? '';



        if (!$isAdd) {

            // Verify old password

            if (empty($oldPass)) {

                sendJSON(['success' => false, 'message' => 'يرجى إدخال كلمة المرور الحالية']);

                return;

            }

            $oldHash = hash('sha256', $oldPass);

            if ($oldHash !== $currentHash && !password_verify($oldPass, $currentHash)) {

                sendJSON(['success' => false, 'message' => 'كلمة المرور الحالية غير صحيحة']);

                return;

            }

        } else {

            // isAdd mode — only allowed if account actually has no password yet

            if (!empty($currentHash)) {

                sendJSON(['success' => false, 'message' => 'الحساب لديه كلمة مرور بالفعل. استخدم تغيير كلمة المرور.']);

                return;

            }

        }



        $newHash = hash('sha256', $newPass);

        $upd = $conn->prepare("UPDATE students SET password_hash = ?, updated_at = NOW() WHERE id = ?");

        $upd->bind_param("si", $newHash, $studentId);



        if ($upd->execute()) {

            sendJSON(['success' => true, 'message' => $isAdd ? 'تم إضافة كلمة المرور بنجاح' : 'تم تغيير كلمة المرور بنجاح']);

        } else {

            sendJSON(['success' => false, 'message' => 'فشل في الحفظ: ' . $conn->error]);

        }



    } catch (Exception $e) {

        error_log("changeStudentPassword error: " . $e->getMessage());

        sendJSON(['success' => false, 'message' => 'خطأ: ' . $e->getMessage()]);

    }

}



function kidLoginByPhoneWithPassword()

{

    try {

        $phone = sanitize($_POST['phone'] ?? '');

        $password = $_POST['password'] ?? '';

        $studentId = intval($_POST['studentId'] ?? 0);



        if (empty($phone) || empty($password)) {

            sendJSON(['success' => false, 'message' => 'رقم الهاتف وكلمة المرور مطلوبان']);

            return;

        }

        $sha256Hash = hash('sha256', $password); // legacy

        $cleanPhone = preg_replace('/[^\d]/', '', $phone);



        error_log("🔐 Phone+password login attempt: $cleanPhone, studentId: $studentId");



        $conn = getDBConnection();



        // Fetch candidates by phone

        if ($studentId > 0) {

            $stmt = $conn->prepare("

                SELECT s.id, s.name, s.address, s.phone, s.birthday,

                       s.coupons, s.attendance_coupons, s.commitment_coupons,

                       s.task_coupons, s.image_url, s.church_id, s.class_id,

                       s.password_hash, s.custom_info,

                       c.church_name,

                       COALESCE(cc.arabic_name, cl.arabic_name, s.class) AS class

                FROM students s

                LEFT JOIN churches c  ON s.church_id = c.id

                LEFT JOIN church_classes cc ON cc.id = s.class_id AND cc.church_id = s.church_id

                LEFT JOIN classes cl  ON cl.id = s.class_id

                WHERE s.id = ?

            ");

            $stmt->bind_param("i", $studentId);

        } else {

            $stmt = $conn->prepare("

                SELECT s.id, s.name, s.address, s.phone, s.birthday,

                       s.coupons, s.attendance_coupons, s.commitment_coupons,

                       s.task_coupons, s.image_url, s.church_id, s.class_id,

                       s.password_hash, s.custom_info,

                       c.church_name,

                       COALESCE(cc.arabic_name, cl.arabic_name, s.class) AS class

                FROM students s

                LEFT JOIN churches c  ON s.church_id = c.id

                LEFT JOIN church_classes cc ON cc.id = s.class_id AND cc.church_id = s.church_id

                LEFT JOIN classes cl  ON cl.id = s.class_id

                WHERE (s.phone = ? OR s.phone LIKE CONCAT('%', ?))

            ");

            $stmt->bind_param("ss", $cleanPhone, $cleanPhone);

        }

        $stmt->execute();

        $result = $stmt->get_result();



        $students = [];

        while ($row = $result->fetch_assoc()) {

            $storedHash = $row['password_hash'] ?? '';

            $matched = !empty($storedHash) && (

                password_verify($password, $storedHash) || $storedHash === $sha256Hash

            );

            if ($matched) {

                $row['birthday'] = formatDateFromDB($row['birthday']);

                $row['class'] = $row['class'] ?? '---';

                unset($row['password_hash']);

                $students[] = $row;

            }

        }



        if (count($students) > 0) {

            sendJSON(['success' => true, 'data' => $students, 'message' => 'تم تسجيل الدخول بنجاح']);

        } else {

            sendJSON(['success' => false, 'message' => 'كلمة المرور غير صحيحة', 'data' => []]);

        }



    } catch (Exception $e) {

        error_log("❌ kidLoginByPhoneWithPassword error: " . $e->getMessage());

        sendJSON(['success' => false, 'message' => 'خطأ في تسجيل الدخول']);

    }

}

function kidLogin()

{

    try {

        $usernameInput = sanitize($_POST['username'] ?? '');

        $password = $_POST['password'] ?? '';



        if (empty($usernameInput) || empty($password)) {

            sendJSON(['success' => false, 'message' => 'اسم المستخدم وكلمة المرور مطلوبان']);

            return;

        }



        $conn = getDBConnection();



        // Detect if input looks like a phone number (digits only)

        $cleanInput = preg_replace('/[^\d]/', '', $usernameInput);

        $isPhoneLike = strlen($cleanInput) >= 7;

        $sha256Hash = hash('sha256', $password); // legacy hash



        error_log("🔐 [kidLogin] input: '$usernameInput' | isPhone: " . ($isPhoneLike ? 'yes' : 'no'));



        // ── Build candidate list ─────────────────────────────────

        // We search by phone OR by username stored in custom_info JSON

        $candidates = [];



        // 1. Search by phone (digits)

        if ($isPhoneLike) {

            $stmt = $conn->prepare("

                SELECT s.id, s.name, s.address, s.phone, s.birthday, s.email,

                       s.coupons, s.attendance_coupons, s.commitment_coupons,

                       s.task_coupons, s.image_url, s.church_id, s.class_id,

                       s.custom_info, s.password_hash,

                       c.church_name,

                       COALESCE(cc.arabic_name, cl.arabic_name, s.class) AS class

                FROM students s

                LEFT JOIN churches c  ON s.church_id = c.id

                LEFT JOIN church_classes cc ON cc.id = s.class_id AND cc.church_id = s.church_id

                LEFT JOIN classes cl  ON cl.id = s.class_id

                WHERE (s.phone LIKE CONCAT('%', ?) OR s.phone = ?)

            ");

            $stmt->bind_param("ss", $cleanInput, $cleanInput);

            $stmt->execute();

            $res = $stmt->get_result();

            while ($row = $res->fetch_assoc()) {

                $row['class'] = $row['class'] ?? '---';

                $candidates[$row['id']] = $row;

            }

        }



        // 2. Search by username in custom_info JSON

        // custom_info is {"username":"..."} stored as JSON text

        $usernameClean = trim($usernameInput);

        if (!empty($usernameClean)) {

            $stmt2 = $conn->prepare("

                SELECT s.id, s.name, s.address, s.phone, s.birthday, s.email,

                       s.coupons, s.attendance_coupons, s.commitment_coupons,

                       s.task_coupons, s.image_url, s.church_id, s.class_id,

                       s.custom_info, s.password_hash,

                       c.church_name,

                       COALESCE(cc.arabic_name, cl.arabic_name, s.class) AS class

                FROM students s

                LEFT JOIN churches c  ON s.church_id = c.id

                LEFT JOIN church_classes cc ON cc.id = s.class_id AND cc.church_id = s.church_id

                LEFT JOIN classes cl  ON cl.id = s.class_id

                WHERE JSON_UNQUOTE(JSON_EXTRACT(s.custom_info, '$.username')) = ?

                   OR JSON_UNQUOTE(JSON_EXTRACT(s.custom_info, '$.username')) = ?

            ");

            $usernameCleanLower = strtolower($usernameClean);

            $stmt2->bind_param("ss", $usernameClean, $usernameCleanLower);

            $stmt2->execute();

            $res2 = $stmt2->get_result();

            while ($row = $res2->fetch_assoc()) {

                $row['class'] = $row['class'] ?? '---';

                if (!isset($candidates[$row['id']])) {

                    $candidates[$row['id']] = $row;

                }

            }

        }



        error_log("🔐 [kidLogin] candidates before auth: " . count($candidates));



        // ── Verify password against each candidate ───────────────

        $authenticated = [];

        foreach ($candidates as $student) {

            $storedHash = $student['password_hash'] ?? '';

            $matched = false;

            $needsHashUpgrade = false;



            if (!empty($storedHash)) {

                // Try SHA256 first (standard for all flows)

                if ($storedHash === $sha256Hash) {

                    $matched = true;

                }

                // Fallback: bcrypt (old registrations) — migrate to SHA256 on success

                elseif (password_verify($password, $storedHash)) {

                    $matched = true;

                    $needsHashUpgrade = true;

                }

            }



            if ($matched) {

                // Migrate bcrypt → SHA256 so all hashes are consistent

                if ($needsHashUpgrade) {

                    $upd = $conn->prepare("UPDATE students SET password_hash = ? WHERE id = ?");

                    if ($upd) {

                        $studentId = $student['id'];

                        $upd->bind_param("si", $sha256Hash, $studentId);

                        $upd->execute();

                    }

                    error_log("🔄 [kidLogin] Migrated bcrypt→SHA256 for student ID " . $student['id']);

                }

                $student['has_password'] = !empty($storedHash); // tell the frontend
                unset($student['password_hash']); // never expose hash

                $authenticated[] = $student;

            }

        }



        error_log("🔐 [kidLogin] authenticated: " . count($authenticated));



        if (count($authenticated) > 0) {

            $vals = array_values($authenticated);
            sendJSON([

                'success' => true,

                'data' => $vals,
                'users' => $vals,
                'user' => count($vals) === 1 ? $vals[0] : null,

                'message' => count($vals) > 1

                    ? 'تم تسجيل الدخول بنجاح - ' . count($vals) . ' أطفال مرتبطين'

                    : 'تم تسجيل الدخول بنجاح'

            ]);

        } else {

            sendJSON([

                'success' => false,

                'message' => 'اسم المستخدم أو رقم الهاتف أو كلمة المرور غير صحيحة',

                'data' => []

            ]);

        }



    } catch (Exception $e) {

        error_log("❌ [kidLogin] Error: " . $e->getMessage());

        sendJSON(['success' => false, 'message' => 'خطأ في تسجيل الدخول: ' . $e->getMessage()]);

    }

}

function checkUsernameAvailable()

{

    try {

        $username = trim(sanitize($_POST['username'] ?? ''));

        if (empty($username)) {

            sendJSON(['available' => false, 'message' => 'اسم المستخدم مطلوب']);

            return;

        }

        if (!preg_match('/^[a-zA-Z0-9_]{3,30}$/', $username)) {

            sendJSON(['available' => false, 'message' => 'حروف إنجليزية وأرقام وشرطة سفلية فقط (3-30)']);

            return;

        }

        $conn = getDBConnection();



        // Check students table — username stored in custom_info JSON

        $s1 = $conn->prepare("SELECT id FROM students WHERE JSON_UNQUOTE(JSON_EXTRACT(custom_info, '$.username')) = ? LIMIT 1");

        if ($s1) {

            $s1->bind_param("s", $username);

            $s1->execute();

            if ($s1->get_result()->num_rows > 0) {

                sendJSON(['available' => false, 'message' => 'اسم المستخدم محجوز']);

                return;

            }

        }



        // Check pending_registrations

        $conn->query("ALTER TABLE pending_registrations ADD COLUMN IF NOT EXISTS username VARCHAR(100) DEFAULT NULL");

        $s2 = $conn->prepare("SELECT id FROM pending_registrations WHERE username = ? AND status = 'pending' LIMIT 1");

        if ($s2) {

            $s2->bind_param("s", $username);

            $s2->execute();

            if ($s2->get_result()->num_rows > 0) {

                sendJSON(['available' => false, 'message' => 'اسم المستخدم محجوز']);

                return;

            }

        }



        sendJSON(['available' => true, 'message' => 'اسم المستخدم متاح']);

    } catch (Exception $e) {

        sendJSON(['available' => false, 'message' => 'خطأ: ' . $e->getMessage()]);

    }

}



function getStudentProfile()

{

    try {

        $studentId = intval($_POST['studentId'] ?? $_GET['studentId'] ?? 0);



        if ($studentId === 0) {

            sendJSON(['success' => false, 'message' => 'معرف الطفل مطلوب']);

            return;

        }



        $conn = getDBConnection();



        $stmt = $conn->prepare("

            SELECT

                s.id, s.name, s.address, s.phone, s.birthday, s.email,

                s.coupons, s.attendance_coupons, s.commitment_coupons,

                s.task_coupons, s.image_url, s.church_id, s.class_id,

                s.custom_info, s.trip_points, s.gender, s.emergency_phone, s.medical_notes,

                c.church_name,

                COALESCE(cc.arabic_name, cl.arabic_name, s.class) AS class

            FROM students s

            LEFT JOIN churches c  ON s.church_id = c.id

            LEFT JOIN church_classes cc ON cc.id = s.class_id AND cc.church_id = s.church_id

            LEFT JOIN classes cl  ON cl.id = s.class_id

            WHERE s.id = ?

        ");

        $stmt->bind_param("i", $studentId);

        $stmt->execute();

        $result = $stmt->get_result();



        if ($row = $result->fetch_assoc()) {

            // تنسيق تاريخ الميلاد

            $row['birthday'] = formatDateFromDB($row['birthday']);

            $row['class'] = $row['class'] ?? '---';

            $tripPoints = [];
            $tripPointsDetails = [];
            if (!empty($row['trip_points'])) {
                $tripPoints = json_decode($row['trip_points'], true) ?: [];
            }
            if (!empty($tripPoints)) {
                $tripIds = array_map('intval', array_keys($tripPoints));
                if (!empty($tripIds)) {
                    $inPlaceholder = implode(',', $tripIds);
                    $tripStmt = $conn->prepare("SELECT id, title FROM trips WHERE id IN ($inPlaceholder)");
                    $tripStmt->execute();
                    $tripResult = $tripStmt->get_result();
                    while ($tRow = $tripResult->fetch_assoc()) {
                        $tId = intval($tRow['id']);
                        $tripPointsDetails[] = [
                            'id' => $tId,
                            'title' => $tRow['title'],
                            'points' => intval($tripPoints[$tId] ?? 0)
                        ];
                    }
                }
            }
            $row['trip_points_details'] = $tripPointsDetails;

            ensurePaperExamTables($conn);
            $examsStmt = $conn->prepare("
                SELECT pe.id, pe.name, pe.total_degree, pe.class_ids, pe.reference_url, ped.degree, ped.answers_picture, pe.created_at
                FROM paper_exams pe
                LEFT JOIN paper_exam_degrees ped ON pe.id = ped.paper_exam_id AND ped.student_id = ?
                WHERE pe.church_id = ?
                ORDER BY pe.created_at DESC
            ");
            $examsStmt->bind_param("ii", $studentId, $row['church_id']);
            $examsStmt->execute();
            $examsRes = $examsStmt->get_result();
            $paperExams = [];
            $studentClassId = intval($row['class_id']);
            if ($studentClassId === 0 && !empty($row['class']) && $row['class'] !== 'بدون فصل') {
                $cName = $row['class'];
                $cStmt = $conn->prepare("SELECT id FROM church_classes WHERE (arabic_name = ? OR code = ?) AND church_id = ?");
                if ($cStmt) {
                    $cStmt->bind_param("ssi", $cName, $cName, $row['church_id']);
                    $cStmt->execute();
                    $cRes = $cStmt->get_result()->fetch_assoc();
                    if ($cRes) {
                        $studentClassId = intval($cRes['id']);
                    } else {
                        $cStmt2 = $conn->prepare("SELECT id FROM classes WHERE arabic_name = ? OR code = ?");
                        if ($cStmt2) {
                            $cStmt2->bind_param("ss", $cName, $cName);
                            $cStmt2->execute();
                            $cRes2 = $cStmt2->get_result()->fetch_assoc();
                            if ($cRes2) {
                                $studentClassId = intval($cRes2['id']);
                            }
                            $cStmt2->close();
                        }
                    }
                    $cStmt->close();
                }
            }
            while ($exRow = $examsRes->fetch_assoc()) {
                $classIdsStr = trim($exRow['class_ids'] ?? '');
                $showExam = false;
                if ($classIdsStr === '') {
                    // Assigned to ALL classes
                    $showExam = true;
                } else {
                    $classIdsArr = explode(',', $classIdsStr);
                    if (in_array(strval($studentClassId), $classIdsArr)) {
                        $showExam = true;
                    }
                }
                if ($showExam) {
                    $paperExams[] = [
                        'id' => intval($exRow['id']),
                        'name' => $exRow['name'],
                        'total_degree' => floatval($exRow['total_degree']),
                        'reference_url' => $exRow['reference_url'],
                        'degree' => $exRow['degree'] !== null ? floatval($exRow['degree']) : null,
                        'answers_picture' => $exRow['answers_picture'],
                        'created_at' => $exRow['created_at']
                    ];
                }
            }
            $examsStmt->close();
            $row['paper_exams'] = $paperExams;

            sendJSON([

                'success' => true,

                'student' => $row,

                'user' => $row,

                'message' => 'تم تحميل الملف الشخصي'

            ]);

        } else {

            sendJSON([

                'success' => false,

                'message' => 'لم يتم العثور على الطفل'

            ]);

        }



    } catch (Exception $e) {

        error_log("getStudentProfile error: " . $e->getMessage());

        sendJSON(['success' => false, 'message' => 'خطأ في تحميل الملف الشخصي']);

    }
}

function ensurePaperExamTables($conn) {
    $conn->query("CREATE TABLE IF NOT EXISTS `paper_exams` (
        `id` int(11) NOT NULL AUTO_INCREMENT,
        `church_id` int(11) NOT NULL,
        `class_id` int(11) DEFAULT NULL,
        `class_ids` varchar(500) DEFAULT NULL,
        `name` varchar(255) NOT NULL,
        `total_degree` int(11) NOT NULL,
        `reference_url` varchar(500) DEFAULT NULL,
        `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
        `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
        PRIMARY KEY (`id`),
        KEY `church_id` (`church_id`),
        KEY `class_id` (`class_id`)
    ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci");

    $conn->query("CREATE TABLE IF NOT EXISTS `paper_exam_degrees` (
        `id` int(11) NOT NULL AUTO_INCREMENT,
        `paper_exam_id` int(11) NOT NULL,
        `student_id` int(11) NOT NULL,
        `degree` float DEFAULT NULL,
        `answers_picture` varchar(500) DEFAULT NULL,
        `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
        `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
        PRIMARY KEY (`id`),
        UNIQUE KEY `exam_student` (`paper_exam_id`, `student_id`),
        KEY `student_id` (`student_id`)
    ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci");

    // MySQL 5.7 safe column checks
    $checkCol = $conn->query("SHOW COLUMNS FROM `paper_exam_degrees` LIKE 'answers_picture'");
    if ($checkCol && $checkCol->num_rows === 0) {
        $conn->query("ALTER TABLE `paper_exam_degrees` ADD COLUMN `answers_picture` varchar(500) DEFAULT NULL AFTER `degree`");
    }

    $checkClassIds = $conn->query("SHOW COLUMNS FROM `paper_exams` LIKE 'class_ids'");
    if ($checkClassIds && $checkClassIds->num_rows === 0) {
        $conn->query("ALTER TABLE `paper_exams` ADD COLUMN `class_ids` varchar(500) DEFAULT NULL AFTER `class_id`");
    }

    $checkDeg = $conn->query("SHOW COLUMNS FROM `paper_exam_degrees` LIKE 'degree'");
    if ($checkDeg && $row = $checkDeg->fetch_assoc()) {
        if (strtoupper($row['Null']) === 'NO') {
            $conn->query("ALTER TABLE `paper_exam_degrees` MODIFY COLUMN `degree` float DEFAULT NULL");
        }
    }
}

function importPaperExamDegreesCSV() {
    checkAuth();
    $conn = getDBConnection();
    ensurePaperExamTables($conn);
    
    $churchId = getChurchId();
    $examId = intval($_POST['paper_exam_id'] ?? 0);
    
    if ($examId <= 0) {
        sendJSON(['success' => false, 'message' => 'معرف الامتحان مطلوب']);
    }
    
    // Check if exam exists
    $stmt = $conn->prepare("SELECT id, name, total_degree, church_id FROM paper_exams WHERE id = ?");
    $stmt->bind_param("i", $examId);
    $stmt->execute();
    $exam = $stmt->get_result()->fetch_assoc();
    $stmt->close();
    
    if (!$exam) {
        sendJSON(['success' => false, 'message' => "الامتحان غير موجود (معرف: {$examId})"]);
    }
    
    if (intval($exam['church_id']) !== $churchId) {
        sendJSON(['success' => false, 'message' => "الامتحان غير تابع لكنيستك (كنيسة الامتحان: {$exam['church_id']}، كنيسة الجلسة: {$churchId})"]);
    }
    
    if (!isset($_FILES['csv_file']) || $_FILES['csv_file']['error'] !== UPLOAD_ERR_OK) {
        sendJSON(['success' => false, 'message' => 'لم يتم رفع أي ملف']);
    }
    
    $fileTmpPath = $_FILES['csv_file']['tmp_name'];
    $file = fopen($fileTmpPath, 'r');
    if (!$file) {
        sendJSON(['success' => false, 'message' => 'فشل فتح الملف']);
    }
    
    // Detect UTF-8 BOM
    $bom = fread($file, 3);
    if ($bom !== "\xEF\xBB\xBF") {
        rewind($file);
    }
    
    // Read header row
    $headerRow = fgetcsv($file);
    if (!$headerRow) {
        fclose($file);
        sendJSON(['success' => false, 'message' => 'ملف CSV فارغ']);
    }
    
    // Normalize headers
    $headers = array_map(function ($h) {
        $cleaned = trim(str_replace('"', '', $h));
        $cleaned = str_replace("\xEF\xBB\xBF", "", $cleaned);
        return mb_strtolower($cleaned, 'UTF-8');
    }, $headerRow);
    
    $colId = false;
    $colName = false;
    $colDegree = false;
    
    foreach ($headers as $idx => $header) {
        if (in_array($header, ['id', 'student_id', 'معرف', 'كود', 'معرف الطفل'])) {
            $colId = $idx;
        } elseif (in_array($header, ['name', 'الاسم', 'الاسم كامل', 'اسم الطفل'])) {
            $colName = $idx;
        } elseif (in_array($header, ['degree', 'الدرجة', 'درجة', 'النتيجة', 'الدرجه'])) {
            $colDegree = $idx;
        }
    }
    
    // Fallbacks
    if ($colId === false && count($headers) > 0) {
        if (strpos($headers[0], 'id') !== false || strpos($headers[0], 'معرف') !== false) {
            $colId = 0;
        }
    }
    if ($colName === false && count($headers) > 1) {
        if (strpos($headers[1], 'الاسم') !== false || strpos($headers[1], 'name') !== false) {
            $colName = 1;
        }
    }
    if ($colDegree === false && count($headers) > 2) {
        if (strpos($headers[2], 'درجة') !== false || strpos($headers[2], 'degree') !== false) {
            $colDegree = 2;
        }
    }
    
    if ($colDegree === false) {
        if (count($headers) >= 2) {
            $colDegree = count($headers) - 1;
        } else {
            fclose($file);
            sendJSON(['success' => false, 'message' => 'تعذر تحديد عمود الدرجة في الملف. يرجى كتابة رأس العمود باسم "الالدرجة"']);
        }
    }
    
    if ($colId === false && $colName === false) {
        fclose($file);
        sendJSON(['success' => false, 'message' => 'تعذر تحديد عمود معرف الطفل أو اسمه. يرجى كتابة رأس العمود باسم "الاسم" أو "id"']);
    }
    
    // Get students for mapping
    $studentsList = [];
    if ($colName !== false) {
        $stmtStu = $conn->prepare("SELECT id, name FROM students WHERE church_id = ?");
        $stmtStu->bind_param("i", $churchId);
        $stmtStu->execute();
        $resStu = $stmtStu->get_result();
        while ($sRow = $resStu->fetch_assoc()) {
            $studentsList[normalizeArabicNamePHP($sRow['name'])] = intval($sRow['id']);
        }
        $stmtStu->close();
    }
    
    $importedCount = 0;
    $errors = [];
    $rowNum = 1;
    
    while (($row = fgetcsv($file)) !== false) {
        $rowNum++;
        if (empty($row) || (count($row) === 1 && empty($row[0]))) {
            continue;
        }
        
        $studentId = null;
        $studentName = '';
        
        if ($colId !== false && isset($row[$colId]) && trim($row[$colId]) !== '') {
            $candidateId = intval(trim($row[$colId]));
            $stmtCheck = $conn->prepare("SELECT id FROM students WHERE id = ? AND church_id = ?");
            $stmtCheck->bind_param("ii", $candidateId, $churchId);
            $stmtCheck->execute();
            $checkRes = $stmtCheck->get_result()->fetch_assoc();
            $stmtCheck->close();
            if ($checkRes) {
                $studentId = $candidateId;
            }
        }
        
        if (!$studentId && $colName !== false && isset($row[$colName]) && trim($row[$colName]) !== '') {
            $studentName = trim($row[$colName]);
            $normName = normalizeArabicNamePHP($studentName);
            if (isset($studentsList[$normName])) {
                $studentId = $studentsList[$normName];
            } else {
                $found = false;
                foreach ($studentsList as $cachedName => $cachedId) {
                    if (strpos($cachedName, $normName) !== false || strpos($normName, $cachedName) !== false) {
                        $studentId = $cachedId;
                        $found = true;
                        break;
                    }
                }
                if (!$found) {
                    $errors[] = "السطر $rowNum: لم يتم العثور على طفل باسم '$studentName'";
                    continue;
                }
            }
        }
        
        if (!$studentId) {
            $errors[] = "السطر $rowNum: لم يتم العثور على طفل مطابق";
            continue;
        }
        
        $degreeVal = null;
        if ($colDegree !== false && isset($row[$colDegree]) && trim($row[$colDegree]) !== '') {
            $rawDegree = trim($row[$colDegree]);
            if (is_numeric($rawDegree)) {
                $degreeVal = floatval($rawDegree);
            }
        }
        
        if ($degreeVal === null) {
            $errors[] = "السطر $rowNum: الدرجة فارغة أو غير صالحة";
            continue;
        }
        
        if ($degreeVal > $exam['total_degree'] || $degreeVal < 0) {
            $errors[] = "السطر $rowNum: الدرجة ($degreeVal) تجاوزت الحد الكلي ({$exam['total_degree']})";
            continue;
        }
        
        $stmtSave = $conn->prepare("
            INSERT INTO paper_exam_degrees (paper_exam_id, student_id, degree)
            VALUES (?, ?, ?)
            ON DUPLICATE KEY UPDATE degree = VALUES(degree)
        ");
        $stmtSave->bind_param("iid", $examId, $studentId, $degreeVal);
        $stmtSave->execute();
        $stmtSave->close();
        
        $importedCount++;
    }
    
    fclose($file);
    
    $msg = "تم استيراد $importedCount درجات بنجاح.";
    if (!empty($errors)) {
        $msg .= " (تنبيهات: " . implode(", ", array_slice($errors, 0, 3));
        if (count($errors) > 3) {
            $msg .= " وأخرى";
        }
        $msg .= ")";
    }
    
    sendJSON([
        'success' => true,
        'message' => $msg,
        'imported_count' => $importedCount,
        'errors' => $errors
    ]);
}

function getPaperExams() {
    checkAuth();
    $conn = getDBConnection();
    ensurePaperExamTables($conn);
    $churchId = getChurchId();

    $stmt = $conn->prepare("
        SELECT pe.id, pe.name, pe.total_degree, pe.class_id, pe.class_ids, pe.reference_url, pe.created_at,
               COALESCE(cc.arabic_name, cl.arabic_name) AS class_name
        FROM paper_exams pe
        LEFT JOIN church_classes cc ON cc.id = pe.class_id AND cc.church_id = pe.church_id
        LEFT JOIN classes cl ON cl.id = pe.class_id
        WHERE pe.church_id = ?
        ORDER BY pe.created_at DESC
    ");
    $stmt->bind_param("i", $churchId);
    $stmt->execute();
    $res = $stmt->get_result();
    $exams = [];
    while ($row = $res->fetch_assoc()) {
        $exams[] = [
            'id' => intval($row['id']),
            'name' => $row['name'],
            'total_degree' => floatval($row['total_degree']),
            'class_id' => $row['class_id'] !== null ? intval($row['class_id']) : null,
            'class_ids' => $row['class_ids'],
            'class_name' => $row['class_name'] ?? 'كل الفصول',
            'reference_url' => $row['reference_url'],
            'created_at' => $row['created_at']
        ];
    }
    $stmt->close();
    sendJSON(['success' => true, 'exams' => $exams]);
}

function savePaperExam() {
    checkAuth();
    $conn = getDBConnection();
    ensurePaperExamTables($conn);

    $churchId = getChurchId();
    $id = intval($_POST['id'] ?? 0);
    $classId = isset($_POST['class_id']) && $_POST['class_id'] !== '' ? intval($_POST['class_id']) : null;
    $classIds = isset($_POST['class_ids']) ? trim($_POST['class_ids']) : null;
    $name = trim($_POST['name'] ?? '');
    $totalDegree = intval($_POST['total_degree'] ?? 0);

    if (empty($name) || $totalDegree <= 0) {
        sendJSON(['success' => false, 'message' => 'الرجاء إدخال اسم الامتحان والدرجة الكلية']);
    }

    $referenceUrl = null;
    if (isset($_FILES['reference_file']) && $_FILES['reference_file']['error'] === UPLOAD_ERR_OK) {
        $file = $_FILES['reference_file'];
        $allowedTypes = ['image/jpeg', 'image/png', 'image/gif', 'image/webp', 'application/pdf', 'application/msword', 'application/vnd.openxmlformats-officedocument.wordprocessingml.document'];
        $fileType = mime_content_type($file['tmp_name']);
        if (!in_array($fileType, $allowedTypes)) {
            sendJSON(['success' => false, 'message' => 'نوع الملف غير مدعوم. المسموح به: صور، PDF، Word']);
        }
        $uploadDir = __DIR__ . '/uploads/exams/';
        if (!is_dir($uploadDir)) {
            mkdir($uploadDir, 0755, true);
        }
        $ext = pathinfo($file['name'], PATHINFO_EXTENSION);
        $filename = "exam_" . time() . "_" . bin2hex(random_bytes(4)) . "." . $ext;
        if (move_uploaded_file($file['tmp_name'], $uploadDir . $filename)) {
            $baseUrl = 'https://' . $_SERVER['HTTP_HOST'];
            $referenceUrl = $baseUrl . '/uploads/exams/' . $filename;
        } else {
            sendJSON(['success' => false, 'message' => 'فشل في حفظ الملف المرفوع']);
        }
    }

    if ($id > 0) {
        if ($referenceUrl !== null) {
            // Delete all written student degrees for this exam so they can start again
            $delDeg = $conn->prepare("DELETE FROM paper_exam_degrees WHERE paper_exam_id = ?");
            $delDeg->bind_param("i", $id);
            $delDeg->execute();
            $delDeg->close();

            $stmt = $conn->prepare("UPDATE paper_exams SET name = ?, total_degree = ?, class_id = ?, class_ids = ?, reference_url = ? WHERE id = ? AND church_id = ?");
            $stmt->bind_param("siissii", $name, $totalDegree, $classId, $classIds, $referenceUrl, $id, $churchId);
        } else {
            $stmt = $conn->prepare("UPDATE paper_exams SET name = ?, total_degree = ?, class_id = ?, class_ids = ? WHERE id = ? AND church_id = ?");
            $stmt->bind_param("siisii", $name, $totalDegree, $classId, $classIds, $id, $churchId);
        }
        $stmt->execute();
        $stmt->close();
        if (function_exists('writeAuditLog')) {
            writeAuditLog('exam_edit', 'exam', $id, $name, null, null, "تعديل امتحان ورقي: " . $name);
        }
        $msg = $referenceUrl !== null ? 'تم تعديل الامتحان وحذف جميع درجات الطلاب السابقة بنجاح' : 'تم تعديل الامتحان بنجاح';
        sendJSON(['success' => true, 'message' => $msg, 'id' => $id]);
    } else {
        $stmt = $conn->prepare("INSERT INTO paper_exams (church_id, class_id, class_ids, name, total_degree, reference_url) VALUES (?, ?, ?, ?, ?, ?)");
        $stmt->bind_param("iissis", $churchId, $classId, $classIds, $name, $totalDegree, $referenceUrl);
        $stmt->execute();
        $newId = $stmt->insert_id;
        $stmt->close();
        if (function_exists('writeAuditLog')) {
            writeAuditLog('exam_add', 'exam', $newId, $name, null, null, "إضافة امتحان ورقي جديد: " . $name);
        }
        sendJSON(['success' => true, 'message' => 'تم إضافة الامتحان بنجاح', 'id' => $newId]);
    }
}

function deletePaperExam() {
    checkAuth();
    $conn = getDBConnection();
