                        'type' => strip_tags(trim($fieldMeta['type'] ?? 'choices')),

                        'choices' => array_values(array_filter(

                            array_map(

                                function ($c) {

                                    return strip_tags(trim((string) $c));

                                },

                                is_array($fieldMeta['choices'] ?? null) ? $fieldMeta['choices'] : []

                            ),

                            function ($c) {

                                return $c !== '';

                            }

                        )),

                    ];

