    } catch (Exception $e) {

        error_log('exportGraduateStudent: ' . $e->getMessage());

        sendJSON(['success' => false, 'message' => 'خطأ في التصدير']);

    }

}



function sendGraduateToChurch()

{

    try {

        checkAuth();

        $churchId = getChurchId();

        $studentId = intval($_POST['studentId'] ?? 0);

        $toChurchCode = sanitize($_POST['to_church_code'] ?? '');



        if (!$churchId || !$studentId || empty($toChurchCode)) {

            sendJSON(['success' => false, 'message' => 'بيانات غير كاملة']);

            return;

        }



        $conn = getDBConnection();

        ensureStudentGraduateSchema($conn);



        $stmt = $conn->prepare("SELECT * FROM students WHERE id = ? AND church_id = ? AND enrollment_status = 'graduate' LIMIT 1");

        $stmt->bind_param("ii", $studentId, $churchId);

        $stmt->execute();

        $student = $stmt->get_result()->fetch_assoc();

        if (!$student) {

            sendJSON(['success' => false, 'message' => 'الطفل غير موجود في قسم الخريجين']);

            return;

        }



        $cStmt = $conn->prepare("SELECT id, church_name FROM churches WHERE church_code = ? LIMIT 1");

        $cStmt->bind_param("s", $toChurchCode);

        $cStmt->execute();

        $toChurch = $cStmt->get_result()->fetch_assoc();

        if (!$toChurch) {

            sendJSON(['success' => false, 'message' => 'رمز الكنيسة غير صحيح']);

            return;

        }

        $toChurchId = (int) $toChurch['id'];

        if ($toChurchId === $churchId) {

            sendJSON(['success' => false, 'message' => 'لا يمكن الإرسال لنفس الكنيسة']);

            return;

        }



        $dup = $conn->prepare("

            SELECT id FROM student_transfer_requests

            WHERE from_student_id = ? AND to_church_id = ? AND status = 'pending' LIMIT 1

        ");

        $dup->bind_param("ii", $studentId, $toChurchId);

        $dup->execute();

        if ($dup->get_result()->num_rows > 0) {

            sendJSON(['success' => false, 'message' => 'يوجد طلب معلق بالفعل لهذا الطفل']);

            return;

        }



        unset($student['password_hash']);

        $snapshotJson = json_encode($student, JSON_UNESCAPED_UNICODE);

        $studentName = $student['name'] ?? '';



        $conn->begin_transaction();

        $ins = $conn->prepare("

            INSERT INTO student_transfer_requests

                (from_church_id, to_church_id, from_student_id, student_name, student_snapshot, status)

            VALUES (?, ?, ?, ?, ?, 'pending')

        ");

        $ins->bind_param("iiiss", $churchId, $toChurchId, $studentId, $studentName, $snapshotJson);

        if (!$ins->execute()) {

            $conn->rollback();

            sendJSON(['success' => false, 'message' => 'فشل إنشاء طلب النقل']);

            return;

        }



        if (!removeStudentFromChurch($conn, $studentId, $churchId)) {

            $conn->rollback();

            sendJSON(['success' => false, 'message' => 'فشل إزالة سجل الخريج']);

            return;

        }



        $conn->commit();

        writeAuditLog('graduate_transfer_send', 'students', $studentId, $studentName, null, null, 'to:' . $toChurch['church_name']);

        sendJSON([

            'success' => true,

            'message' => 'تم إرسال الطلب إلى ' . $toChurch['church_name'] . ' — بانتظار الموافقة',

        ]);

    } catch (Exception $e) {

        if (isset($conn))

            $conn->rollback();

        error_log('sendGraduateToChurch: ' . $e->getMessage());

        sendJSON(['success' => false, 'message' => 'خطأ في إرسال الطلب']);

    }

}



function respondGraduateTransfer()

{

    try {

        checkAuth();

        $churchId = getChurchId();

        $requestId = intval($_POST['request_id'] ?? 0);

        $decision = sanitize($_POST['decision'] ?? '');

        $classId = intval($_POST['class_id'] ?? 0);



        if (!$churchId || !$requestId || !in_array($decision, ['accept', 'reject'], true)) {

            sendJSON(['success' => false, 'message' => 'بيانات غير صالحة']);

            return;

        }



        $conn = getDBConnection();

        ensureStudentGraduateSchema($conn);



        $rStmt = $conn->prepare("

            SELECT * FROM student_transfer_requests

            WHERE id = ? AND to_church_id = ? AND status = 'pending' LIMIT 1

        ");

        $rStmt->bind_param("ii", $requestId, $churchId);

        $rStmt->execute();

        $req = $rStmt->get_result()->fetch_assoc();

        if (!$req) {

            sendJSON(['success' => false, 'message' => 'الطلب غير موجود أو تمت معالجته']);

            return;

        }



        if ($decision === 'reject') {

            $upd = $conn->prepare("UPDATE student_transfer_requests SET status = 'rejected', updated_at = NOW() WHERE id = ?");

            $upd->bind_param("i", $requestId);

            $upd->execute();

            writeAuditLog('graduate_transfer_reject', 'students', $requestId, $req['student_name'] ?? '');

            sendJSON(['success' => true, 'message' => 'تم رفض طلب النقل']);

            return;

        }



        if ($classId <= 0) {

            $classId = getFirstClassIdForChurch($churchId);

        }

        if ($classId <= 0) {

            sendJSON(['success' => false, 'message' => 'لا توجد فصول في الكنيسة — أضف فصلاً أولاً']);

            return;

        }



        $snapshot = json_decode($req['student_snapshot'], true);

        if (!is_array($snapshot) || empty($snapshot['name'])) {

            sendJSON(['success' => false, 'message' => 'بيانات الطفل غير صالحة']);

            return;

        }



        $className = '';

        $hasCustom = $conn->prepare("SELECT arabic_name FROM church_classes WHERE id = ? AND church_id = ? AND is_active = 1");

        $hasCustom->bind_param("ii", $classId, $churchId);

        $hasCustom->execute();

        if ($cr = $hasCustom->get_result()->fetch_assoc()) {

            $className = $cr['arabic_name'];

        } else {

            $g = $conn->prepare("SELECT arabic_name FROM classes WHERE id = ?");

            $g->bind_param("i", $classId);

            $g->execute();

            if ($gr = $g->get_result()->fetch_assoc()) {

                $className = $gr['arabic_name'];

            }

        }



        $name = sanitize($snapshot['name']);

        $gender = in_array($snapshot['gender'] ?? '', ['male', 'female'], true) ? $snapshot['gender'] : 'male';

        $phone = sanitize($snapshot['phone'] ?? '');

        $address = sanitize($snapshot['address'] ?? '');

        $emergency = sanitize($snapshot['emergency_phone'] ?? '');

        $medical = sanitize($snapshot['medical_notes'] ?? '');

        $birthday = !empty($snapshot['birthday']) ? $snapshot['birthday'] : null;

        $customInfo = !empty($snapshot['custom_info']) ? $snapshot['custom_info'] : null;

        $imageUrl = $snapshot['image_url'] ?? null;

        $coupons = intval($snapshot['coupons'] ?? 0);

        $attC = intval($snapshot['attendance_coupons'] ?? 0);

        $comC = intval($snapshot['commitment_coupons'] ?? 0);

        $taskC = intval($snapshot['task_coupons'] ?? 0);



        $conn->begin_transaction();

        $addedByType = 'transfer';
        $ins = $conn->prepare("

            INSERT INTO students

                (church_id, name, gender, class_id, class, address, phone, emergency_phone,

                 medical_notes, birthday, coupons, attendance_coupons, commitment_coupons,

                 task_coupons, image_url, custom_info, enrollment_status, added_by)

            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 'active', ?)

        ");

        $ins->bind_param(

            "ississssssiiiisss",

            $churchId,

            $name,

            $gender,

            $classId,

            $className,

            $address,

            $phone,

            $emergency,

            $medical,

            $birthday,

            $coupons,

            $attC,

            $comC,

            $taskC,

            $imageUrl,

            $customInfo,

            $addedByType

        );

        if (!$ins->execute()) {

            $conn->rollback();

            sendJSON(['success' => false, 'message' => 'فشل إضافة الطفل: ' . $ins->error]);

            return;

        }

        $newStudentId = (int) $conn->insert_id;



        $upd = $conn->prepare("

            UPDATE student_transfer_requests

            SET status = 'accepted', target_class_id = ?, accepted_student_id = ?, updated_at = NOW()

            WHERE id = ?

        ");

        $upd->bind_param("iii", $classId, $newStudentId, $requestId);

        $upd->execute();



        $conn->commit();

        writeAuditLog('graduate_transfer_accept', 'students', $newStudentId, $name, null, null, 'class:' . $className);

        sendJSON([

            'success' => true,

            'message' => 'تم قبول الطفل وإضافته إلى ' . ($className ?: 'الفصل المحدد'),

            'student_id' => $newStudentId,

        ]);

    } catch (Exception $e) {

        if (isset($conn))

            $conn->rollback();

        error_log('respondGraduateTransfer: ' . $e->getMessage());

        sendJSON(['success' => false, 'message' => 'خطأ في معالجة الطلب']);

    }

}



// ===== CHURCH SETTINGS (attendance day + combined class + more) =====



/**

 * Ensure the church_settings table exists with all needed columns.

 */

function ensureChurchSettingsTable($conn)

{

    $conn->query("

        CREATE TABLE IF NOT EXISTS `church_settings` (

            `id`                     INT AUTO_INCREMENT PRIMARY KEY,

            `church_id`              INT NOT NULL UNIQUE,

            `attendance_day`         TINYINT NOT NULL DEFAULT 5

                                     COMMENT '1=Mon 2=Tue 3=Wed 4=Thu 5=Fri 6=Sat 7=Sun',

            `uncle_class_navigation` VARCHAR(10) NOT NULL DEFAULT 'all'

                                     COMMENT 'all | own',

            `combined_class_groups`  TEXT DEFAULT NULL

                                     COMMENT 'JSON array of {label, classes[]} groups',

            `custom_field`           TEXT DEFAULT NULL

                                     COMMENT 'JSON {name,icon} — one custom info field per church',

            `view_mode`              VARCHAR(10) NOT NULL DEFAULT 'classes'

                                     COMMENT 'classes | all | both',

            `coupons_enabled`        TINYINT NOT NULL DEFAULT 1

                                     COMMENT '0=disabled, 1=enabled',

            `coupons_count`          INT NOT NULL DEFAULT 100

                                     COMMENT 'number of coupons awarded on attendance',

            `coupon_presets`         VARCHAR(255) NOT NULL DEFAULT '10,30,50,100'

                                     COMMENT 'comma separated quick coupon adjustment values',

            `allowed_view_uncles`    TEXT DEFAULT NULL

                                     COMMENT 'comma separated usernames allowed to view uncles view',

            `uncle_fees_enabled`     TINYINT NOT NULL DEFAULT 1

                                     COMMENT '0=disabled, 1=enabled',

            `updated_at`             TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP

        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci

    ");

    // Safe migrations for existing installs

    $conn->query("ALTER TABLE church_settings ADD COLUMN IF NOT EXISTS

        `custom_field` TEXT DEFAULT NULL

        COMMENT 'JSON {name,icon} — one custom info field per church'");

    $conn->query("ALTER TABLE church_settings ADD COLUMN IF NOT EXISTS

        `view_mode` VARCHAR(10) NOT NULL DEFAULT 'classes'

        COMMENT 'classes | all | both'");

    $conn->query("ALTER TABLE church_settings ADD COLUMN IF NOT EXISTS

        `coupons_enabled` TINYINT NOT NULL DEFAULT 1

        COMMENT '0=disabled, 1=enabled'");

    $conn->query("ALTER TABLE church_settings ADD COLUMN IF NOT EXISTS

        `coupons_count` INT NOT NULL DEFAULT 100

        COMMENT 'number of coupons awarded on attendance'");

    $conn->query("ALTER TABLE church_settings ADD COLUMN IF NOT EXISTS

        `coupon_presets` VARCHAR(255) NOT NULL DEFAULT '10,30,50,100'

        COMMENT 'comma separated quick coupon adjustment values'");

    $conn->query("ALTER TABLE church_settings ADD COLUMN IF NOT EXISTS

        `allowed_view_uncles` TEXT DEFAULT NULL

        COMMENT 'comma separated usernames allowed to view uncles view'");

    $conn->query("ALTER TABLE church_settings ADD COLUMN IF NOT EXISTS

        `uncle_fees_enabled` TINYINT NOT NULL DEFAULT 1

        COMMENT '0=disabled, 1=enabled'");

    ensureChurchSettingsAutoGradeColumns($conn);

}



function getChurchSettings()

{

    try {

        $churchId = getChurchId();

        if (!$churchId) {

            sendJSON(['success' => true, 'settings' => getDefaultChurchSettings()]);

            return;

        }

        $conn = getDBConnection();

        ensureChurchSettingsTable($conn);



        $stmt = $conn->prepare("SELECT * FROM church_settings WHERE church_id = ?");

        $stmt->bind_param("i", $churchId);

        $stmt->execute();

        $row = $stmt->get_result()->fetch_assoc();



        if (!$row) {

            // Auto-create default row

            $conn->prepare("INSERT IGNORE INTO church_settings (church_id) VALUES (?)")

                ->bind_param("i", $churchId);

            $conn->query("INSERT IGNORE INTO church_settings (church_id) VALUES ($churchId)");

            $row = ['church_id' => $churchId] + getDefaultChurchSettings();

        }



        $rawCf = !empty($row['custom_field']) ? json_decode($row['custom_field'], true) : null;

        // Normalize: always return array of field objects or null

        $customFields = null;

        if (is_array($rawCf)) {

            if (isset($rawCf[0]) && is_array($rawCf[0])) {

                $customFields = $rawCf; // already an array

            } elseif (!empty($rawCf['name'])) {

                $customFields = [$rawCf]; // wrap single object in array

            }

        }



        $settings = [

            'attendance_day' => (int) ($row['attendance_day'] ?? 5),

            'uncle_class_navigation' => $row['uncle_class_navigation'] ?? 'all',

            'combined_class_groups' => $row['combined_class_groups']

                ? json_decode($row['combined_class_groups'], true) ?? []

                : [],

            'custom_field' => $customFields,

            'custom_fields' => $customFields, // alias for clarity

            'view_mode' => $row['view_mode'] ?? 'classes',

            'auto_kids_approval' => false, // will be overridden below

            'auto_grade_month' => isset($row['auto_grade_month']) ? (int) $row['auto_grade_month'] : null,

            'auto_grade_day' => isset($row['auto_grade_day']) ? (int) $row['auto_grade_day'] : null,

            'last_auto_grade_year' => isset($row['last_auto_grade_year']) ? (int) $row['last_auto_grade_year'] : null,

            'coupons_enabled' => isset($row['coupons_enabled']) ? (int) $row['coupons_enabled'] : 1,

            'coupons_count' => isset($row['coupons_count']) ? (int) $row['coupons_count'] : 100,

            'coupon_presets' => $row['coupon_presets'] ?? '10,30,50,100',

            'allowed_view_uncles' => $row['allowed_view_uncles'] ?? '',

            'uncle_fees_enabled' => isset($row['uncle_fees_enabled']) ? (int) $row['uncle_fees_enabled'] : 1,

        ];



        // Load auto_kids_approval from churches.settings JSON

        $csStmt = $conn->prepare("SELECT settings FROM churches WHERE id = ? LIMIT 1");

        $csStmt->bind_param("i", $churchId);

        $csStmt->execute();

        $csRow = $csStmt->get_result()->fetch_assoc();

        if ($csRow && !empty($csRow['settings'])) {

            $cs = json_decode($csRow['settings'], true);

            $settings['auto_kids_approval'] = !empty($cs['auto_kids_approval']);

        }

        $settings['church_id'] = $churchId;
        $nameStmt = $conn->prepare("SELECT church_name FROM churches WHERE id = ? LIMIT 1");
        $nameStmt->bind_param("i", $churchId);
        $nameStmt->execute();
        $nameRow = $nameStmt->get_result()->fetch_assoc();
        $settings['church_name'] = $nameRow['church_name'] ?? '';

        sendJSON(['success' => true, 'settings' => $settings]);

    } catch (Exception $e) {

        error_log("getChurchSettings error: " . $e->getMessage());

        sendJSON(['success' => true, 'settings' => getDefaultChurchSettings()]);

    }

}



function getDefaultChurchSettings(): array

{

    return [

        'attendance_day' => 5,

        'uncle_class_navigation' => 'all',

        'combined_class_groups' => [],

        'custom_field' => null,

        'view_mode' => 'classes',

        'auto_grade_month' => null,

        'auto_grade_day' => null,

        'last_auto_grade_year' => null,

        'coupons_enabled' => 1,

        'coupons_count' => 100,

        'coupon_presets' => '10,30,50,100',

        'allowed_view_uncles' => '',

        'uncle_fees_enabled' => 1,

    ];

}



function saveChurchSettings()

{

    try {

        $churchId = getChurchId();

        if (!$churchId) {

            sendJSON(['success' => false, 'message' => 'معرف الكنيسة مطلوب']);

            return;

        }

        $conn = getDBConnection();

        ensureChurchSettingsTable($conn);



        $attendanceDay = intval($_POST['attendance_day'] ?? 5);

        $uncleClassNav = sanitize($_POST['uncle_class_navigation'] ?? 'all');

        $combinedGroupsRaw = $_POST['combined_class_groups'] ?? '[]';

        $customFieldRaw = $_POST['custom_field'] ?? '';

        $viewMode = sanitize($_POST['view_mode'] ?? 'classes');

        $autoKidsApproval = !empty($_POST['auto_kids_approval']) && $_POST['auto_kids_approval'] === '1';

        $hasAutoGradeFields = array_key_exists('auto_grade_month', $_POST)

            || array_key_exists('auto_grade_day', $_POST);

        $autoGradeMonth = null;

        $autoGradeDay = null;

        if ($hasAutoGradeFields) {

            $autoGradeMonthRaw = $_POST['auto_grade_month'] ?? '';

            $autoGradeDayRaw = $_POST['auto_grade_day'] ?? '';

            $autoGradeMonth = ($autoGradeMonthRaw === '' || $autoGradeMonthRaw === '0')

                ? null : max(1, min(12, intval($autoGradeMonthRaw)));

            $autoGradeDay = ($autoGradeDayRaw === '' || $autoGradeDayRaw === '0')

                ? null : max(1, min(31, intval($autoGradeDayRaw)));

        }



        // Validate

        if ($attendanceDay < 1 || $attendanceDay > 7)

            $attendanceDay = 5;

        if (!in_array($uncleClassNav, ['all', 'own']))

            $uncleClassNav = 'all';

        if (!in_array($viewMode, ['classes', 'all', 'both']))

            $viewMode = 'classes';



        $combinedGroups = json_decode($combinedGroupsRaw, true);

        if (!is_array($combinedGroups))

            $combinedGroups = [];

        $combinedGroupsJson = json_encode($combinedGroups, JSON_UNESCAPED_UNICODE);



        // Validate custom fields: supports either a single {name,icon} object OR an array of them

        $customFieldJson = null;

        if (!empty($customFieldRaw)) {

            $cf = json_decode($customFieldRaw, true);

            if (is_array($cf)) {

                // Array of fields: [{name,icon}, ...]

                if (isset($cf[0]) && is_array($cf[0])) {

                    $cleaned = [];

                    foreach ($cf as $i => $field) {

                        if (!empty($field['name'])) {

                            // Assign a stable key if not already set — based on index

                            $stableKey = !empty($field['key']) ? sanitize($field['key']) : ('field_' . $i);

                            $cleaned[] = [

                                'name' => mb_substr(sanitize($field['name']), 0, 50),

                                'icon' => sanitize($field['icon'] ?? 'fa-info-circle'),

                                'key' => $stableKey,

                            ];

                        }

                    }

                    if (!empty($cleaned)) {

                        $customFieldJson = json_encode($cleaned, JSON_UNESCAPED_UNICODE);

                    }

                    // Single field object: {name, icon}

                } elseif (!empty($cf['name'])) {

                    $stableKey = !empty($cf['key']) ? sanitize($cf['key']) : 'field_0';

                    $cleaned = [

                        'name' => mb_substr(sanitize($cf['name']), 0, 50),

                        'icon' => sanitize($cf['icon'] ?? 'fa-info-circle'),

                        'key' => $stableKey,

                    ];

                    $customFieldJson = json_encode([$cleaned], JSON_UNESCAPED_UNICODE);

                }

            }

        }



        $couponsEnabled = isset($_POST['coupons_enabled']) ? intval($_POST['coupons_enabled']) : 1;

        $couponsCount = isset($_POST['coupons_count']) ? intval($_POST['coupons_count']) : 100;

        $couponPresets = sanitize($_POST['coupon_presets'] ?? '10,30,50,100');

        $allowedViewUncles = sanitize($_POST['allowed_view_uncles'] ?? '');

        $uncleFeesEnabled = isset($_POST['uncle_fees_enabled']) ? intval($_POST['uncle_fees_enabled']) : 1;

        if ($hasAutoGradeFields) {

            $stmt = $conn->prepare("

                INSERT INTO church_settings

                    (church_id, attendance_day, uncle_class_navigation, combined_class_groups, custom_field, view_mode,

                     auto_grade_month, auto_grade_day, coupons_enabled, coupons_count, coupon_presets, allowed_view_uncles, uncle_fees_enabled)

                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)

                ON DUPLICATE KEY UPDATE

                    attendance_day         = VALUES(attendance_day),

                    uncle_class_navigation = VALUES(uncle_class_navigation),

                    combined_class_groups  = VALUES(combined_class_groups),

                    custom_field           = VALUES(custom_field),

                    view_mode              = VALUES(view_mode),

                    auto_grade_month       = VALUES(auto_grade_month),

                    auto_grade_day         = VALUES(auto_grade_day),

                    coupons_enabled        = VALUES(coupons_enabled),

                    coupons_count          = VALUES(coupons_count),

                    coupon_presets         = VALUES(coupon_presets),

                    allowed_view_uncles    = VALUES(allowed_view_uncles),

                    uncle_fees_enabled     = VALUES(uncle_fees_enabled),

                    updated_at             = NOW()

            ");

            $stmt->bind_param(

                "iissssiiiissi",

                $churchId,

                $attendanceDay,

                $uncleClassNav,

                $combinedGroupsJson,

                $customFieldJson,

                $viewMode,

                $autoGradeMonth,

                $autoGradeDay,

                $couponsEnabled,

                $couponsCount,

                $couponPresets,

                $allowedViewUncles,

                $uncleFeesEnabled

            );

        } else {

            $stmt = $conn->prepare("

                INSERT INTO church_settings

                    (church_id, attendance_day, uncle_class_navigation, combined_class_groups, custom_field, view_mode,

                     coupons_enabled, coupons_count, coupon_presets, allowed_view_uncles, uncle_fees_enabled)

                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)

                ON DUPLICATE KEY UPDATE

                    attendance_day         = VALUES(attendance_day),

                    uncle_class_navigation = VALUES(uncle_class_navigation),

                    combined_class_groups  = VALUES(combined_class_groups),

                    custom_field           = VALUES(custom_field),

                    view_mode              = VALUES(view_mode),

                    coupons_enabled        = VALUES(coupons_enabled),

                    coupons_count          = VALUES(coupons_count),

                    coupon_presets         = VALUES(coupon_presets),

                    allowed_view_uncles    = VALUES(allowed_view_uncles),

                    uncle_fees_enabled     = VALUES(uncle_fees_enabled),

                    updated_at             = NOW()

            ");

            $stmt->bind_param(

                "iissssiissi",

                $churchId,

                $attendanceDay,

                $uncleClassNav,

                $combinedGroupsJson,

                $customFieldJson,

                $viewMode,

                $couponsEnabled,

                $couponsCount,

                $couponPresets,

                $allowedViewUncles,

                $uncleFeesEnabled

            );

        }



        if ($stmt->execute()) {

            if ($hasAutoGradeFields && ($autoGradeMonth === null || $autoGradeDay === null)) {

                $clr = $conn->prepare("

                    UPDATE church_settings

                    SET auto_grade_month = NULL, auto_grade_day = NULL

                    WHERE church_id = ?

                ");

                $clr->bind_param("i", $churchId);

                $clr->execute();

            }

            // Save auto_kids_approval in churches.settings JSON

            $csStmt2 = $conn->prepare("SELECT settings FROM churches WHERE id = ? LIMIT 1");

            $csStmt2->bind_param("i", $churchId);

            $csStmt2->execute();

            $csRow2 = $csStmt2->get_result()->fetch_assoc();

            $existingSettings = [];

            if ($csRow2 && !empty($csRow2['settings'])) {

                $existingSettings = json_decode($csRow2['settings'], true) ?? [];

            }

            $existingSettings['auto_kids_approval'] = $autoKidsApproval;

            $newSettingsJson = json_encode($existingSettings, JSON_UNESCAPED_UNICODE);

            $updStmt = $conn->prepare("UPDATE churches SET settings = ? WHERE id = ?");

            $updStmt->bind_param("si", $newSettingsJson, $churchId);

            $updStmt->execute();



            sendJSON(['success' => true, 'message' => 'تم حفظ الإعدادات بنجاح']);

        } else {

            sendJSON(['success' => false, 'message' => 'فشل في حفظ الإعدادات: ' . $stmt->error]);

        }

    } catch (Exception $e) {

        error_log("saveChurchSettings error: " . $e->getMessage());

        sendJSON(['success' => false, 'message' => 'خطأ في حفظ الإعدادات: ' . $e->getMessage()]);

    }

}



/**

 * Uncle dashboard: Get data for a combined class group.

 * POST: group_label (string) — the label of the combined group

 * The API looks up combined_class_groups from church_settings and returns

 * all students from all classes in the group as a single merged list.

 */

function getUncleClassView()

{

    try {

        $churchId = getChurchId();

        $groupLabel = sanitize($_POST['group_label'] ?? '');



        if (empty($groupLabel)) {

            sendJSON(['success' => false, 'message' => 'اسم المجموعة مطلوب']);

            return;

        }



        $conn = getDBConnection();

        ensureChurchSettingsTable($conn);



        // Load combined groups for this church

        $stmt = $conn->prepare("SELECT combined_class_groups FROM church_settings WHERE church_id = ?");

        $stmt->bind_param("i", $churchId);

        $stmt->execute();

        $row = $stmt->get_result()->fetch_assoc();

        $groups = $row ? json_decode($row['combined_class_groups'] ?? '[]', true) : [];



        // Find the matching group

        $targetGroup = null;

        foreach ($groups as $g) {

            if (($g['label'] ?? '') === $groupLabel) {

                $targetGroup = $g;

                break;

            }

        }



        if (!$targetGroup || empty($targetGroup['classes'])) {

            sendJSON(['success' => false, 'message' => 'المجموعة غير موجودة أو فارغة']);

            return;

        }



        $classNames = array_map('trim', (array) $targetGroup['classes']);

        if (empty($classNames)) {

            sendJSON(['success' => false, 'message' => 'لا توجد فصول في هذه المجموعة']);

            return;

        }



        // Resolve class IDs for the given names (custom + global)

        $churchClasses = getClassesForChurch($churchId);

        $classIdMap = [];

        foreach ($churchClasses as $c) {

            $classIdMap[mb_strtolower($c['arabic_name'])] = $c['id'];

        }



        $classIds = [];

        foreach ($classNames as $cn) {

            $key = mb_strtolower($cn);

            if (isset($classIdMap[$key])) {

                $classIds[] = (int) $classIdMap[$key];

            }

        }



        if (empty($classIds)) {

            sendJSON(['success' => false, 'message' => 'لم يتم العثور على فصول مطابقة']);

            return;

        }



        $placeholders = implode(',', array_fill(0, count($classIds), '?'));

        $types = str_repeat('i', count($classIds) + 1); // +1 for church_id



        $sql = "

            SELECT 

                s.id, s.name, s.phone, s.birthday, s.coupons,

                s.attendance_coupons, s.commitment_coupons, s.image_url, s.class_id,

                COALESCE(cc.arabic_name, gc.arabic_name, s.class) AS class_name,

                COALESCE(cc.code, gc.code) AS class_code

            FROM students s

            LEFT JOIN church_classes cc ON s.class_id = cc.id AND cc.church_id = s.church_id AND cc.is_active = 1

            LEFT JOIN classes gc        ON s.class_id = gc.id

            WHERE s.church_id = ? AND s.class_id IN ($placeholders)

            ORDER BY COALESCE(cc.display_order, gc.display_order, 999), s.name

        ";



        $bindValues = array_merge([$churchId], $classIds);

        $stmt2 = $conn->prepare($sql);

        $stmt2->bind_param($types, ...$bindValues);

        $stmt2->execute();

        $result = $stmt2->get_result();



        $students = [];

        while ($r = $result->fetch_assoc()) {

            $studentData = [

                'الاسم' => $r['name'],

                'الفصل' => $r['class_name'] ?? '',

                '_classId' => (int) $r['class_id'],

                '_classCode' => $r['class_code'] ?? '',

                'رقم التليفون' => $r['phone'] ?? '',

                'عيد الميلاد' => formatDateFromDB($r['birthday']),

                'كوبونات' => (int) $r['coupons'],

                'كوبونات الحضور' => (int) $r['attendance_coupons'],

                'كوبونات الالتزام' => (int) $r['commitment_coupons'],

                'صورة' => $r['image_url'] ?? '',

                '_studentId' => (int) $r['id'],

                '_allAttendance' => [],

            ];



            // Load recent attendance

            $attStmt = $conn->prepare("

                SELECT attendance_date, status FROM attendance

                WHERE student_id = ?

                ORDER BY attendance_date DESC LIMIT 50

            ");

            $attStmt->bind_param("i", $r['id']);

            $attStmt->execute();

            $attResult = $attStmt->get_result();

            while ($att = $attResult->fetch_assoc()) {

                $d = formatDateFromDB($att['attendance_date']);

                $v = $att['status'] === 'present' ? 'ح' : 'غ';

                $studentData[$d] = $v;

                $studentData['_allAttendance'][$d] = $v;

            }



            $students[] = $studentData;

        }



        sendJSON([

            'success' => true,

            'students' => $students,

            'group_label' => $groupLabel,

            'class_names' => $classNames,

            'count' => count($students),

        ]);



    } catch (Exception $e) {

        error_log("getUncleClassView error: " . $e->getMessage());

        sendJSON(['success' => false, 'message' => 'خطأ في تحميل بيانات المجموعة: ' . $e->getMessage()]);

    }

}

// ── Delete a single audit log entry (admin only) ─────────────

function deleteAuditLog()

{

    try {

        $churchId = getChurchId();

        $logId = intval($_POST['log_id'] ?? 0);

        if (!$logId) {

            sendJSON(['success' => false, 'message' => 'معرف السجل مطلوب']);

            return;

        }

        $conn = getDBConnection();

        $stmt = $conn->prepare("DELETE FROM audit_logs WHERE id = ? AND church_id = ?");

        $stmt->bind_param("ii", $logId, $churchId);

        if ($stmt->execute() && $stmt->affected_rows > 0) {

            sendJSON(['success' => true, 'message' => 'تم حذف السجل']);

        } else {

            sendJSON(['success' => false, 'message' => 'لم يتم العثور على السجل']);

        }

    } catch (Exception $e) {

        sendJSON(['success' => false, 'message' => 'خطأ: ' . $e->getMessage()]);

    }

}



function reinsertRecordInternal($tableName, $row, $conn) {
    if (empty($row) || !is_array($row)) return false;
    
    $fields = [];
    $placeholders = [];
    $types = '';
    $params = [];
    
    foreach ($row as $key => $val) {
        if (strpos($key, '_') === 0) continue; // skip nested snapshots
        $fields[] = "`$key`";
        $placeholders[] = "?";
        $params[] = $val;
        
        if (is_int($val)) $types .= 'i';
        elseif (is_float($val)) $types .= 'd';
        else $types .= 's';
    }
    
    $sql = "INSERT INTO `$tableName` (" . implode(', ', $fields) . ") VALUES (" . implode(', ', $placeholders) . ")";
    $stmt = $conn->prepare($sql);
    if (!$stmt) {
        throw new Exception("Reinsert failed preparing query for $tableName: " . $conn->error);
    }
    
    $stmt->bind_param($types, ...$params);
    return $stmt->execute();
}

function restoreSingleAuditLogInternal($logId, $churchId, $conn, $targetStudentId = 0)
{
    try {
        if (!$logId) {
            return ['success' => false, 'message' => 'معرف السجل مطلوب'];
        }
        if (!$churchId) {
            $churchId = getChurchId();
        }
        if (!$conn) {
            $conn = getDBConnection();
        }



        // 1. Fetch the log entry

        $stmt = $conn->prepare("SELECT * FROM audit_logs WHERE id = ? AND church_id = ?");

        $stmt->bind_param("ii", $logId, $churchId);

        $stmt->execute();

        $log = $stmt->get_result()->fetch_assoc();



        if (!$log) {

            return ['success' => false, 'message' => 'لم يتم العثور على السجل'];

        }



        $action = $log['action'];

        $entity = $log['entity'];

        $entityId = $log['entity_id'];

        $oldData = !empty($log['old_data']) ? json_decode($log['old_data'], true) : null;

        $newData = !empty($log['new_data']) ? json_decode($log['new_data'], true) : null;



        if (empty($oldData) && empty($newData)) {

            return ['success' => false, 'message' => 'لا توجد بيانات تاريخية لاسترجاعها لهذا السجل'];

        }



        $reverted = false;
        $msg = "تم استرجاع العملية بنجاح";

        if (!$targetStudentId) {
            $targetStudentId = intval($_POST['target_student_id'] ?? 0);
        }

        if ($entity === 'bulk_action') {
            if (!is_array($oldData)) {
                return ['success' => false, 'message' => 'بيانات السجل الجماعي غير صالحة'];
            }

            if ($targetStudentId > 0) {
                $filtered = [];
                foreach ($oldData as $item) {
                    if (intval($item['id'] ?? 0) === $targetStudentId) {
                        $filtered[] = $item;
                        break;
                    }
                }
                if (empty($filtered)) {
                    return ['success' => false, 'message' => 'الطفل المحدد غير موجود في هذه العملية الجماعية'];
                }
                $oldData = $filtered;
            }

            $conn->begin_transaction();
            $revertedCount = 0;

            foreach ($oldData as $item) {
                $sid = intval($item['id'] ?? 0);
                $sName = $item['name'] ?? '';
                if (!$sid) continue;

                if ($action === 'bulk_student_delete') {
                    $snapshot = $item['old_data'] ?? null;
                    if (!$snapshot) continue;

                    $chk = $conn->prepare("SELECT id FROM students WHERE id = ?");
                    $chk->bind_param("i", $sid);
                    $chk->execute();
                    if ($chk->get_result()->num_rows > 0) {
                        continue;
                    }

                    $whitelist = ['id', 'church_id', 'name', 'gender', 'class_id', 'class', 'address', 'phone', 'emergency_phone', 'medical_notes', 'birthday', 'coupons', 'attendance_coupons', 'commitment_coupons', 'task_coupons', 'image_url', 'custom_info', 'email', 'added_by'];
                    $fields = [];
                    $placeholders = [];
                    $types = '';
                    $params = [];
                    foreach ($snapshot as $key => $val) {
                        if (in_array($key, $whitelist, true)) {
                            $fields[] = "`$key`";
                            $placeholders[] = "?";
                            $params[] = $val;
                            if (is_int($val)) $types .= 'i';
                            elseif (is_float($val)) $types .= 'd';
                            else $types .= 's';
                        }
                    }

                    if (!empty($fields)) {
                        $sql = "INSERT INTO students (" . implode(', ', $fields) . ", created_at) VALUES (" . implode(', ', $placeholders) . ", NOW())";
                        $ins = $conn->prepare($sql);
                        $ins->bind_param($types, ...$params);
                        if ($ins->execute()) {
                            $revertedCount++;
                            if (!empty($snapshot['image_url'])) {
                                recoverRevertedImageFile($snapshot['image_url']);
                            }

                            // Restore related attendance from snapshot if present
                            if (isset($snapshot['_attendance_history']) && is_array($snapshot['_attendance_history'])) {
                                $insAtt = $conn->prepare("
                                    INSERT INTO attendance (student_id, church_id, attendance_date, status, uncle_id, created_at)
                                    VALUES (?, ?, ?, ?, ?, NOW())
                                    ON DUPLICATE KEY UPDATE status = VALUES(status), uncle_id = VALUES(uncle_id)
                                ");
                                foreach ($snapshot['_attendance_history'] as $att) {
                                    $uId = $att['uncle_id'] ?? null;
                                    $insAtt->bind_param("iissi", $sid, $churchId, $att['attendance_date'], $att['status'], $uId);
                                    $insAtt->execute();
                                }
                            } else {
                                // Fallback: Reconstruct attendance from audit logs
                                recoverStudentAttendanceFromAuditLogs($sid, $churchId, $conn);
                            }

                            // Restore sibling groups if present
                            if (isset($snapshot['_sibling_groups']) && is_array($snapshot['_sibling_groups'])) {
                                $insSib = $conn->prepare("INSERT INTO student_sibling_group_members (student_id, group_id) VALUES (?, ?)");
                                foreach ($snapshot['_sibling_groups'] as $groupId) {
                                    $insSib->bind_param("ii", $sid, $groupId);
                                    $insSib->execute();
                                }
                            }
                        }
                    }
                } elseif ($action === 'bulk_student_class_update') {
                    $oldClassId = intval($item['old_data']['class_id'] ?? 0);
                    $oldClass = $item['old_data']['class'] ?? '';
                    
                    $chk = $conn->prepare("SELECT id FROM students WHERE id = ? AND church_id = ?");
                    $chk->bind_param("ii", $sid, $churchId);
                    $chk->execute();
                    if ($chk->get_result()->num_rows === 0) {
                        continue;
                    }

                    $upd = $conn->prepare("UPDATE students SET class_id = ?, class = ?, updated_at = NOW() WHERE id = ? AND church_id = ?");
                    $upd->bind_param("isii", $oldClassId, $oldClass, $sid, $churchId);
                    if ($upd->execute()) {
                        $revertedCount++;
                    }
                } elseif ($action === 'bulk_student_coupon_update') {
                    $chk = $conn->prepare("SELECT coupons, commitment_coupons FROM students WHERE id = ? AND church_id = ?");
                    $chk->bind_param("ii", $sid, $churchId);
                    $chk->execute();
                    $stu = $chk->get_result()->fetch_assoc();
                    if (!$stu) continue;

                    $oldTotal = intval($item['old_data']['coupons'] ?? 0);
                    $newTotal = intval($item['new_data']['coupons'] ?? 0);
                    $diff = $oldTotal - $newTotal;
                    $newCommitment = intval($stu['commitment_coupons']) + $diff;
                    if ($newCommitment < 0) $newCommitment = 0;

                    $upd = $conn->prepare("UPDATE students SET coupons = ?, commitment_coupons = ?, updated_at = NOW() WHERE id = ? AND church_id = ?");
                    $upd->bind_param("iiii", $oldTotal, $newCommitment, $sid, $churchId);
                    if ($upd->execute()) {
                        $uncleId = $_SESSION['uncle_id'] ?? null;
                        $logStmt = $conn->prepare("
                            INSERT INTO coupon_logs (student_id, uncle_id, old_count, new_count, change_amount, change_type)
                            VALUES (?, ?, ?, ?, ?, 'manual')
                        ");
                        $logStmt->bind_param("iiiii", $sid, $uncleId, $newTotal, $oldTotal, $diff);
                        $logStmt->execute();
                        $revertedCount++;
                    }
                } elseif ($action === 'bulk_attendance_save') {
                    $oldStatus = $item['old_data']['status'] ?? 'pending';
                    $newStatus = $item['new_data']['status'] ?? 'pending';
                    $attDate = $item['date'] ?? null;
                    if (!$attDate) continue;

                    $chkStu = $conn->prepare("SELECT id, name, coupons, attendance_coupons, commitment_coupons, task_coupons FROM students WHERE id = ? AND church_id = ?");
                    $chkStu->bind_param("ii", $sid, $churchId);
                    $chkStu->execute();
                    $student = $chkStu->get_result()->fetch_assoc();
                    if (!$student) continue;

                    $currentAttCoupons = intval($student['attendance_coupons']);
                    $commitmentCoupons = intval($student['commitment_coupons']);
                    $taskCoupons = intval($student['task_coupons']);

                    if ($oldStatus === 'pending') {
                        $del = $conn->prepare("DELETE FROM attendance WHERE student_id = ? AND attendance_date = ?");
                        $del->bind_param("is", $sid, $attDate);
                        $del->execute();
                        
                        if ($newStatus === 'present') {
                            $newAtt = max(0, $currentAttCoupons - 100);
                            $newTotal = $newAtt + $commitmentCoupons + $taskCoupons;
                            $upd = $conn->prepare("UPDATE students SET attendance_coupons=?, coupons=? WHERE id=?");
                            $upd->bind_param("iii", $newAtt, $newTotal, $sid);
                            $upd->execute();
                        }
                        $revertedCount++;
                    } else {
                        $ins = $conn->prepare("
                            INSERT INTO attendance (student_id, church_id, attendance_date, status, uncle_id)
                            VALUES (?, ?, ?, ?, ?)
                            ON DUPLICATE KEY UPDATE status = VALUES(status), uncle_id = VALUES(uncle_id)
                        ");
                        $uncleId = $_SESSION['uncle_id'] ?? null;
                        $ins->bind_param("iissi", $sid, $churchId, $attDate, $oldStatus, $uncleId);
                        if ($ins->execute()) {
                            if ($oldStatus === 'present' && $newStatus !== 'present') {
                                $newAtt = $currentAttCoupons + 100;
                                $newTotal = $newAtt + $commitmentCoupons + $taskCoupons;
                                $upd = $conn->prepare("UPDATE students SET attendance_coupons=?, coupons=? WHERE id=?");
                                $upd->bind_param("iii", $newAtt, $newTotal, $sid);
                                $upd->execute();
                            } elseif ($oldStatus !== 'present' && $newStatus === 'present') {
                                $newAtt = max(0, $currentAttCoupons - 100);
                                $newTotal = $newAtt + $commitmentCoupons + $taskCoupons;
                                $upd = $conn->prepare("UPDATE students SET attendance_coupons=?, coupons=? WHERE id=?");
                                $upd->bind_param("iii", $newAtt, $newTotal, $sid);
                                $upd->execute();
                            }
                            $revertedCount++;
                        }
                    }
                } elseif ($action === 'bulk_note_add') {
                    $chk = $conn->prepare("SELECT custom_info FROM students WHERE id = ? AND church_id = ?");
                    $chk->bind_param("ii", $sid, $churchId);
                    $chk->execute();
                    $student = $chk->get_result()->fetch_assoc();
                    if ($student) {
                        $customInfo = !empty($student['custom_info']) ? json_decode($student['custom_info'], true) : [];
                        if (is_array($customInfo) && isset($customInfo['_notes']) && is_array($customInfo['_notes'])) {
                            $foundIdx = -1;
                            $targetNoteId = $item['note']['id'] ?? '';
                            foreach ($customInfo['_notes'] as $idx => $note) {
                                if (($note['id'] ?? '') === $targetNoteId) {
                                    $foundIdx = $idx;
                                    break;
                                }
                            }
                            if ($foundIdx !== -1) {
                                array_splice($customInfo['_notes'], $foundIdx, 1);
                                $customInfoJson = json_encode($customInfo, JSON_UNESCAPED_UNICODE);
                                $upd = $conn->prepare("UPDATE students SET custom_info = ?, updated_at = NOW() WHERE id = ? AND church_id = ?");
                                $upd->bind_param("sii", $customInfoJson, $sid, $churchId);
                                if ($upd->execute()) {
                                    $revertedCount++;
                                }
                            }
                        }
                    }
                }
            }

            if ($revertedCount > 0) {
                $conn->commit();
                $reverted = true;
                
                if ($targetStudentId > 0) {
                    $msg = "تم استرجاع العملية للطفل بنجاح";
                    $notes = "استرجاع الطفل " . ($oldData[0]['name'] ?? '') . " فقط من العملية: " . ($log['notes'] ?? $action);
                } else {
                    $msg = "تم استرجاع العملية الجماعية بالكامل لـ $revertedCount من الأطفال بنجاح";
                    $notes = "استرجاع العملية الجماعية بالكامل: " . ($log['notes'] ?? $action);
                }
                
                writeAuditLog(
                    'audit_restore',
                    'audit_logs',
                    $logId,
                    $action,
                    null,
                    null,
                    $notes
                );

                return ['success' => true, 'message' => $msg];
            } else {
                $conn->rollback();
                return ['success' => false, 'message' => 'لم يتم استرجاع أي طفل. ربما تم استرجاعهم بالفعل أو غير موجودين.'];
            }
        }

        if ($entity === 'student') {

            if ($action === 'note_add') {
                $chk = $conn->prepare("SELECT custom_info FROM students WHERE id = ? AND church_id = ?");
                $chk->bind_param("ii", $entityId, $churchId);
                $chk->execute();
                $student = $chk->get_result()->fetch_assoc();
                if ($student) {
                    $customInfo = !empty($student['custom_info']) ? json_decode($student['custom_info'], true) : [];
                    if (is_array($customInfo) && isset($customInfo['_notes']) && is_array($customInfo['_notes'])) {
                        $foundIdx = -1;
                        foreach ($customInfo['_notes'] as $idx => $note) {
                            if (($note['id'] ?? '') === ($newData['id'] ?? '')) {
                                $foundIdx = $idx;
                                break;
                            }
                        }
                        if ($foundIdx !== -1) {
                            array_splice($customInfo['_notes'], $foundIdx, 1);
                            $customInfoJson = json_encode($customInfo, JSON_UNESCAPED_UNICODE);
                            $upd = $conn->prepare("UPDATE students SET custom_info = ?, updated_at = NOW() WHERE id = ? AND church_id = ?");
                            $upd->bind_param("sii", $customInfoJson, $entityId, $churchId);
                            if ($upd->execute()) {
                                $reverted = true;
                                $msg = "تم التراجع عن إضافة الملاحظة وحذفها بنجاح";
                            }
                        }
                    }
                }
            } elseif ($action === 'note_delete') {
                $chk = $conn->prepare("SELECT custom_info FROM students WHERE id = ? AND church_id = ?");
                $chk->bind_param("ii", $entityId, $churchId);
                $chk->execute();
                $student = $chk->get_result()->fetch_assoc();
                if ($student) {
                    $customInfo = !empty($student['custom_info']) ? json_decode($student['custom_info'], true) : [];
                    if (!is_array($customInfo)) {
                        $customInfo = [];
                    }
                    if (!isset($customInfo['_notes']) || !is_array($customInfo['_notes'])) {
                        $customInfo['_notes'] = [];
                    }
                    $duplicate = false;
                    foreach ($customInfo['_notes'] as $note) {
                        if (($note['id'] ?? '') === ($oldData['id'] ?? '')) {
                            $duplicate = true;
                            break;
                        }
                    }
                    if (!$duplicate && !empty($oldData)) {
                        $customInfo['_notes'][] = $oldData;
                        $customInfoJson = json_encode($customInfo, JSON_UNESCAPED_UNICODE);
                        $upd = $conn->prepare("UPDATE students SET custom_info = ?, updated_at = NOW() WHERE id = ? AND church_id = ?");
                        $upd->bind_param("sii", $customInfoJson, $entityId, $churchId);
                        if ($upd->execute()) {
                            $reverted = true;
                            $msg = "تم استرجاع الملاحظة المحذوفة بنجاح";
                        }
                    }
                }
            } elseif ($action === 'student_merge') {
                $targetId = intval($oldData['target_id'] ?? 0);
                $duplicateId = intval($oldData['duplicate_id'] ?? 0);
                $targetSnapshot = $oldData['target_snapshot'] ?? null;
                $duplicateSnapshot = $oldData['duplicate_snapshot'] ?? null;
                
                if (!$targetId || !$duplicateId || !$targetSnapshot || !$duplicateSnapshot) {
                    return ['success' => false, 'message' => 'بيانات الدمج التاريخية غير صالحة للاسترجاع'];
                }
                
                $conn->begin_transaction();
                try {
                    // 1. Delete all records for both IDs in related tables to get a clean slate
                    $deleteTables = [
                        'attendance' => 'student_id',
                        'student_sibling_group_members' => 'student_id',
                        'task_submissions' => 'student_id',
                        'exam_starts' => 'student_id',
                        'coupon_logs' => 'student_id',
                        'coupon_withdrawals' => 'student_id',
                        'trip_waitlist' => 'student_id'
                    ];
                    
                    foreach ($deleteTables as $tbl => $col) {
                        $delStmt = $conn->prepare("DELETE FROM `$tbl` WHERE `$col` = ? OR `$col` = ?");
                        $delStmt->bind_param("ii", $targetId, $duplicateId);
                        $delStmt->execute();
                    }
                    
                    // Clear trip registrations & payments for both kids
                    $getRegs = $conn->prepare("SELECT id FROM trip_registrations WHERE student_id = ? OR student_id = ?");
                    $getRegs->bind_param("ii", $targetId, $duplicateId);
                    $getRegs->execute();
                    $regRes = $getRegs->get_result();
                    $regIds = [];
                    while ($r = $regRes->fetch_assoc()) {
                        $regIds[] = intval($r['id']);
                    }
                    
                    if (!empty($regIds)) {
                        $regIdsStr = implode(',', $regIds);
                        $conn->query("DELETE FROM trip_payments WHERE registration_id IN ($regIdsStr)");
                        $conn->query("DELETE FROM trip_registrations WHERE id IN ($regIdsStr)");
                    }
                    
                    // 2. Revert Profiles (delete first then insert)
                    $conn->query("DELETE FROM students WHERE id = $targetId");
                    $conn->query("DELETE FROM students WHERE id = $duplicateId");
                    
                    // 3. Re-insert both students profiles
                    reinsertRecordInternal('students', $targetSnapshot, $conn);
                    reinsertRecordInternal('students', $duplicateSnapshot, $conn);

                    // Restore image files if present
                    if (!empty($targetSnapshot['image_url'])) {
                        recoverRevertedImageFile($targetSnapshot['image_url']);
                    }
                    if (!empty($duplicateSnapshot['image_url'])) {
                        recoverRevertedImageFile($duplicateSnapshot['image_url']);
                    }
                    
                    // 4. Restore related data for both snapshots
                    $snapshots = [$targetSnapshot, $duplicateSnapshot];
                    foreach ($snapshots as $snap) {
                        $sid = intval($snap['id']);
                        
                        // Attendance
                        if (isset($snap['_attendance_history']) && is_array($snap['_attendance_history'])) {
                            foreach ($snap['_attendance_history'] as $att) {
                                $att['student_id'] = $sid;
                                if (empty($att['church_id'])) {
                                    $att['church_id'] = $churchId;
                                }
                                reinsertRecordInternal('attendance', $att, $conn);
                            }
                        }
                        
                        // Sibling Groups
                        if (isset($snap['_sibling_groups']) && is_array($snap['_sibling_groups'])) {
                            $insSib = $conn->prepare("INSERT INTO student_sibling_group_members (student_id, group_id) VALUES (?, ?)");
                            foreach ($snap['_sibling_groups'] as $groupId) {
                                $insSib->bind_param("ii", $sid, $groupId);
                                $insSib->execute();
                            }
                        }
                        
                        // Task Submissions
                        if (isset($snap['_task_submissions']) && is_array($snap['_task_submissions'])) {
                            foreach ($snap['_task_submissions'] as $task) {
                                reinsertRecordInternal('task_submissions', $task, $conn);
                            }
                        }
                        
                        // Exam Starts
                        if (isset($snap['_exam_starts']) && is_array($snap['_exam_starts'])) {
                            foreach ($snap['_exam_starts'] as $exam) {
                                reinsertRecordInternal('exam_starts', $exam, $conn);
                            }
                        }
                        
                        // Coupon Withdrawals
                        if (isset($snap['_coupon_withdrawals']) && is_array($snap['_coupon_withdrawals'])) {
                            foreach ($snap['_coupon_withdrawals'] as $w) {
                                reinsertRecordInternal('coupon_withdrawals', $w, $conn);
                            }
                        }
                        
                        // Coupon Logs
                        if (isset($snap['_coupon_logs']) && is_array($snap['_coupon_logs'])) {
                            foreach ($snap['_coupon_logs'] as $clog) {
                                reinsertRecordInternal('coupon_logs', $clog, $conn);
                            }
                        }
                        
                        // Trip waitlist
                        if (isset($snap['_trip_waitlist']) && is_array($snap['_trip_waitlist'])) {
                            foreach ($snap['_trip_waitlist'] as $wait) {
                                reinsertRecordInternal('trip_waitlist', $wait, $conn);
                            }
                        }
                        
                        // Trip registrations & payments
                        if (isset($snap['_trip_registrations']) && is_array($snap['_trip_registrations'])) {
                            foreach ($snap['_trip_registrations'] as $reg) {
                                $payments = $reg['_payments'] ?? [];
                                unset($reg['_payments']);
                                
                                reinsertRecordInternal('trip_registrations', $reg, $conn);
                                
                                foreach ($payments as $pay) {
                                    reinsertRecordInternal('trip_payments', $pay, $conn);
                                }
                            }
                        }
                    }
                    
                    $conn->commit();
                    $reverted = true;
                    $msg = "تم التراجع عن عملية الدمج بنجاح واستعادة كلا الطفلين لسيرتهما الأولى";
                    
                } catch (Exception $txEx) {
                    $conn->rollback();
                    throw $txEx;
                }
            } elseif ($action === 'student_edit') {

                if (empty($oldData)) {

                    return ['success' => false, 'message' => 'لا توجد بيانات سابقة لاسترجاعها'];

                }

                // Check if student still exists

                $chk = $conn->prepare("SELECT id FROM students WHERE id = ?");

                $chk->bind_param("i", $entityId);

                $chk->execute();

                if ($chk->get_result()->num_rows === 0) {

                    return ['success' => false, 'message' => 'لا يمكن الاسترجاع: الطفل غير موجود حالياً'];

                }

                // If image_url is being reverted
                if (isset($oldData['image_url']) || isset($newData['image_url'])) {
                    $oldImg = $oldData['image_url'] ?? '';
                    $newImg = $newData['image_url'] ?? '';
                    if ($oldImg !== $newImg) {
                        restoreRevertedImageFile($oldImg, $newImg);
                    }
                }



                // Update using whitelisted columns

                $whitelist = ['name', 'gender', 'class_id', 'class', 'address', 'phone', 'emergency_phone', 'medical_notes', 'birthday', 'coupons', 'attendance_coupons', 'commitment_coupons', 'task_coupons', 'image_url', 'custom_info', 'email'];

                $updates = [];

                $types = '';

                $params = [];

                foreach ($oldData as $key => $val) {

                    if (in_array($key, $whitelist, true)) {

                        $updates[] = "`$key` = ?";

                        $params[] = $val;

                        if (is_int($val)) $types .= 'i';

                        elseif (is_float($val)) $types .= 'd';

                        else $types .= 's';

                    }

                }



                if (!empty($updates)) {

                    $sql = "UPDATE students SET " . implode(', ', $updates) . ", updated_at = NOW() WHERE id = ?";

                    $types .= 'i';

                    $params[] = $entityId;

                    $upd = $conn->prepare($sql);

                    $upd->bind_param($types, ...$params);

                    if ($upd->execute()) {

                        $reverted = true;

                        $msg = "تم استرجاع بيانات الطفل بنجاح";

                    }

                } else {

                    return ['success' => false, 'message' => 'لم يتم العثور على حقول قابلة للتحديث'];

                }

            } elseif ($action === 'student_delete') {

                if (empty($oldData)) {

                    return ['success' => false, 'message' => 'لا توجد بيانات سابقة لإعادة الإدخال'];

                }

                // Check if student ID already exists

                $chk = $conn->prepare("SELECT id FROM students WHERE id = ?");

                $chk->bind_param("i", $entityId);

                $chk->execute();

                if ($chk->get_result()->num_rows > 0) {

                    return ['success' => false, 'message' => 'الطفل موجود بالفعل في قاعدة البيانات ولا حاجة لاسترجاعه'];

                }



                // Re-insert using whitelisted columns + id + church_id

                $whitelist = ['id', 'church_id', 'name', 'gender', 'class_id', 'class', 'address', 'phone', 'emergency_phone', 'medical_notes', 'birthday', 'coupons', 'attendance_coupons', 'commitment_coupons', 'task_coupons', 'image_url', 'custom_info', 'email', 'added_by'];

                $fields = [];

                $placeholders = [];

                $types = '';

                $params = [];

                foreach ($oldData as $key => $val) {

                    if (in_array($key, $whitelist, true)) {

                        $fields[] = "`$key`";

                        $placeholders[] = "?";

                        $params[] = $val;

                        if (is_int($val)) $types .= 'i';

                        elseif (is_float($val)) $types .= 'd';

                        else $types .= 's';

                    }

                }



                if (!empty($fields)) {

                    $sql = "INSERT INTO students (" . implode(', ', $fields) . ", created_at) VALUES (" . implode(', ', $placeholders) . ", NOW())";

                    $ins = $conn->prepare($sql);

                    $ins->bind_param($types, ...$params);

                    if ($ins->execute()) {
                        $reverted = true;
                        $msg = "تم إعادة تسجيل الطفل المحذوف بنجاح";
                        if (!empty($oldData['image_url'])) {
                            recoverRevertedImageFile($oldData['image_url']);
                        }

                        // Restore related attendance from snapshot if present
                        if (isset($oldData['_attendance_history']) && is_array($oldData['_attendance_history'])) {
                            $insAtt = $conn->prepare("
                                INSERT INTO attendance (student_id, church_id, attendance_date, status, uncle_id, created_at)
                                VALUES (?, ?, ?, ?, ?, NOW())
                                ON DUPLICATE KEY UPDATE status = VALUES(status), uncle_id = VALUES(uncle_id)
                            ");
                            foreach ($oldData['_attendance_history'] as $att) {
                                $uId = $att['uncle_id'] ?? null;
                                $insAtt->bind_param("iissi", $entityId, $churchId, $att['attendance_date'], $att['status'], $uId);
                                $insAtt->execute();
                            }
                        } else {
                            // Fallback: Reconstruct attendance from audit logs
                            recoverStudentAttendanceFromAuditLogs($entityId, $churchId, $conn);
                        }

                        // Restore sibling groups if present
                        if (isset($oldData['_sibling_groups']) && is_array($oldData['_sibling_groups'])) {
                            $insSib = $conn->prepare("INSERT INTO student_sibling_group_members (student_id, group_id) VALUES (?, ?)");
                            foreach ($oldData['_sibling_groups'] as $groupId) {
                                $insSib->bind_param("ii", $entityId, $groupId);
                                $insSib->execute();
                            }
                        }
                    }

                } else {

                    return ['success' => false, 'message' => 'لم يتم العثور على بيانات صالحة لإعادة الإدخال'];

                }

            } elseif ($action === 'student_add') {

                // Undoing a student add is deleting the student, but only if they have no other registrations/attendance to avoid issues

                $chkAtt = $conn->prepare("SELECT id FROM attendance WHERE student_id = ?");

                $chkAtt->bind_param("i", $entityId);

                $chkAtt->execute();

                if ($chkAtt->get_result()->num_rows > 0) {

                    return ['success' => false, 'message' => 'لا يمكن التراجع عن إضافة الطفل لوجود سجلات حضور مسجلة له'];

                }



                $chkReg = $conn->prepare("SELECT id FROM trip_registrations WHERE student_id = ?");

                $chkReg->bind_param("i", $entityId);

                $chkReg->execute();

                if ($chkReg->get_result()->num_rows > 0) {

                    return ['success' => false, 'message' => 'لا يمكن التراجع عن إضافة الطفل لوجود تسجيلات رحلات مسجلة له'];

                }



                $del = $conn->prepare("DELETE FROM students WHERE id = ? AND church_id = ?");

                $del->bind_param("ii", $entityId, $churchId);

                if ($del->execute() && $del->affected_rows > 0) {

                    $reverted = true;

                    $msg = "تم التراجع عن إضافة الطفل وحذفه بنجاح";

                } else {

                    return ['success' => false, 'message' => 'لم يتم العثور على الطفل لحذفه'];

                }

            }

        } elseif ($entity === 'coupon') {

            if ($action === 'coupon_edit') {

                // coupons: oldTotal -> newTotal

                // We should read the student's current coupon count

                $chk = $conn->prepare("SELECT coupons, commitment_coupons FROM students WHERE id = ?");

                $chk->bind_param("i", $entityId);

                $chk->execute();

                $stu = $chk->get_result()->fetch_assoc();

                if (!$stu) {

                    return ['success' => false, 'message' => 'الطفل غير موجود'];

                }



                $oldTotal = intval($oldData['coupons'] ?? 0);

                $newTotal = intval($newData['coupons'] ?? 0);

                $diff = $oldTotal - $newTotal; // Reversing difference



                $newCommitment = intval($stu['commitment_coupons']) + $diff;



                $upd = $conn->prepare("UPDATE students SET coupons = ?, commitment_coupons = ?, updated_at = NOW() WHERE id = ?");

                $upd->bind_param("iii", $oldTotal, $newCommitment, $entityId);

                if ($upd->execute()) {

                    // Insert a reverse coupon log

                    $uncleId = $_SESSION['uncle_id'] ?? null;

                    $logStmt = $conn->prepare("

                        INSERT INTO coupon_logs (student_id, uncle_id, old_count, new_count, change_amount, change_type)

                        VALUES (?, ?, ?, ?, ?, 'manual')

                    ");

                    $logStmt->bind_param("iiiii", $entityId, $uncleId, $newTotal, $oldTotal, $diff);

                    $logStmt->execute();



                    $reverted = true;

                    $msg = "تم استرجاع رصيد الكوبونات بنجاح";

                }

            } elseif ($action === 'coupon_withdraw') {
                $stmt = $conn->prepare("SELECT id FROM coupon_withdrawals WHERE student_id = ? AND is_refunded = 0 ORDER BY created_at DESC, id DESC LIMIT 1");
                $stmt->bind_param("i", $entityId);
                $stmt->execute();
                $resW = $stmt->get_result()->fetch_assoc();
                if (!$resW) {
                    return ['success' => false, 'message' => 'لم يتم العثور على عملية سحب نشطة قابلة للتراجع لهذا الطفل'];
                }
                $withdrawalId = intval($resW['id']);
                
                $stmt = $conn->prepare("SELECT * FROM coupon_withdrawals WHERE id = ? FOR UPDATE");
                $stmt->bind_param("i", $withdrawalId);
                $stmt->execute();
                $w = $stmt->get_result()->fetch_assoc();
                if (!$w) {
                    throw new Exception('عملية السحب غير موجودة');
                }
                if ($w['is_refunded']) {
                    throw new Exception('تم استرجاع هذه العملية بالفعل');
                }

                $amount = intval($w['amount']);
                $att = intval($w['att_amount'] ?? 0);
                $com = intval($w['com_amount'] ?? 0);
                $tsk = intval($w['tsk_amount'] ?? 0);

                // Update student
                $upd = $conn->prepare("UPDATE students SET coupons = coupons + ?, attendance_coupons = attendance_coupons + ?, commitment_coupons = commitment_coupons + ?, task_coupons = task_coupons + ? WHERE id = ?");
                $upd->bind_param("iiiii", $amount, $att, $com, $tsk, $entityId);
                if (!$upd->execute()) {
                    throw new Exception('فشل استعادة الكوبونات للطفل');
                }

                // Mark as refunded
                $mark = $conn->prepare("UPDATE coupon_withdrawals SET is_refunded = 1, refunded_at = NOW() WHERE id = ?");
                $mark->bind_param("i", $withdrawalId);
                if (!$mark->execute()) {
                    throw new Exception('فشل تحديث حالة السحب');
                }

                // Retrieve student name for log if not loaded
                $studentName = '';
                $stuStmt = $conn->prepare("SELECT name FROM students WHERE id = ?");
                $stuStmt->bind_param("i", $entityId);
                $stuStmt->execute();
                $stuRes = $stuStmt->get_result()->fetch_assoc();
                if ($stuRes) {
                    $studentName = $stuRes['name'];
                }

                // Write audit log
                writeAuditLog('coupon_refund', 'coupon', $entityId, $studentName, null, ['amount' => $amount], "تراجع عن السحب: استرجاع $amount كوبون (عملية #$withdrawalId)");
                $reverted = true;
                $msg = "تم التراجع عن عملية السحب بنجاح وإعادة الكوبونات للطفل";
            }

        } elseif ($entity === 'attendance') {

            // Restore attendance

            if ($action === 'attendance_add' || $action === 'attendance_edit') {

                $attDate = $oldData['date'] ?? $newData['date'] ?? null;

                $oldStatus = $oldData['status'] ?? 'pending';



                if (!$attDate) {

                    return ['success' => false, 'message' => 'تاريخ الغياب غير محدد في السجل'];

                }



                if ($oldStatus === 'pending') {

                    // If it was pending (or cleared), we delete the record

                    $del = $conn->prepare("DELETE FROM attendance WHERE student_id = ? AND attendance_date = ?");

                    $del->bind_param("is", $entityId, $attDate);

                    $del->execute();

                    $reverted = true;

                    $msg = "تم إلغاء سجل الحضور بنجاح";

                } else {

                    // Upsert status

                    $chk = $conn->prepare("SELECT id FROM attendance WHERE student_id = ? AND attendance_date = ?");

                    $chk->bind_param("is", $entityId, $attDate);

                    $chk->execute();

                    $res = $chk->get_result();



                    if ($res->num_rows > 0) {

                        $attId = $res->fetch_assoc()['id'];

                        $upd = $conn->prepare("UPDATE attendance SET status = ?, updated_at = NOW() WHERE id = ?");

                        $upd->bind_param("si", $oldStatus, $attId);

                        $upd->execute();

                    } else {

                        $ins = $conn->prepare("INSERT INTO attendance (student_id, church_id, attendance_date, status, uncle_id, created_at) VALUES (?, ?, ?, ?, ?, NOW())");

                        $uncleId = $_SESSION['uncle_id'] ?? null;

                        $ins->bind_param("iissi", $entityId, $churchId, $attDate, $oldStatus, $uncleId);

                        $ins->execute();

                    }

                    $reverted = true;

                    $msg = "تم استرجاع حالة الحضور بنجاح";

                }

            } elseif ($action === 'attendance_delete') {

                // Re-insert row from oldData

                $attDate = $oldData['attendance_date'] ?? null;

                $status = $oldData['status'] ?? 'present';

                if (!$attDate) {

                    return ['success' => false, 'message' => 'بيانات الحضور غير كاملة'];

                }



                $ins = $conn->prepare("INSERT INTO attendance (student_id, church_id, attendance_date, status, uncle_id, created_at) VALUES (?, ?, ?, ?, ?, NOW())");

                $uncleId = $_SESSION['uncle_id'] ?? null;

                $ins->bind_param("iissi", $entityId, $churchId, $attDate, $status, $uncleId);

                if ($ins->execute()) {

                    $reverted = true;

                    $msg = "تم استرجاع سجل الحضور المحذوف بنجاح";

                }

            }

        } elseif ($entity === 'uncle') {
            if ($action === 'uncle_delete') {
                $stmt = $conn->prepare("UPDATE uncles SET deleted = 0 WHERE id = ? AND church_id = ?");
                $stmt->bind_param("ii", $entityId, $churchId);
                if ($stmt->execute() && $stmt->affected_rows > 0) {
                    $reverted = true;
                    $msg = "تم استرجاع الخادم المحذوف بنجاح";
                    if (!empty($oldData['image_url'])) {
                        recoverRevertedImageFile($oldData['image_url']);
                    }
                }
            } elseif ($action === 'uncle_add') {
                $stmt = $conn->prepare("SELECT image_url FROM uncles WHERE id = ? AND church_id = ?");
                $stmt->bind_param("ii", $entityId, $churchId);
                $stmt->execute();
                $uncleRow = $stmt->get_result()->fetch_assoc();
                $imgUrl = $uncleRow['image_url'] ?? '';

                $del = $conn->prepare("DELETE FROM uncles WHERE id = ? AND church_id = ?");
                $del->bind_param("ii", $entityId, $churchId);
                if ($del->execute() && $del->affected_rows > 0) {
                    $reverted = true;
                    $msg = "تم التراجع عن إضافة الخادم وحذفه بنجاح";
                    if (!empty($imgUrl)) {
                        $path = $imgUrl;
                        if (strpos($path, 'https://') === 0 || strpos($path, 'http://') === 0) {
                            $parsed = parse_url($path);
                            $path = $parsed['path'] ?? '';
                        }
                        $realFile = __DIR__ . $path;
                        if (is_file($realFile)) {
                            @unlink($realFile);
                        }
                    }
                }
            } elseif ($action === 'uncle_edit') {
                if (empty($oldData)) {
                    return ['success' => false, 'message' => 'لا توجد بيانات سابقة لاسترجاعها'];
                }

                if (isset($oldData['image_url']) || isset($newData['image_url'])) {
                    $oldImg = $oldData['image_url'] ?? '';
                    $newImg = $newData['image_url'] ?? '';
                    if ($oldImg !== $newImg) {
                        restoreRevertedImageFile($oldImg, $newImg);
                    }
                }

                $whitelist = ['name', 'email', 'role', 'image_url', 'deleted'];
                $updates = [];
                $types = '';
                $params = [];
                foreach ($oldData as $key => $val) {
                    if (in_array($key, $whitelist, true)) {
                        $updates[] = "`$key` = ?";
                        $params[] = $val;
                        if (is_int($val)) $types .= 'i';
                        elseif (is_float($val)) $types .= 'd';
                        else $types .= 's';
                    }
                }

                if (!empty($updates)) {
                    $sql = "UPDATE uncles SET " . implode(', ', $updates) . " WHERE id = ? AND church_id = ?";
                    $types .= 'ii';
                    $params[] = $entityId;
                    $params[] = $churchId;
                    $upd = $conn->prepare($sql);
                    $upd->bind_param($types, ...$params);
                    if ($upd->execute()) {
                        $reverted = true;
                        $msg = "تم استرجاع بيانات الخادم بنجاح";
                    }
                } else {
                    return ['success' => false, 'message' => 'لم يتم العثور على حقول قابلة للتحديث'];
                }
            }
        }



        if ($reverted) {

            // Write audit log for the restore action

            writeAuditLog(

                'audit_restore',

                'audit_logs',

                $logId,

                $action,

                null,

                null,

                "استرجاع العملية: " . ($log['notes'] ?? $action)

            );

            return ['success' => true, 'message' => $msg];

        } else {

            return ['success' => false, 'message' => 'نوع العملية غير مدعوم حالياً للاسترجاع التلقائي'];

        }



    } catch (Exception $e) {

        return ['success' => false, 'message' => 'خطأ أثناء الاسترجاع: ' . $e->getMessage()];

    }


}


function restoreAuditLog()
{
    try {
        $churchId = getChurchId();
        $logId = intval($_POST['log_id'] ?? 0);
        if (!$logId) {
            sendJSON(['success' => false, 'message' => 'معرف السجل مطلوب']);
            return;
        }

        $conn = getDBConnection();
        $res = restoreSingleAuditLogInternal($logId, $churchId, $conn, intval($_POST['target_student_id'] ?? 0));
        sendJSON($res);
    } catch (Exception $e) {
        sendJSON(['success' => false, 'message' => 'خطأ أثناء الاسترجاع: ' . $e->getMessage()]);
    }
}


function bulkRestoreAuditLogs()
{
    try {
        $churchId = getChurchId();
        $logIdsStr = sanitize($_POST['log_ids'] ?? '');
        if (empty($logIdsStr)) {
            sendJSON(['success' => false, 'message' => 'لم يتم تحديد أي سجلات لاسترجاعها']);
            return;
        }

        $logIds = array_map('intval', explode(',', $logIdsStr));
        $logIds = array_filter($logIds);
        if (empty($logIds)) {
            sendJSON(['success' => false, 'message' => 'سجلات غير صالحة']);
            return;
        }

        $conn = getDBConnection();
        // Sort descending to restore in reverse chronological order
        rsort($logIds);

        $successCount = 0;
        $failedLogs = [];

        foreach ($logIds as $logId) {
            $res = restoreSingleAuditLogInternal($logId, $churchId, $conn);
            if ($res['success']) {
                $successCount++;
            } else {
                $failedLogs[] = "السجل #$logId: " . $res['message'];
            }
        }

        if ($successCount > 0) {
            $msg = "تم استرجاع $successCount من العمليات بنجاح";
            if (!empty($failedLogs)) {
                $msg .= ". وفشل: " . implode(', ', $failedLogs);
            }
            sendJSON(['success' => true, 'message' => $msg]);
        } else {
            sendJSON(['success' => false, 'message' => 'فشل استرجاع العمليات: ' . implode(', ', $failedLogs)]);
        }
    } catch (Exception $e) {
        sendJSON(['success' => false, 'message' => 'خطأ: ' . $e->getMessage()]);
    }
}


function bulkDeleteAuditLogs()
{
    try {
        $churchId = getChurchId();
        $logIdsStr = sanitize($_POST['log_ids'] ?? '');
        if (empty($logIdsStr)) {
            sendJSON(['success' => false, 'message' => 'لم يتم تحديد أي سجلات لحذفها']);
            return;
        }

        $logIds = array_map('intval', explode(',', $logIdsStr));
        $logIds = array_filter($logIds);
        if (empty($logIds)) {
            sendJSON(['success' => false, 'message' => 'سجلات غير صالحة']);
            return;
        }

        $conn = getDBConnection();
        $placeholders = implode(',', array_fill(0, count($logIds), '?'));
        $types = str_repeat('i', count($logIds)) . 'i';
        $bindValues = array_merge($logIds, [$churchId]);

        $stmt = $conn->prepare("DELETE FROM audit_logs WHERE id IN ($placeholders) AND church_id = ?");
        $stmt->bind_param($types, ...$bindValues);
        if ($stmt->execute()) {
            $deletedCount = $stmt->affected_rows;
            sendJSON(['success' => true, 'message' => "تم حذف $deletedCount من السجلات بنجاح"]);
        } else {
            sendJSON(['success' => false, 'message' => 'فشل في حذف السجلات']);
        }
    } catch (Exception $e) {
        sendJSON(['success' => false, 'message' => 'خطأ: ' . $e->getMessage()]);
    }
}




function getLastAuditLog()

{

    try {

        $churchId = getChurchId();

        $uncleId = $_SESSION['uncle_id'] ?? null;

        if (!$uncleId) {

            sendJSON(['success' => false, 'message' => 'غير مصرح']);

            return;

        }

        $conn = getDBConnection();

        // Get the latest log entry created by this uncle in the last 10 seconds

        // Restorable actions: student_add, student_edit, student_delete, coupon_edit, attendance_add, attendance_edit, attendance_delete

        $stmt = $conn->prepare("

            SELECT id, action, entity, entity_name, notes 

            FROM audit_logs 

            WHERE church_id = ? 

              AND uncle_id = ? 

              AND action IN ('student_add', 'student_edit', 'student_delete', 'coupon_edit', 'attendance_add', 'attendance_edit', 'attendance_delete', 'bulk_student_delete', 'bulk_student_class_update', 'bulk_student_coupon_update', 'bulk_attendance_save', 'student_merge')

              AND created_at >= NOW() - INTERVAL 10 SECOND

            ORDER BY id DESC LIMIT 1

        ");

        $stmt->bind_param("ii", $churchId, $uncleId);

        $stmt->execute();

        $res = $stmt->get_result();

        if ($res->num_rows > 0) {

            $log = $res->fetch_assoc();

            sendJSON(['success' => true, 'log' => $log]);

        } else {

            sendJSON(['success' => false, 'message' => 'لا توجد عمليات مؤخرة']);

        }

    } catch (Exception $e) {

        sendJSON(['success' => false, 'message' => $e->getMessage()]);

    }

}



function bulkDeleteStudents()

{

    try {

        $churchId = getChurchId();

        $studentIdsRaw = $_POST['student_ids'] ?? '';

        if (empty($studentIdsRaw)) {

            sendJSON(['success' => false, 'message' => 'لم يتم تحديد أطفال']);

            return;

        }



        $studentIds = array_filter(array_map('intval', explode(',', $studentIdsRaw)));

        if (empty($studentIds)) {

            sendJSON(['success' => false, 'message' => 'معرفات الأطفال غير صالحة']);

            return;

        }



        $conn = getDBConnection();

        $conn->begin_transaction();



        $successCount = 0;

        foreach ($studentIds as $studentId) {

            // Check existence and ownership

            $getStmt = $conn->prepare("SELECT name, image_url FROM students WHERE id = ? AND church_id = ?");

            $getStmt->bind_param("ii", $studentId, $churchId);

            $getStmt->execute();

            $student = $getStmt->get_result()->fetch_assoc();



            if ($student) {

                $studentName = $student['name'];

                $studentImageUrl = $student['image_url'];



                // Get snapshot before deleting

                $studentSnapshot = getStudentSnapshot($studentId);



                // Purge relationships

                purgeStudentRelatedRows($conn, $studentId);



                // Delete student

                $del = $conn->prepare("DELETE FROM students WHERE id = ? AND church_id = ?");

                $del->bind_param("ii", $studentId, $churchId);

                if ($del->execute() && $del->affected_rows > 0) {

                    // Clean image file

                    if ($studentImageUrl) {

                        deleteUploadedFile($studentImageUrl);

                    }



                    // Audit deletion

                    auditStudentDelete($studentId, $studentSnapshot ?? ['id' => $studentId, 'name' => $studentName]);

                    $successCount++;

                }

            }

        }



        $conn->commit();

        sendJSON(['success' => true, 'message' => "تم حذف $successCount من الأطفال بنجاح"]);

    } catch (Exception $e) {

        if (isset($conn)) $conn->rollback();

        sendJSON(['success' => false, 'message' => 'خطأ أثناء الحذف الجماعي: ' . $e->getMessage()]);

    }

}



function bulkUpdateStudentsClass()

{

    try {

        $churchId = getChurchId();

        $studentIdsRaw = $_POST['student_ids'] ?? '';

        $classId = intval($_POST['class_id'] ?? 0);



        if (empty($studentIdsRaw) || !$classId) {

            sendJSON(['success' => false, 'message' => 'بيانات غير كاملة']);

            return;

        }



        $studentIds = array_filter(array_map('intval', explode(',', $studentIdsRaw)));

        if (empty($studentIds)) {

            sendJSON(['success' => false, 'message' => 'معرفات الأطفال غير صالحة']);

            return;

        }



        $conn = getDBConnection();



        // Resolve class name

        // Check custom church classes first

        $classRow = null;

        $cChk = $conn->prepare("SELECT id, arabic_name FROM church_classes WHERE id = ? AND church_id = ? AND is_active = 1 LIMIT 1");

        $cChk->bind_param("ii", $classId, $churchId);

        $cChk->execute();

        $classRow = $cChk->get_result()->fetch_assoc();



        if (!$classRow) {

            // Check global classes

            $gChk = $conn->prepare("SELECT id, arabic_name FROM classes WHERE id = ? LIMIT 1");

            $gChk->bind_param("i", $classId);

            $gChk->execute();

            $classRow = $gChk->get_result()->fetch_assoc();

        }



        if (!$classRow) {

            sendJSON(['success' => false, 'message' => 'الفصل المحدد غير موجود']);

            return;

        }



        $className = $classRow['arabic_name'];



        $conn->begin_transaction();

        $successCount = 0;



        foreach ($studentIds as $studentId) {

            // Verify student in church

            $chk = $conn->prepare("SELECT id FROM students WHERE id = ? AND church_id = ?");

            $chk->bind_param("ii", $studentId, $churchId);

            $chk->execute();

            if ($chk->get_result()->num_rows > 0) {

                // Get before snapshot

                $beforeSnapshot = getStudentSnapshot($studentId);



                // Update student class

                $upd = $conn->prepare("UPDATE students SET class_id = ?, class = ?, updated_at = NOW() WHERE id = ? AND church_id = ?");

                $upd->bind_param("isii", $classId, $className, $studentId, $churchId);

                if ($upd->execute()) {

                    // Get after snapshot

                    $afterSnapshot = getStudentSnapshot($studentId);



                    // Audit

                    auditStudentEdit($studentId, $beforeSnapshot ?? [], $afterSnapshot ?? []);

                    $successCount++;

                }

            }

        }



        $conn->commit();

        sendJSON(['success' => true, 'message' => "تم نقل $successCount من الأطفال إلى فصل \"$className\" بنجاح"]);

    } catch (Exception $e) {

        if (isset($conn)) $conn->rollback();

        sendJSON(['success' => false, 'message' => 'خطأ أثناء نقل الأطفال: ' . $e->getMessage()]);

    }

}



function bulkUpdateStudentsCoupons()

{

    try {

        $churchId = getChurchId();

        $studentIdsRaw = $_POST['student_ids'] ?? '';

        $changeAmount = intval($_POST['change_amount'] ?? 0);

        $reason = trim($_POST['reason'] ?? 'تعديل جماعي');

        $uncleId = $_SESSION['uncle_id'] ?? null;



        if (empty($studentIdsRaw) || !$changeAmount) {

            sendJSON(['success' => false, 'message' => 'بيانات غير كاملة']);

            return;

        }



        $studentIds = array_filter(array_map('intval', explode(',', $studentIdsRaw)));

        if (empty($studentIds)) {

            sendJSON(['success' => false, 'message' => 'معرفات الأطفال غير صالحة']);

            return;

        }



        $conn = getDBConnection();

        $conn->begin_transaction();



        $successCount = 0;

        foreach ($studentIds as $studentId) {

            // Verify and load current coupons

            $chk = $conn->prepare("SELECT name, coupons, attendance_coupons, commitment_coupons, task_coupons FROM students WHERE id = ? AND church_id = ?");

            $chk->bind_param("ii", $studentId, $churchId);

            $chk->execute();

            $student = $chk->get_result()->fetch_assoc();



            if ($student) {

                $oldCount = intval($student['coupons']);

                $currentAttendance = intval($student['attendance_coupons']);

                $currentTask = intval($student['task_coupons'] ?? 0);

                

                $newCount = max(0, $oldCount + $changeAmount);

                $newCommitment = $newCount - $currentAttendance - $currentTask;

                if ($newCommitment < 0) {

                    $newCommitment = 0;

                }



                $upd = $conn->prepare("UPDATE students SET coupons = ?, commitment_coupons = ?, updated_at = NOW() WHERE id = ? AND church_id = ?");

                $upd->bind_param("iiii", $newCount, $newCommitment, $studentId, $churchId);

                if ($upd->execute()) {

                    // Log coupon history

                    $logStmt = $conn->prepare("

                        INSERT INTO coupon_logs (student_id, uncle_id, old_count, new_count, change_amount, change_type)

                        VALUES (?, ?, ?, ?, ?, 'manual')

                    ");

                    $actualChange = $newCount - $oldCount;

                    $logStmt->bind_param("iiiii", $studentId, $uncleId, $oldCount, $newCount, $actualChange);

                    $logStmt->execute();



                    // Audit

                    auditCouponChange($studentId, $student['name'], $oldCount, $newCount, $reason);

                    $successCount++;

                }

            }

        }



        $conn->commit();

        sendJSON(['success' => true, 'message' => "تم تعديل الكوبونات لـ $successCount من الأطفال بنجاح"]);

    } catch (Exception $e) {

        if (isset($conn)) $conn->rollback();

        sendJSON(['success' => false, 'message' => 'خطأ أثناء تعديل الكوبونات: ' . $e->getMessage()]);

    }

}


function addStudentNote()
{
    try {
        $churchId = getChurchId();
        $studentId = intval($_POST['studentId'] ?? 0);
        $title = trim($_POST['title'] ?? '');
        $description = trim($_POST['description'] ?? '');
        $date = trim($_POST['date'] ?? '');

        if (!$studentId || empty($title) || empty($description)) {
            sendJSON(['success' => false, 'message' => 'بيانات غير كاملة']);
            return;
        }

        if (empty($date)) {
            $date = date('Y-m-d');
        }

        $conn = getDBConnection();
        $stmt = $conn->prepare("SELECT name, custom_info FROM students WHERE id = ? AND church_id = ?");
        $stmt->bind_param("ii", $studentId, $churchId);
        $stmt->execute();
        $student = $stmt->get_result()->fetch_assoc();

        if (!$student) {
            sendJSON(['success' => false, 'message' => 'الطفل غير موجود']);
            return;
        }

        $customInfo = !empty($student['custom_info']) ? json_decode($student['custom_info'], true) : [];
        if (!is_array($customInfo)) {
            $customInfo = [];
        }

        if (!isset($customInfo['_notes']) || !is_array($customInfo['_notes'])) {
            $customInfo['_notes'] = [];
        }

        $noteId = uniqid('note_', true);
        $newNote = [
            'id' => $noteId,
            'title' => sanitize($title),
            'description' => sanitize($description),
            'date' => sanitize($date),
            'created_by' => $_SESSION['uncle_name'] ?? 'خادم',
            'created_at' => date('Y-m-d H:i:s')
        ];

        $customInfo['_notes'][] = $newNote;
        $customInfoJson = json_encode($customInfo, JSON_UNESCAPED_UNICODE);

        $upd = $conn->prepare("UPDATE students SET custom_info = ?, updated_at = NOW() WHERE id = ? AND church_id = ?");
        $upd->bind_param("sii", $customInfoJson, $studentId, $churchId);

        if ($upd->execute()) {
            writeAuditLog('note_add', 'student', $studentId, $student['name'], null, $newNote, "إضافة ملاحظة: " . $title);
            sendJSON(['success' => true, 'message' => 'تم إضافة الملاحظة بنجاح']);
        } else {
            sendJSON(['success' => false, 'message' => 'فشل في حفظ الملاحظة']);
        }
    } catch (Exception $e) {
        sendJSON(['success' => false, 'message' => 'خطأ: ' . $e->getMessage()]);
    }
}

function deleteStudentNote()
{
    try {
        $churchId = getChurchId();
        $studentId = intval($_POST['studentId'] ?? 0);
        $noteId = trim($_POST['noteId'] ?? '');

        if (!$studentId || empty($noteId)) {
            sendJSON(['success' => false, 'message' => 'بيانات غير كاملة']);
            return;
        }

        $conn = getDBConnection();
        $stmt = $conn->prepare("SELECT name, custom_info FROM students WHERE id = ? AND church_id = ?");
        $stmt->bind_param("ii", $studentId, $churchId);
        $stmt->execute();
        $student = $stmt->get_result()->fetch_assoc();

        if (!$student) {
            sendJSON(['success' => false, 'message' => 'الطفل غير موجود']);
            return;
        }

        $customInfo = !empty($student['custom_info']) ? json_decode($student['custom_info'], true) : [];
        if (!is_array($customInfo) || !isset($customInfo['_notes']) || !is_array($customInfo['_notes'])) {
            sendJSON(['success' => false, 'message' => 'لا توجد ملاحظات لحذفها']);
            return;
        }

        $foundIdx = -1;
        foreach ($customInfo['_notes'] as $idx => $note) {
            if (($note['id'] ?? '') === $noteId) {
                $foundIdx = $idx;
                break;
            }
        }

        if ($foundIdx === -1) {
            sendJSON(['success' => false, 'message' => 'الملاحظة غير موجودة']);
            return;
        }

        $oldNote = $customInfo['_notes'][$foundIdx];
        array_splice($customInfo['_notes'], $foundIdx, 1);
        $customInfoJson = json_encode($customInfo, JSON_UNESCAPED_UNICODE);

        $upd = $conn->prepare("UPDATE students SET custom_info = ?, updated_at = NOW() WHERE id = ? AND church_id = ?");
        $upd->bind_param("sii", $customInfoJson, $studentId, $churchId);

        if ($upd->execute()) {
            writeAuditLog('note_delete', 'student', $studentId, $student['name'], $oldNote, null, "حذف ملاحظة: " . ($oldNote['title'] ?? ''));
            sendJSON(['success' => true, 'message' => 'تم حذف الملاحظة بنجاح']);
        } else {
            sendJSON(['success' => false, 'message' => 'فشل في حذف الملاحظة']);
        }
    } catch (Exception $e) {
        sendJSON(['success' => false, 'message' => 'خطأ: ' . $e->getMessage()]);
    }
}

function bulkAddStudentNotes()
{
    try {
        $churchId = getChurchId();
        $studentIdsRaw = $_POST['student_ids'] ?? '';
        $title = trim($_POST['title'] ?? '');
        $description = trim($_POST['description'] ?? '');
        $date = trim($_POST['date'] ?? '');

        if (empty($studentIdsRaw) || empty($title) || empty($description)) {
