// DEVELOPER MESSAGES

// ════════════════════════════════════════════════════════════════



function ensureDevMessagesTable($conn)

{

    $conn->query("

        CREATE TABLE IF NOT EXISTS `developer_messages` (

            `id`             INT AUTO_INCREMENT PRIMARY KEY,

            `to_church_id`   INT NOT NULL DEFAULT 0 COMMENT '0 = broadcast to all churches',

            `subject`        VARCHAR(300) NOT NULL,

            `body`           TEXT NOT NULL,

            `is_read`        TINYINT(1) NOT NULL DEFAULT 0,

            `is_deleted`     TINYINT(1) NOT NULL DEFAULT 0,

            `created_at`     DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,

            `redirect_url`   VARCHAR(500) NULL,

            `button_text`    VARCHAR(100) NULL,

            `image_url`      VARCHAR(500) NULL,

            `description`    TEXT NULL,

            `target_type`    VARCHAR(50) DEFAULT 'uncles',

            INDEX idx_target (`to_church_id`, `is_deleted`),

            INDEX idx_read (`is_deleted`, `is_read`)

        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci

    ");

    // Migrate old table if it has wrong columns

    $cols = $conn->query("SHOW COLUMNS FROM developer_messages")->fetch_all(MYSQLI_ASSOC);

    $colNames = array_column($cols, 'Field');

    if (in_array('from_church_id', $colNames) && !in_array('to_church_id', $colNames)) {

        $conn->query("ALTER TABLE developer_messages ADD COLUMN to_church_id INT NOT NULL DEFAULT 0 AFTER id");

        $conn->query("ALTER TABLE developer_messages DROP COLUMN from_church_id");

        $conn->query("ALTER TABLE developer_messages DROP COLUMN from_name");

    }

    if (!in_array('redirect_url', $colNames)) {

        $conn->query("ALTER TABLE developer_messages ADD COLUMN redirect_url VARCHAR(500) NULL");

    }

    if (!in_array('button_text', $colNames)) {

        $conn->query("ALTER TABLE developer_messages ADD COLUMN button_text VARCHAR(100) NULL");

    }

    if (!in_array('image_url', $colNames)) {

        $conn->query("ALTER TABLE developer_messages ADD COLUMN image_url VARCHAR(500) NULL");

    }

    if (!in_array('description', $colNames)) {

        $conn->query("ALTER TABLE developer_messages ADD COLUMN description TEXT NULL");

    }

    if (!in_array('target_type', $colNames)) {

        $conn->query("ALTER TABLE developer_messages ADD COLUMN target_type VARCHAR(50) DEFAULT 'uncles'");

    }

}



function ensureAnnouncementsTable($conn)

{

    $conn->query("

        CREATE TABLE IF NOT EXISTS `announcements` (

            `id`             INT AUTO_INCREMENT PRIMARY KEY,

            `church_id`      INT NOT NULL,

            `type`           VARCHAR(50) NOT NULL DEFAULT 'message',

            `text`           TEXT NOT NULL,

            `link`           VARCHAR(500) NULL,

            `class`          VARCHAR(200) DEFAULT 'الجميع',

            `student_names`  TEXT NULL,

            `is_active`      TINYINT(1) NOT NULL DEFAULT 1,

            `created_at`     DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,

            `button_text`    VARCHAR(100) NULL,

            `image_url`      VARCHAR(500) NULL,

            `description`    TEXT NULL,

            `target_type`    VARCHAR(50) DEFAULT 'kids'

        ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci

    ");

    $cols = $conn->query("SHOW COLUMNS FROM announcements")->fetch_all(MYSQLI_ASSOC);

    $colNames = array_column($cols, 'Field');

    if (!in_array('button_text', $colNames)) {

        $conn->query("ALTER TABLE announcements ADD COLUMN button_text VARCHAR(100) NULL");

    }

    if (!in_array('image_url', $colNames)) {

        $conn->query("ALTER TABLE announcements ADD COLUMN image_url VARCHAR(500) NULL");

    }

    if (!in_array('description', $colNames)) {

        $conn->query("ALTER TABLE announcements ADD COLUMN description TEXT NULL");

    }

    if (!in_array('target_type', $colNames)) {

        $conn->query("ALTER TABLE announcements ADD COLUMN target_type VARCHAR(50) DEFAULT 'kids'");

    }

}



function sendDeveloperMessage()

{

    // Only developers can send messages TO churches

    try {

        $role = strtolower($_SESSION['uncle_role'] ?? '');

        if (!in_array($role, ['developer', 'dev'])) {

            sendJSON(['success' => false, 'message' => 'فقط المطور يمكنه إرسال الرسائل']);

            return;

        }

        $conn = getDBConnection();

        $toChurchId = (int) ($_POST['to_church_id'] ?? 0); // 0 = broadcast to all

        $subject = sanitize($_POST['subject'] ?? '');

        $body = sanitize($_POST['body'] ?? '');

        $redirectUrl = sanitize($_POST['redirect_url'] ?? '');

        $buttonText = sanitize($_POST['button_text'] ?? '');

        $imageUrl = sanitize($_POST['image_url'] ?? '');

        $description = sanitize($_POST['description'] ?? '');

        $targetType = sanitize($_POST['target_type'] ?? 'uncles');



        if (!$subject || !$body) {

            sendJSON(['success' => false, 'message' => 'الموضوع والرسالة مطلوبان']);

            return;

        }



        ensureDevMessagesTable($conn);

        $stmt = $conn->prepare("INSERT INTO developer_messages (to_church_id, subject, body, redirect_url, button_text, image_url, description, target_type) VALUES (?,?,?,?,?,?,?,?)");

        $stmt->bind_param('isssssss', $toChurchId, $subject, $body, $redirectUrl, $buttonText, $imageUrl, $description, $targetType);

        $stmt->execute();

        $msgId = $conn->insert_id;



        // Build notification payload

        $pushPayload = [

            'notifType' => 'developer_message',

            'redirect_url' => $redirectUrl,

            'button_text' => $buttonText,

            'image_url' => $imageUrl,

            'description' => $description,

            'target_type' => $targetType

        ];



        // Send to targeted church(es)

        $targetChurches = [];

        if ($toChurchId > 0) {

            $targetChurches[] = $toChurchId;

        } else {

            $chRows = $conn->query("SELECT id FROM churches WHERE 1 LIMIT 200")->fetch_all(MYSQLI_ASSOC);

            foreach ($chRows as $ch) {

                $targetChurches[] = (int)$ch['id'];

            }

        }



        foreach ($targetChurches as $chId) {

            // Uncles

            if ($targetType === 'uncles' || $targetType === 'both') {

                pushNotification($conn, $chId, 'developer_message', $subject, $body, 'developer_message', $msgId);

                _sendWebPushToChurch($conn, $chId, $subject, $body, $pushPayload);

            }

            // Kids

            if ($targetType === 'kids' || $targetType === 'both') {

                _sendWebPushToKids($conn, $chId, $subject, $body, $pushPayload);

            }

        }



        sendJSON(['success' => true, 'message' => 'تم الإرسال بنجاح']);

    } catch (Exception $e) {

        sendJSON(['success' => false, 'message' => $e->getMessage()]);

    }

}



function getDeveloperMessages()

{

    try {

        $conn = getDBConnection();

        ensureDevMessagesTable($conn);

        $role = strtolower($_SESSION['uncle_role'] ?? '');

        $isDev = in_array($role, ['developer', 'dev']);



        if ($isDev) {

            // Developer sees ALL messages they sent (outbox)

            $rows = $conn->query("SELECT * FROM developer_messages WHERE is_deleted=0 ORDER BY created_at DESC LIMIT 200")->fetch_all(MYSQLI_ASSOC);

            $unread = 0;

        } else {

            // Church sees messages addressed to them (to_church_id=their id OR broadcast 0)

            $churchId = getChurchId();

            if (!$churchId) {

                sendJSON(['success' => false, 'message' => 'غير مصرح']);

                return;

            }

            $stmt = $conn->prepare("SELECT * FROM developer_messages WHERE is_deleted=0 AND (to_church_id=? OR to_church_id=0) ORDER BY created_at DESC LIMIT 100");

            $stmt->bind_param('i', $churchId);

            $stmt->execute();

            $rows = $stmt->get_result()->fetch_all(MYSQLI_ASSOC);

            $unread = count(array_filter($rows, fn($r) => !$r['is_read']));

        }

        sendJSON(['success' => true, 'messages' => $rows, 'unread_count' => (int) $unread, 'is_developer' => $isDev]);

    } catch (Exception $e) {

        sendJSON(['success' => false, 'message' => $e->getMessage()]);

    }

}



// Helper: send web push to all devices subscribed for a church

function _sendWebPushToChurch($conn, $churchId, $title, $body, $extra = [])

{

    try {

        // Requires push_subscriptions table and VAPID key

        $vapid = defined('VAPID_PRIVATE_KEY') ? VAPID_PRIVATE_KEY : (getenv('VAPID_PRIVATE_KEY') ?: '');

        $vapidPub = defined('VAPID_PUBLIC_KEY') ? VAPID_PUBLIC_KEY : (getenv('VAPID_PUBLIC_KEY') ?: '');

        if (!$vapid || !$vapidPub)

            return;



        $tbl = $conn->query("SHOW TABLES LIKE 'push_subscriptions'")->fetch_assoc();

        if (!$tbl)

            return;



        $stmt = $conn->prepare("SELECT endpoint, p256dh, auth FROM push_subscriptions WHERE church_id=? AND uncle_id IS NOT NULL LIMIT 50");

        $stmt->bind_param('i', $churchId);

        $stmt->execute();

        $subs = $stmt->get_result()->fetch_all(MYSQLI_ASSOC);

        if (!$subs)

            return;



        // Use the same sendPushToSubscription helper if it exists

        if (function_exists('_pushToEndpoint')) {

            foreach ($subs as $sub) {

                _pushToEndpoint(

                    $sub['endpoint'],

                    $sub['p256dh'],

                    $sub['auth'],

                    json_encode(array_merge([
                        'title' => $title,
                        'body' => $body,
                        'type' => $extra['notifType'] ?? 'general',
                        'notifType' => $extra['notifType'] ?? 'general',
                        'icon' => '/logo.png',
                        'badge' => '/badge.png'
                    ], $extra)),

                    $vapid,

                    $vapidPub

                );

            }

        }

    } catch (Exception $e) {

        error_log("_sendWebPushToChurch error: " . $e->getMessage());

    }

}



function savePushSubscription()

{

    try {

        $conn = getDBConnection();

        $endpoint = $_POST['endpoint'] ?? '';

        $p256dh = $_POST['p256dh'] ?? '';

        $auth = $_POST['auth'] ?? '';

        $uncleId = isset($_SESSION['uncle_id']) ? (int) $_SESSION['uncle_id'] : (isset($_POST['uncle_id']) && $_POST['uncle_id'] !== '' ? (int)$_POST['uncle_id'] : null);
        $studentId = isset($_POST['student_id']) && $_POST['student_id'] !== '' ? (int)$_POST['student_id'] : null;

        $churchId = getChurchId();



        if (!$endpoint) {

            sendJSON(['success' => false, 'message' => 'endpoint مطلوب']);

            return;

        }



        $conn->query("

            CREATE TABLE IF NOT EXISTS push_subscriptions (

                id         INT AUTO_INCREMENT PRIMARY KEY,

                church_id  INT NOT NULL DEFAULT 0,

                uncle_id   INT DEFAULT NULL,

                endpoint   TEXT NOT NULL,

                p256dh     TEXT NOT NULL,

                auth       VARCHAR(100) NOT NULL,

                created_at DATETIME DEFAULT CURRENT_TIMESTAMP,

                updated_at DATETIME DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,

                UNIQUE KEY uq_endpoint (endpoint(200))

            ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4

        ");


        $colCheck = $conn->query("SHOW COLUMNS FROM push_subscriptions LIKE 'student_id'");
        if ($colCheck && $colCheck->num_rows === 0) {
            $conn->query("ALTER TABLE push_subscriptions ADD COLUMN student_id INT DEFAULT NULL AFTER uncle_id");
        }


        $stmt = $conn->prepare("

            INSERT INTO push_subscriptions (church_id, uncle_id, student_id, endpoint, p256dh, auth)

            VALUES (?,?,?,?,?,?)

            ON DUPLICATE KEY UPDATE church_id=VALUES(church_id), uncle_id=VALUES(uncle_id), student_id=VALUES(student_id), p256dh=VALUES(p256dh), auth=VALUES(auth), updated_at=NOW()

        ");

        $stmt->bind_param('iiisss', $churchId, $uncleId, $studentId, $endpoint, $p256dh, $auth);

        $stmt->execute();

        sendJSON(['success' => true]);

    } catch (Exception $e) {

        sendJSON(['success' => false, 'message' => $e->getMessage()]);

    }

}



